const API = window.location.hostname === "localhost" ? "http://localhost:8000" : "";
const GITHUB_REPO = "CBL-AICM/MD.Piece";

// 本地時區的 YYYY-MM-DD — 解所有「今日比對」用 UTC slice 造成台灣早上 8 點前
// 打的卡會被歸到前一天 UTC、導致 UI 看不到的 bug（藥物 / KPI / sidebar 今日 badge）。
// timestamp 寫入 DB 仍走 toISOString()，UTC 才是正確的儲存格式。
// 純 'YYYY-MM-DD' 字串（後端純日期欄位、自選日期）原樣返回，不做時區轉換。
function _localDay(input) {
  var d;
  if (arguments.length === 0) {
    d = new Date();
  } else {
    if (input == null || input === "") return "";
    if (typeof input === "string") {
      if (/^\d{4}-\d{2}-\d{2}$/.test(input)) return input;
      d = new Date(input);
    } else if (input instanceof Date) {
      d = input;
    } else {
      return "";
    }
  }
  if (!d || isNaN(d.getTime())) return "";
  return d.getFullYear() + "-"
    + String(d.getMonth() + 1).padStart(2, "0") + "-"
    + String(d.getDate()).padStart(2, "0");
}

// ─── 顯示模式（年長版 / 普通版）─────────────────────────────
// 'senior' = 大字體、寬按鈕、高對比；'standard' = 原本的精緻 UI
//
// 與 elder-mode.css 對齊：
//   html[data-mode="senior"] === html.elder-mode
//   localStorage 'mdpiece_mode' 與 'md.elderMode' 雙向同步
//   ?elder=1 query 強制開啟一次（不會覆寫使用者偏好除非顯式設定）

const ELDER_LS_KEY = 'md.elderMode';
const LEGACY_MODE_KEY = 'mdpiece_mode';

function _readElderPref() {
  // 新 key 優先；舊 key 作為 fallback
  const v = localStorage.getItem(ELDER_LS_KEY);
  if (v === '1' || v === 'true') return true;
  if (v === '0' || v === 'false') return false;
  return localStorage.getItem(LEGACY_MODE_KEY) === 'senior';
}

function _detectInitialElderMode() {
  // 啟動順序：?elder=1 > localStorage 偏好 > 預設 false
  try {
    const qs = new URLSearchParams(window.location.search);
    if (qs.get('elder') === '1') return true;
    if (qs.get('elder') === '0') return false;
  } catch (e) { /* ignore */ }
  return _readElderPref();
}

function getMode() {
  return _readElderPref() ? 'senior' : 'standard';
}

function setMode(mode) {
  const isElder = mode === 'senior';
  const m = isElder ? 'senior' : 'standard';
  // 雙向同步：新 key 與舊 key 都寫，方便其他既有程式碼讀取
  localStorage.setItem(ELDER_LS_KEY, isElder ? '1' : '0');
  localStorage.setItem(LEGACY_MODE_KEY, m);
  // 同時掛 data-mode（既有 CSS）與 .elder-mode（新 CSS）
  document.documentElement.setAttribute('data-mode', m);
  document.documentElement.classList.toggle('elder-mode', isElder);
  // 同步切換按鈕顯示（i18n 化：透過字典決定中/英文標籤）
  const t = (window.MDPiece_i18n && window.MDPiece_i18n.t) || ((k) => k);
  const labelKey = isElder ? 'mode.toNormal' : 'mode.toSenior';
  const fallback = isElder ? '切換為普通版' : '切換為年長版';
  document.querySelectorAll('[data-mode-toggle]').forEach(function (el) {
    // 新版按鈕（topbar 那顆 A+）自帶 icon DOM，不能把 textContent 整個寫掉，
    // 否則 icon 會消失；認 .ael-icon 來判定是不是自管 DOM 的按鈕。
    var ownsLabel = el.querySelector('.ael-icon');
    if (!ownsLabel) {
      el.textContent = window.MDPiece_i18n ? t(labelKey) : fallback;
    }
    el.setAttribute('aria-pressed', isElder ? 'true' : 'false');
  });
  // 廣播事件給其他元件（例如時間軸 Bento 需依模式調整 grid）
  try {
    window.dispatchEvent(new CustomEvent('mdpiece-elder-mode-change', {
      detail: { elder: isElder },
    }));
  } catch (e) { /* ignore on old browsers */ }
}

function toggleMode() {
  setMode(getMode() === 'senior' ? 'standard' : 'senior');
}

// alias — 比較直觀的英文名
function isElderMode() { return getMode() === 'senior'; }
function toggleElderMode() {
  toggleMode();
  // 第一次切換時顯示一個 toast，讓使用者知道「字真的變大了」
  _showElderModeHint(isElderMode());
}

function _showElderModeHint(turnedOn) {
  var prior = document.querySelector('.elder-mode-hint');
  if (prior) prior.remove();
  var hint = document.createElement('div');
  hint.className = 'elder-mode-hint';
  hint.textContent = turnedOn ? '字級已放大、按鈕變大、對比加強' : '字級已恢復';
  document.body.appendChild(hint);
  setTimeout(function() { if (hint.parentNode) hint.remove(); }, 3000);
}

// ─── 照護模式（門診 / 住院）─────────────────────────────────
// 跟 'senior/standard' 是兩個正交的維度：
//   senior/standard = UI 大小（字級、按鈕）
//   outpatient/inpatient = 功能範圍（門診相關 / 住院相關）
// 住院模式會把 sidebar 收成只剩住院期間真正會用到的項目。

const INPATIENT_NAV_PAGES = [
  'admissions', 'medications', 'vitals', 'memo', 'reminders',
  'inpatientEdu', 'handover', 'medRecon', 'bedside', 'dischargePlan',
  'settings', 'account'
];

function getCareMode() {
  return localStorage.getItem('mdpiece_care_mode') === 'inpatient' ? 'inpatient' : 'outpatient';
}

function setCareMode(mode) {
  const m = mode === 'inpatient' ? 'inpatient' : 'outpatient';
  localStorage.setItem('mdpiece_care_mode', m);
  applyCareMode();
  // 切到住院時若當前頁面在門診專屬清單裡，回首頁避免使用者卡在「看不到 nav 又出不來」
  if (m === 'inpatient' && _currentPageKey
      && _currentPageKey !== 'home'
      && INPATIENT_NAV_PAGES.indexOf(_currentPageKey) === -1) {
    if (typeof navigateTo === 'function') navigateTo('home', null);
  }
  // 重畫首頁好讓 chip 的 active 狀態跟著變
  if (_currentPageKey === 'home' && typeof showPage === 'function') showPage('home');
}

function applyCareMode() {
  document.documentElement.setAttribute('data-care-mode', getCareMode());
  // 底部 nav 隨 care mode 換一組 tabs（住院模式換成住院相關）
  if (typeof renderMobileTabbar === 'function') renderMobileTabbar();
}
applyCareMode();

// ─── 設計憲法 條 3 (客製化提醒語氣) ──────────────────────────────────────
// 「嚴肅」直白指令、「溫柔」鼓勵帶溫度、「極簡」省略所有修飾。
// 任何給病人看的 system message (todo / SOS / reminder) 都該過 reminderToneify()。
function getReminderTone() {
  try { return localStorage.getItem('mdpiece_reminder_tone') || 'warm'; } catch (e) { return 'warm'; }
}
function setReminderTone(tone) {
  if (['strict','warm','short'].indexOf(tone) === -1) tone = 'warm';
  try { localStorage.setItem('mdpiece_reminder_tone', tone); } catch (e) {}
  document.documentElement.setAttribute('data-reminder-tone', tone);
}
// 把短句依語氣改寫。傳入物件 { strict, warm, short }，分別是 3 種版本；
// 也支援單一字串 (各語氣套對應規則)。
function reminderToneify(input) {
  var tone = getReminderTone();
  if (input && typeof input === 'object' && !Array.isArray(input)) {
    return input[tone] || input.warm || input.strict || input.short || '';
  }
  var s = String(input || '');
  if (tone === 'strict') return s; // 原句通常已是直白指令
  if (tone === 'warm') {
    // 暖色修飾 — 加結尾語
    if (/[。！？]$/.test(s)) return s + ' ❤️';
    return s + '，慢慢來。';
  }
  // short — 砍掉「請」「記得」這類客氣詞，留動詞 + 名詞
  return s.replace(/^(請|記得|別忘了|趕快|麻煩|快點)/, '').replace(/[，。！]/g, '').trim();
}
// 啟動時就套用到 <html>，方便 CSS 依語氣調 chip 顏色等視覺
setReminderTone(getReminderTone());

// ─── 設計憲法 條 6 (家屬代理視角) ─────────────────────────────────────────
// 切到「我幫家人」時，所有新紀錄帶 proxy_for 標籤 + 頁首 banner 提醒目前是代理模式。
function getProxyFor() {
  try { return JSON.parse(localStorage.getItem('mdpiece_proxy_for') || 'null'); }
  catch (e) { return null; }
}
function setProxyFor(p) {
  if (!p) localStorage.removeItem('mdpiece_proxy_for');
  else localStorage.setItem('mdpiece_proxy_for', JSON.stringify(p));
  refreshProxyBanner();
}
function isProxyMode() { return !!getProxyFor(); }
function renderProxyToggle() {
  var p = getProxyFor();
  if (p && p.name) {
    return ''
      + '<div class="set-proxy-active">'
      +   '<span>正在幫 <strong>' + escapeHtml(p.name) + '</strong>' + (p.relation ? '（' + escapeHtml(p.relation) + '）' : '') + '紀錄</span>'
      +   '<button type="button" class="set-btn" onclick="onProxySwitch()">換對象 / 取消</button>'
      + '</div>';
  }
  return '<button type="button" class="set-btn" onclick="onProxySwitch()"><i data-lucide="user-plus" style="width:14px;height:14px"></i> 切到家人代理</button>';
}
function onProxySwitch() {
  var cur = getProxyFor();
  if (cur) {
    if (confirm('取消家人代理，回到「我自己」模式？')) {
      setProxyFor(null);
      if (typeof showToast === 'function') showToast('已切回「我自己」', 'success');
      if (typeof showPage === 'function') showPage('settings');
    }
    return;
  }
  var name = prompt('家人姓名（例：媽媽 / 王阿嬤）：', '');
  if (!name || !name.trim()) return;
  var relation = prompt('關係（例：母親 / 配偶 / 子女，可空）：', '');
  setProxyFor({ name: name.trim(), relation: (relation || '').trim() });
  if (typeof showToast === 'function') showToast('已切到「幫 ' + name.trim() + ' 紀錄」模式', 'success');
  if (typeof showPage === 'function') showPage('settings');
}
function renderProxyBanner() {
  // 全 app 共用 — 永遠掛在 #app 上方，由 refreshProxyBanner 寫入內容
  return '<div class="proxy-banner" id="proxy-banner" hidden></div>';
}
function refreshProxyBanner() {
  var el = document.getElementById('proxy-banner');
  if (!el) return;
  var p = getProxyFor();
  if (!p) { el.hidden = true; el.innerHTML = ''; return; }
  el.hidden = false;
  el.innerHTML = ''
    + '<i data-lucide="users" style="width:14px;height:14px"></i>'
    + '<span>正在幫 <strong>' + escapeHtml(p.name) + '</strong>' + (p.relation ? '（' + escapeHtml(p.relation) + '）' : '') + '紀錄。所有新紀錄都會打上代理標籤。</span>'
    + '<button type="button" class="proxy-banner-switch" onclick="onProxySwitch()" aria-label="切換代理對象">'
    +   '<i data-lucide="repeat" style="width:12px;height:12px"></i>'
    + '</button>';
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

// ─── 底部 mobile tabbar — 依 care mode 動態渲染 ────────────────────────
// 門診：首頁 / 碎片 / FAB / 診前 / 醫聊 — 對齊 v11 demo
// 住院：首頁 / 住院 / FAB / 量測 / 診前 — 同上對稱結構
// 「更多」改放在 hamburger menu，不佔 tabbar 空間
function _mobileTabSets() {
  return {
    outpatient: [
      { page: 'home',        icon: 'mdp-home',      labelKey: 'tab.home',        zh: '首頁', en: 'Home',     home: true },
      { page: 'pieces',      icon: 'mdp-puzzle',    labelKey: 'tab.pieces',      zh: '碎片', en: 'Pieces' },
      { page: 'quickadd',    icon: 'plus',          labelKey: 'tab.quickadd',    zh: '記一筆', en: 'Log',    fab: true },
      { page: 'previsit',    icon: 'mdp-clipboard', labelKey: 'tab.previsit',    zh: '診前', en: 'Pre-visit' },
      { page: 'chat',        icon: 'mdp-chat',      labelKey: 'tab.chat',        zh: '醫聊', en: 'Chat' },
    ],
    inpatient: [
      { page: 'home',        icon: 'mdp-home',      labelKey: 'tab.home',        zh: '首頁',   en: 'Home',    home: true },
      { page: 'admissions',  icon: 'mdp-bed',       labelKey: 'tab.admissions',  zh: '住院',   en: 'Stay' },
      { page: 'quickadd',    icon: 'plus',          labelKey: 'tab.quickadd',    zh: '記一筆', en: 'Log',     fab: true },
      { page: 'vitals',      icon: 'mdp-pulse',     labelKey: 'tab.vitals',      zh: '量測',   en: 'Vitals' },
      { page: 'previsit',    icon: 'mdp-clipboard', labelKey: 'tab.previsit',    zh: '診前',   en: 'Pre-visit' },
    ],
  };
}

// 自家品牌底部 tab icon — 24×24 viewBox，雙路徑：
//   .ic-stroke 永遠顯示（線稿）；.ic-accent 預設透明，被選中時點亮（duotone 填色）
// 每顆 icon 都在右下角埋一個 MD.Piece「碎片」缺口（class="ic-piece"），是品牌簽名。
// 包在函式裡是因為 applyCareMode() 在 app.js 頂層就會被呼叫（line 63），那時 var 還沒指派；
// function declaration 會被完全 hoist，所以放在函式裡才會在第一次 render 就有值。
function _mdpNavIconSvg(name, size) {
  var ICONS = {
    'mdp-home':
      '<path class="ic-stroke" d="M3.5 11.5 L12 4 L20.5 11.5 V20 a1 1 0 0 1-1 1 H4.5 a1 1 0 0 1-1-1 Z" fill="none" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round"/>' +
      '<path class="ic-accent" d="M4.2 11 L12 4.3 L19.8 11 V13.2 H4.2 Z"/>' +
      '<path class="ic-piece" d="M14 16 h3.5 v3.5 a0.8 0.8 0 0 1-0.8 0.8 h-2.7 Z" fill="none" stroke-width="1.6" stroke-linejoin="round"/>',
    'mdp-puzzle':
      '<path class="ic-stroke" d="M9 4 h2 a1 1 0 0 1 1 1 v1.5 a1.5 1.5 0 0 0 3 0 V5 a1 1 0 0 1 1-1 h2.5 a1 1 0 0 1 1 1 v3.5 a1 1 0 0 0 1 1 h0 a1.5 1.5 0 0 1 0 3 h0 a1 1 0 0 0-1 1 V16 a1 1 0 0 1-1 1 h-3.5 a1 1 0 0 0-1 1 V20 a1 1 0 0 1-1 1 H5 a1 1 0 0 1-1-1 v-3.5 a1 1 0 0 1 1-1 h1.5 a1.5 1.5 0 0 0 0-3 H5 a1 1 0 0 1-1-1 V8 a1 1 0 0 1 1-1 h3 a1 1 0 0 1 1 -1 Z" fill="none" stroke-width="1.6" stroke-linejoin="round" stroke-linecap="round"/>' +
      '<circle class="ic-accent" cx="12" cy="12" r="3.4"/>',
    'mdp-bed':
      // 側視床：headboard 左 / 床框 / 床面分隔 / 枕頭方塊；mattress 為 accent fill
      '<path class="ic-stroke" d="M3 10 V19 H21 V14 H3" fill="none" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round"/>' +
      '<rect class="ic-stroke" x="4.8" y="11" width="5.4" height="3" rx="1.3" fill="none" stroke-width="1.6"/>' +
      '<path class="ic-accent" d="M3.6 14.5 H20.4 V18.4 H3.6 Z"/>' +
      '<path class="ic-piece" d="M16.4 16.2 h3 v2 a0.7 0.7 0 0 1-0.7 0.7 h-2.3 Z" fill="none" stroke-width="1.4" stroke-linejoin="round"/>',
    'mdp-pulse':
      '<path class="ic-stroke" d="M12 20 s-7-4.5-7-10 a4 4 0 0 1 7-2.6 a4 4 0 0 1 7 2.6 c0 1.2-0.35 2.3-0.9 3.3" fill="none" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round"/>' +
      '<polyline class="ic-stroke" points="3,13 7,13 9,10 11,16 13,12 16,14 21,14" fill="none" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round"/>' +
      '<path class="ic-accent" d="M12 18.4 c-3-1.7-5.5-4.3-5.5-7.7 a2.6 2.6 0 0 1 5.5-1.4 a2.6 2.6 0 0 1 4.6 0.9"/>',
    'mdp-memo':
      '<path class="ic-stroke" d="M5 4 h9 l4 4 V19 a1.5 1.5 0 0 1-1.5 1.5 H5 a1 1 0 0 1-1-1 V5 a1 1 0 0 1 1-1 Z" fill="none" stroke-width="1.8" stroke-linejoin="round"/>' +
      '<path class="ic-stroke" d="M14 4 V8 h4" fill="none" stroke-width="1.8" stroke-linejoin="round"/>' +
      '<path class="ic-accent" d="M5 5 h8.6 L17.6 9 V14 H5 Z"/>' +
      '<line class="ic-stroke" x1="7.5" y1="16.5" x2="14" y2="16.5" stroke-width="1.6" stroke-linecap="round"/>' +
      '<line class="ic-stroke" x1="7.5" y1="13" x2="11" y2="13" stroke-width="1.6" stroke-linecap="round"/>',
    'mdp-clipboard':
      '<rect class="ic-stroke" x="5" y="5" width="14" height="16" rx="1.5" fill="none" stroke-width="1.8"/>' +
      '<rect class="ic-stroke" x="9" y="3" width="6" height="4" rx="1" fill="none" stroke-width="1.8"/>' +
      '<path class="ic-accent" d="M6 7 h12 V12.5 H6 Z"/>' +
      '<polyline class="ic-stroke" points="8.5,14.5 11,17 16,12" fill="none" stroke-width="1.9" stroke-linejoin="round" stroke-linecap="round"/>',
    'mdp-chat':
      '<path class="ic-stroke" d="M4 6 a2 2 0 0 1 2-2 h12 a2 2 0 0 1 2 2 v9 a2 2 0 0 1-2 2 h-7 l-4 3.5 V17 H6 a2 2 0 0 1-2-2 Z" fill="none" stroke-width="1.8" stroke-linejoin="round"/>' +
      '<path class="ic-accent" d="M12 13.5 c-1.3-0.9-3-2.1-3-3.6 a1.6 1.6 0 0 1 3-0.8 a1.6 1.6 0 0 1 3 0.8 c0 1.5-1.7 2.7-3 3.6 Z"/>',
    'mdp-more':
      '<circle class="ic-stroke" cx="6"  cy="12" r="1.7" fill="none" stroke-width="1.8"/>' +
      '<circle class="ic-stroke" cx="12" cy="12" r="1.7" fill="none" stroke-width="1.8"/>' +
      '<circle class="ic-stroke" cx="18" cy="12" r="1.7" fill="none" stroke-width="1.8"/>' +
      '<circle class="ic-accent" cx="6"  cy="12" r="1.4"/>' +
      '<circle class="ic-accent" cx="12" cy="12" r="1.4"/>' +
      '<circle class="ic-accent" cx="18" cy="12" r="1.4"/>',
  };
  var s = size || 24;
  var body = ICONS[name];
  if (!body) return '';
  return '<svg class="mdp-nav-svg" viewBox="0 0 24 24" width="' + s + '" height="' + s + '" aria-hidden="true" focusable="false">' + body + '</svg>';
}

function renderMobileTabbar() {
  var nav = document.getElementById('mobile-tabbar');
  if (!nav) return;
  var mode = (typeof getCareMode === 'function') ? getCareMode() : 'outpatient';
  var tabs = _mobileTabSets()[mode] || _mobileTabSets().outpatient;
  var lang = (window.MDPiece_i18n && window.MDPiece_i18n.getLang) ? window.MDPiece_i18n.getLang() : 'zh-TW';
  var html = '<div class="mtab-rail"></div>';
  tabs.forEach(function(t) {
    var label = (lang === 'en' ? t.en : t.zh);
    if (t.fab) {
      html += ''
        + '<button class="mtab mtab-fab" data-mtab="quickadd" onclick="mobileQuickAdd(this)" type="button" aria-label="快速紀錄" data-i18n-aria-label="tab.quickaddAria">'
        +   '<span class="mtab-fab-ring"></span>'
        +   '<span class="mtab-fab-core"><i data-lucide="' + t.icon + '" style="width:22px;height:22px"></i></span>'
        +   '<span class="mtab-fab-label" data-i18n="' + t.labelKey + '">' + label + '</span>'
        + '</button>';
    } else {
      var cls = 'mtab' + (t.home ? ' mtab-home' : '') + (t.more ? ' mtab-more' : '');
      var onclick = t.more ? 'openMobileMore(this)' : ('mobileTabTo(\'' + t.page + '\', this)');
      var dataKey = t.more ? 'more' : t.page;
      html += ''
        + '<button class="' + cls + '" data-mtab="' + dataKey + '" onclick="' + onclick + '" type="button">'
        +   '<span class="mtab-pill">'
        +     '<span class="mtab-icon">' + _mdpNavIconSvg(t.icon, 22) + '</span>'
        +     '<span class="mtab-label" data-i18n="' + t.labelKey + '">' + label + '</span>'
        +   '</span>'
        + '</button>';
    }
  });
  nav.innerHTML = html;
  if (typeof lucide !== 'undefined' && lucide.createIcons) try { lucide.createIcons(); } catch (e) {}
  // 重畫後重新標記目前頁面對應的 tab
  if (typeof _currentPageKey === 'string' && typeof _setActiveMobileTabForPage === 'function') {
    _setActiveMobileTabForPage(_currentPageKey);
  }
}

// 給 syncMobileTabs 用：依 page 找出該亮哪個 tab。
// 如果 page 不在當前 tabset 裡，所有 tab 都消燈。
function _setActiveMobileTabForPage(page) {
  var nav = document.getElementById('mobile-tabbar');
  if (!nav) return;
  nav.querySelectorAll('.mtab').forEach(function(b) {
    b.classList.toggle('active', b.dataset.mtab === page);
  });
}

// 切換語言時 tabbar 文字也要跟著重畫（因為內含 i18n key）
window.addEventListener('mdpiece-lang-change', function() {
  if (typeof renderMobileTabbar === 'function') renderMobileTabbar();
});

// 在 DOMContentLoaded 之前先把屬性掛上，避免閃爍
// 同時處理 ?elder=1 query string，讓無障礙連結可一鍵分享長者模式
setMode(_detectInitialElderMode() ? 'senior' : 'standard');

// ─── 使用者狀態 ─────────────────────────────────────────────

function getCurrentUser() {
  try {
    return JSON.parse(localStorage.getItem('mdpiece_user'));
  } catch { return null; }
}

function setCurrentUser(user) {
  // Phase 1a：把 access_token 拆出來單獨存（避免每次序列化 user 都帶著）
  if (user && user.access_token) {
    try { localStorage.setItem('mdpiece_access_token', user.access_token); } catch {}
    user = Object.assign({}, user);
    delete user.access_token;
  }
  localStorage.setItem('mdpiece_user', JSON.stringify(user));
}

function getAccessToken() {
  try { return localStorage.getItem('mdpiece_access_token'); } catch { return null; }
}

// Phase 1a：fetch wrapper，把 Authorization: Bearer 自動帶上、處理 401。
// 後續 router 漸進改成 Depends(current_user) 時，前端不用再各自改。
async function apiFetch(input, init) {
  init = init || {};
  var headers = new Headers(init.headers || {});
  var tok = getAccessToken();
  if (tok && !headers.has('Authorization')) headers.set('Authorization', 'Bearer ' + tok);
  init.headers = headers;
  var res = await fetch(input, init);
  // 只有「呼叫時原本有 token」才走「token 過期 → 清掉 → reload」流程。
  // 如果一開始就沒 token（例如登入頁背景的 apiFetch），把 401 直接回給 caller，
  // 避免 reload 迴圈讓使用者連登入頁都進不去（Phase 1b 加 enforce 後曝出的 bug）。
  if (res.status === 401 && tok) {
    try {
      localStorage.removeItem('mdpiece_access_token');
      localStorage.removeItem('mdpiece_user');
    } catch (e) {}
    if (typeof showToast === 'function') showToast('登入已過期，請重新登入', 'warning');
    setTimeout(function() { window.location.reload(); }, 800);
  }
  return res;
}
window.apiFetch = apiFetch;

// 登出 — 清除使用者資料並回到 landing
function logout() {
  if (!confirm('確定要登出嗎？\n\n$ exit\n\n下次回來會回到歡迎頁。')) return;
  try {
    localStorage.removeItem('mdpiece_user');
    localStorage.removeItem('mdpiece_access_token');
    localStorage.removeItem('mdpiece_demo_pid');
  } catch (e) {}
  window.location.reload();
}

// 取得或建立一個穩定 UUID（避免 demo 模式下 patient_id 不是 UUID 導致後端寫入失敗）
function getStablePatientId() {
  var user = getCurrentUser();
  if (user && user.id) return user.id;
  var demoId = localStorage.getItem('mdpiece_demo_pid');
  if (!demoId) {
    demoId = generateSecureId();
    localStorage.setItem('mdpiece_demo_pid', demoId);
  }
  return demoId;
}

// 產生 demo patient_id — 一律用 Web Crypto，避免 Math.random 流入 user_id（CodeQL）
function generateSecureId() {
  if (typeof crypto !== 'undefined') {
    if (typeof crypto.randomUUID === 'function') return crypto.randomUUID();
    if (typeof crypto.getRandomValues === 'function') {
      var b = new Uint8Array(16);
      crypto.getRandomValues(b);
      // RFC 4122 v4
      b[6] = (b[6] & 0x0f) | 0x40;
      b[8] = (b[8] & 0x3f) | 0x80;
      var hex = Array.prototype.map.call(b, function(x) {
        return ('00' + x.toString(16)).slice(-2);
      }).join('');
      return hex.slice(0, 8) + '-' + hex.slice(8, 12) + '-' + hex.slice(12, 16) + '-' + hex.slice(16, 20) + '-' + hex.slice(20);
    }
  }
  // 最後保險：所有現代瀏覽器都已支援 Web Crypto，這條基本上跑不到
  throw new Error('Web Crypto API unavailable');
}

