// ─── Memo（拍照 + 給醫師留言 + 給自己備忘） ──────────────────
var MEMO_STORE_KEY = "mdpiece_memos_v1";
var _memoFilter = "all";          // all / doctor / self
var _memoComposeMode = null;       // "photo" | "text" | null
var _memoStagedPhoto = null;       // dataURL，等待儲存
var _memoStagedPhotoCanvas = null; // 預覽用 canvas（從 compress 留下來；Samsung Internet 上 <img> 對 data:/blob: 都不穩，所以連 URL 載入都不要走）
var _memoEditingId = null;         // 編輯中的 memo id（null 表示新增）

function memoLoad() {
  try {
    var raw = localStorage.getItem(MEMO_STORE_KEY);
    if (!raw) return [];
    var parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) { return []; }
}
function memoSaveAll(arr) {
  try { localStorage.setItem(MEMO_STORE_KEY, JSON.stringify(arr)); }
  catch (e) { showToast("儲存失敗，可能空間不足", "error"); }
}

function loadMemoPage() {
  _memoFilter = "all";
  _memoComposeMode = null;
  _memoStagedPhoto = null;
  _memoStagedPhotoCanvas = null;
  memoRenderList();
  if (typeof lucide !== 'undefined') setTimeout(function() { lucide.createIcons(); }, 30);
}

function memoStartText() {
  _memoComposeMode = "text";
  _memoStagedPhoto = null;
  _memoStagedPhotoCanvas = null;
  memoOpenComposer("寫下要說的話", { forDoctor: true });
}

function memoIsHeic(file) {
  if (!file) return false;
  var t = (file.type || "").toLowerCase();
  if (t === "image/heic" || t === "image/heif" || t === "image/heic-sequence" || t === "image/heif-sequence") return true;
  var name = (file.name || "").toLowerCase();
  return /\.(heic|heif)$/.test(name);
}

// Samsung Internet 沒有 HEIC 解碼器 — 從 iPhone 同步來的照片進到這個 picker 會全部炸掉。
// 解法：lazy-load heic2any（libheif-js wasm wrapper）轉成 JPEG 再走原本 pipeline。
var _heic2anyLoading = null;
function memoLoadHeic2Any() {
  if (typeof window !== "undefined" && window.heic2any) return Promise.resolve(window.heic2any);
  if (_heic2anyLoading) return _heic2anyLoading;
  _heic2anyLoading = new Promise(function(resolve, reject) {
    var s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/heic2any@0.0.4/dist/heic2any.min.js";
    s.async = true;
    s.onload = function() {
      if (window.heic2any) resolve(window.heic2any);
      else reject(new Error("heic2any loaded but not exposed on window"));
    };
    s.onerror = function() { _heic2anyLoading = null; reject(new Error("heic2any script load failed")); };
    document.head.appendChild(s);
  });
  return _heic2anyLoading;
}

function memoConvertHeicToJpeg(file) {
  return memoLoadHeic2Any().then(function(heic2any) {
    return heic2any({ blob: file, toType: "image/jpeg", quality: 0.85 });
  }).then(function(out) {
    var blob = Array.isArray(out) ? out[0] : out;
    var baseName = (file.name || "photo").replace(/\.(heic|heif)$/i, "");
    return new File([blob], baseName + ".jpg", { type: "image/jpeg" });
  });
}

function memoOnPhotoPicked(ev) {
  var input = ev.target;
  var file = input.files && input.files[0];
  if (!file) return;
  // iOS HEIC 有時 file.type 是空字串；只在明確不是圖片時擋
  if (file.type && file.type.indexOf("image/") !== 0) {
    showToast("請選擇圖片檔", "warning");
    try { input.value = ""; } catch (e) { /* noop */ }
    return;
  }
  _memoComposeMode = "photo";
  function resetInput() { try { input.value = ""; } catch (e) { /* noop */ } }

  // HEIC（iPhone 預設格式）：Samsung / Chrome / Firefox 都不能直接解，先轉 JPEG
  var prep;
  if (memoIsHeic(file)) {
    showToast("照片是 HEIC 格式，正在轉檔...", "info");
    prep = memoConvertHeicToJpeg(file).catch(function(err) {
      console.warn("[memo] HEIC convert failed", err);
      showToast("HEIC 轉檔失敗 — 請改用 JPEG（iPhone 設定 → 相機 → 格式 → 相容）", "error");
      throw err;
    });
  } else {
    prep = Promise.resolve(file);
  }

  prep.then(function(usableFile) {
    // 大圖縮到 max 1280px、JPEG 0.85，避免 localStorage 爆掉
    return memoCompressImage(usableFile, 1280, 0.85).then(function(result) {
      if (!memoIsValidDataUrl(result.dataUrl)) throw new Error("compress produced invalid dataURL");
      _memoStagedPhoto = result.dataUrl;
      _memoStagedPhotoCanvas = result.canvas || null;
      memoOpenComposer("為這張照片加備註（可選）", { forDoctor: false });
      resetInput();
    }).catch(function(err) {
      console.warn("[memo] compress failed, falling back to raw dataURL", err);
      // 壓縮失敗：仍用原始 dataURL 存起來，至少不會卡關
      return memoReadAsDataURL(usableFile).then(function(dataUrl) {
        if (!memoIsValidDataUrl(dataUrl)) {
          console.warn("[memo] raw dataURL also invalid", dataUrl && dataUrl.slice(0, 40));
          showToast("照片讀取失敗", "error");
          resetInput();
          return;
        }
        _memoStagedPhoto = dataUrl;
        _memoStagedPhotoCanvas = null;
        memoOpenComposer("為這張照片加備註（可選）", { forDoctor: false });
        resetInput();
      });
    });
  }).catch(function(e) {
    console.warn("[memo] photo prep failed", e);
    resetInput();
  });
}

function memoIsValidDataUrl(s) {
  // data:<mime>;base64,<至少幾個 char>
  return typeof s === "string" && s.length > 32 && s.indexOf("data:image/") === 0 && s.indexOf(",") > 0;
}

// Samsung Internet PWA 上把長 data:/blob: URL 丟進 <img> 都會破圖。多策略 fallback：
// 1) 直接用 compose 階段已經畫好的 canvas（最穩，零 URL 載入）
// 2) dataURL → Blob → createImageBitmap → drawImage 到新 canvas
// 3) dataURL → Blob → Object URL → <img>
// 4) dataURL → <img>
// 任一條成功就停；全部掛掉時把每條路的結果 / 錯誤展示在 UI 上方便診斷。
var MEMO_VERSION_TAG = "v89-heic-convert";

function memoDataUrlToBlob(dataUrl) {
  var comma = dataUrl.indexOf(",");
  if (comma < 0) throw new Error("invalid dataURL");
  var header = dataUrl.slice(0, comma);
  var payload = dataUrl.slice(comma + 1);
  var mimeMatch = header.match(/data:([^;]+)/);
  var mime = mimeMatch ? mimeMatch[1] : "image/jpeg";
  var bin = header.indexOf(";base64") >= 0 ? atob(payload) : decodeURIComponent(payload);
  var len = bin.length;
  var u8 = new Uint8Array(len);
  for (var i = 0; i < len; i++) u8[i] = bin.charCodeAt(i);
  return new Blob([u8], { type: mime });
}

// container: 目標 DOM；dataUrl: 圖片 dataURL；className: 套 CSS；preBuiltCanvas: 可選，已畫好的 canvas
function memoMountPhoto(container, dataUrl, className, preBuiltCanvas) {
  if (!container) return;
  while (container.firstChild) container.removeChild(container.firstChild);

  var diag = { dataUrlLen: dataUrl ? dataUrl.length : 0, attempts: [] };
  function record(name, ok, info, err) {
    diag.attempts.push({ name: name, ok: !!ok, info: info || null, err: err == null ? null : String(err && err.message || err) });
    try { console.log("[memo-diag]", MEMO_VERSION_TAG, name, ok ? "ok" : "FAIL", info || "", err || ""); } catch (_) {}
  }
  function done(method) {
    // 在 container 上記一下哪條路成功了，方便外部查
    container.setAttribute("data-memo-render-method", method);
    container.setAttribute("data-memo-render-version", MEMO_VERSION_TAG);
  }
  function showDiag() {
    while (container.firstChild) container.removeChild(container.firstChild);
    var box = document.createElement("div");
    box.className = "memo-photo-fallback";
    box.style.cssText =
      "padding:10px;border:1px dashed var(--border-glass);border-radius:6px;" +
      "color:var(--text-dim);font-size:.72rem;line-height:1.5;text-align:left;" +
      "font-family:ui-monospace,Menlo,monospace;white-space:pre-wrap;word-break:break-all";
    var lines = ["預覽載入失敗 — 試過 " + diag.attempts.length + " 種方法（資料仍存在）"];
    lines.push("[" + MEMO_VERSION_TAG + "] dataURL len=" + diag.dataUrlLen);
    diag.attempts.forEach(function(a) {
      var line = "• " + a.name + ": " + (a.ok ? "ok" : "FAIL");
      if (a.info) line += " " + JSON.stringify(a.info);
      if (a.err) line += " — " + a.err;
      lines.push(line);
    });
    box.textContent = lines.join("\n");
    container.appendChild(box);
    done("none");
  }

  // ── 1) pre-built canvas ──
  if (preBuiltCanvas) {
    try {
      if (className) preBuiltCanvas.className = className;
      container.appendChild(preBuiltCanvas);
      record("preBuiltCanvas", true, { w: preBuiltCanvas.width, h: preBuiltCanvas.height });
      done("preBuiltCanvas");
      return;
    } catch (e) {
      record("preBuiltCanvas", false, null, e);
    }
  }

  if (!dataUrl) {
    record("noDataURL", false, null, "no dataURL");
    showDiag();
    return;
  }

  // 共用：把 dataURL 解成 Blob 供 strategy 2/3
  var blob = null;
  try {
    blob = memoDataUrlToBlob(dataUrl);
    record("dataUrlToBlob", true, { size: blob.size, type: blob.type });
  } catch (e) {
    record("dataUrlToBlob", false, null, e);
  }

  // 既有 HEIC memo（v89 之前 Samsung 上存進去的）：用 heic2any 轉成 JPEG blob 再走後續策略
  function ensureNonHeicBlobThenContinue() {
    if (!blob || !/image\/(heic|heif)/i.test(blob.type)) {
      tryCreateImageBitmap();
      return;
    }
    memoLoadHeic2Any().then(function(heic2any) {
      return heic2any({ blob: blob, toType: "image/jpeg", quality: 0.85 });
    }).then(function(out) {
      var jpegBlob = Array.isArray(out) ? out[0] : out;
      record("heicConvert", true, { size: jpegBlob.size, type: jpegBlob.type });
      blob = jpegBlob;
      tryCreateImageBitmap();
    }).catch(function(err) {
      record("heicConvert", false, null, err);
      // 轉檔失敗仍進入策略 2-4，雖然會掛但診斷面板會把細節秀出來
      tryCreateImageBitmap();
    });
  }

  // ── 2) createImageBitmap → canvas ──
  function tryCreateImageBitmap() {
    if (!blob) { record("createImageBitmap+canvas", false, null, "no blob"); return tryObjectUrlImg(); }
    if (typeof createImageBitmap !== "function") { record("createImageBitmap+canvas", false, null, "unsupported"); return tryObjectUrlImg(); }
    return createImageBitmap(blob).then(function(bm) {
      try {
        var canvas = document.createElement("canvas");
        if (className) canvas.className = className;
        canvas.width = bm.width; canvas.height = bm.height;
        canvas.getContext("2d").drawImage(bm, 0, 0);
        container.appendChild(canvas);
        record("createImageBitmap+canvas", true, { w: bm.width, h: bm.height });
        done("createImageBitmap+canvas");
      } catch (e) {
        record("createImageBitmap+canvas", false, null, e);
        return tryObjectUrlImg();
      }
    }).catch(function(e) {
      record("createImageBitmap+canvas", false, null, e);
      return tryObjectUrlImg();
    });
  }

  // ── 3) Object URL → <img> ──
  function tryObjectUrlImg() {
    if (!blob) { record("ObjectURL+img", false, null, "no blob"); return tryDataUrlImg(); }
    return new Promise(function(resolve) {
      var url;
      try { url = URL.createObjectURL(blob); }
      catch (e) { record("ObjectURL+img", false, null, e); resolve(tryDataUrlImg()); return; }
      var img = new Image();
      img.onload = function() {
        if (!img.naturalWidth || !img.naturalHeight) {
          try { URL.revokeObjectURL(url); } catch (_) {}
          record("ObjectURL+img", false, null, "zero dimensions");
          resolve(tryDataUrlImg());
          return;
        }
        if (className) img.className = className;
        container.appendChild(img);
        record("ObjectURL+img", true, { w: img.naturalWidth, h: img.naturalHeight });
        done("ObjectURL+img");
        resolve();
        // 不 revoke：img 還在 DOM 用著這個 URL；container 整個被清掉時 GC
      };
      img.onerror = function() {
        try { URL.revokeObjectURL(url); } catch (_) {}
        record("ObjectURL+img", false, null, "img.onerror");
        resolve(tryDataUrlImg());
      };
      img.src = url;
    });
  }

  // ── 4) dataURL → <img> ──
  function tryDataUrlImg() {
    return new Promise(function(resolve) {
      var img = new Image();
      img.onload = function() {
        if (!img.naturalWidth || !img.naturalHeight) {
          record("dataURL+img", false, null, "zero dimensions");
          showDiag();
          resolve();
          return;
        }
        if (className) img.className = className;
        container.appendChild(img);
        record("dataURL+img", true, { w: img.naturalWidth, h: img.naturalHeight });
        done("dataURL+img");
        resolve();
      };
      img.onerror = function() {
        record("dataURL+img", false, null, "img.onerror");
        showDiag();
        resolve();
      };
      img.src = dataUrl;
    });
  }

  ensureNonHeicBlobThenContinue();
}

function memoRenderStagedPreview() {
  var preview = document.getElementById("memo-photo-preview");
  if (!preview) return;
  while (preview.firstChild) preview.removeChild(preview.firstChild);
  if (!_memoStagedPhoto) {
    preview.style.display = "none";
    return;
  }
  preview.style.display = "block";
  // 新拍照路徑帶著 pre-built canvas；編輯路徑只有 dataURL
  memoMountPhoto(preview, _memoStagedPhoto, "memo-preview-canvas", _memoStagedPhotoCanvas);
}

function memoReadAsDataURL(file) {
  return new Promise(function(resolve, reject) {
    var reader = new FileReader();
    reader.onerror = function() { reject(new Error("read failed")); };
    reader.onload = function() { resolve(reader.result); };
    reader.readAsDataURL(file);
  });
}

// 用 Object URL 載入而不是 FileReader→dataURL→img.src，避免 Samsung Internet
// 對大型 data URL 處理不穩定造成預覽破圖
function memoLoadImageFromBlob(file) {
  return new Promise(function(resolve, reject) {
    var url = URL.createObjectURL(file);
    var img = new Image();
    img.onload = function() {
      var w = img.naturalWidth, h = img.naturalHeight;
      URL.revokeObjectURL(url);
      if (!w || !h) { reject(new Error("zero dimensions")); return; }
      resolve({ source: img, width: w, height: h });
    };
    img.onerror = function() {
      URL.revokeObjectURL(url);
      reject(new Error("image load failed"));
    };
    img.src = url;
  });
}

function memoLoadImageBitmap(file) {
  if (typeof createImageBitmap !== "function") {
    return Promise.reject(new Error("createImageBitmap not supported"));
  }
  var opts;
  try { opts = { imageOrientation: "from-image" }; } catch (_) { opts = undefined; }
  return createImageBitmap(file, opts || undefined).then(function(bm) {
    return { source: bm, width: bm.width, height: bm.height };
  });
}

function memoCompressImage(file, maxDim, quality) {
  function draw(loaded) {
    var w = loaded.width, h = loaded.height;
    var scale = Math.min(1, maxDim / Math.max(w, h));
    var tw = Math.round(w * scale), th = Math.round(h * scale);
    var canvas = document.createElement("canvas");
    canvas.width = tw; canvas.height = th;
    var ctx = canvas.getContext("2d");
    ctx.fillStyle = "#fff";  // 白底，處理透明 PNG
    ctx.fillRect(0, 0, tw, th);
    ctx.drawImage(loaded.source, 0, 0, tw, th);
    return { dataUrl: canvas.toDataURL("image/jpeg", quality), canvas: canvas };
  }
  return memoLoadImageBitmap(file)
    .catch(function() { return memoLoadImageFromBlob(file); })
    .then(draw);
}

function memoOpenComposer(title, opts) {
  opts = opts || {};
  var box = document.getElementById("memo-composer");
  if (!box) return;
  document.getElementById("memo-composer-title").textContent = title;
  document.getElementById("memo-text").value = "";
  document.getElementById("memo-for-doctor").checked = !!opts.forDoctor;

  memoRenderStagedPreview();
  box.style.display = "block";
  box.scrollIntoView({ behavior: "smooth", block: "nearest" });
  setTimeout(function() {
    var ta = document.getElementById("memo-text");
    if (ta) ta.focus();
  }, 50);
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function memoCancelCompose() {
  _memoComposeMode = null;
  _memoStagedPhoto = null;
  _memoStagedPhotoCanvas = null;
  _memoEditingId = null;
  var box = document.getElementById("memo-composer");
  if (box) box.style.display = "none";
}

function memoSave() {
  var text = (document.getElementById("memo-text").value || "").trim();
  var forDoctor = document.getElementById("memo-for-doctor").checked;
  if (!_memoStagedPhoto && !text) {
    showToast("寫點什麼或加張照片再儲存", "warning");
    return;
  }
  var memos = memoLoad();
  var editingId = _memoEditingId;
  if (editingId) {
    var idx = memos.findIndex(function(x) { return x.id === editingId; });
    if (idx >= 0) {
      memos[idx] = Object.assign({}, memos[idx], {
        type: _memoStagedPhoto ? "photo" : "text",
        photo: _memoStagedPhoto || null,
        text: text,
        forDoctor: !!forDoctor,
        updatedAt: new Date().toISOString()
      });
    }
  } else {
    memos.unshift({
      id: "m_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
      type: _memoStagedPhoto ? "photo" : "text",
      photo: _memoStagedPhoto || null,
      text: text,
      forDoctor: !!forDoctor,
      createdAt: new Date().toISOString()
    });
  }
  memoSaveAll(memos);
  memoCancelCompose();
  memoRenderList();
  showToast(editingId ? "已更新" : "已儲存", "success");
  if (typeof refreshNavBadges === 'function') refreshNavBadges();
}

function memoEdit(id) {
  var memos = memoLoad();
  var m = memos.find(function(x) { return x.id === id; });
  if (!m) return;
  _memoEditingId = id;
  _memoComposeMode = m.photo ? "photo" : "text";
  _memoStagedPhoto = m.photo || null;
  _memoStagedPhotoCanvas = null; // 編輯模式只有 dataURL，preview 走 createImageBitmap 異步路徑

  var box = document.getElementById("memo-composer");
  if (!box) return;
  document.getElementById("memo-composer-title").textContent = "編輯 memo";
  document.getElementById("memo-text").value = m.text || "";
  document.getElementById("memo-for-doctor").checked = !!m.forDoctor;

  memoRenderStagedPreview();
  box.style.display = "block";
  box.scrollIntoView({ behavior: "smooth", block: "nearest" });
  setTimeout(function() {
    var ta = document.getElementById("memo-text");
    if (ta) ta.focus();
  }, 50);
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function memoDelete(id) {
  if (!confirm("確定要刪除這則 memo？")) return;
  var memos = memoLoad().filter(function(m) { return m.id !== id; });
  memoSaveAll(memos);
  memoRenderList();
}

function memoOpenLightbox(id) {
  var memos = memoLoad();
  var m = memos.find(function(x) { return x.id === id; });
  if (!m) return;
  // 已存在的 overlay 先關掉避免疊起來
  var existing = document.getElementById("memo-lightbox");
  if (existing) existing.remove();

  var bodyHtml = "";
  if (m.photo) {
    bodyHtml += '<div class="memo-lb-photo-slot"></div>';
  }
  if (m.text) {
    bodyHtml += '<div class="memo-lb-text">' + escapeHtml(m.text).replace(/\n/g, "<br>") + '</div>';
  }
  var pill = m.forDoctor
    ? '<span class="memo-pill memo-pill-doctor"><i data-lucide="stethoscope" style="width:12px;height:12px"></i> 給醫師</span>'
    : '<span class="memo-pill memo-pill-self"><i data-lucide="user" style="width:12px;height:12px"></i> 自己</span>';

  var overlay = document.createElement("div");
  overlay.id = "memo-lightbox";
  overlay.className = "memo-lightbox-overlay";
  overlay.setAttribute("role", "dialog");
  overlay.setAttribute("aria-modal", "true");
  overlay.innerHTML =
    '<div class="memo-lightbox-card" onclick="event.stopPropagation()">' +
      '<div class="memo-lightbox-meta">' +
        pill +
        '<span class="memo-time">' + escapeHtml(memoFormatTime(m.createdAt)) + '</span>' +
        '<button class="memo-lightbox-close" onclick="memoCloseLightbox()" aria-label="關閉">' +
          '<i data-lucide="x" style="width:18px;height:18px"></i>' +
        '</button>' +
      '</div>' +
      '<div class="memo-lightbox-body">' + bodyHtml + '</div>' +
    '</div>';
  overlay.addEventListener("click", memoCloseLightbox);
  document.body.appendChild(overlay);
  if (m.photo) {
    var lbSlot = overlay.querySelector(".memo-lb-photo-slot");
    if (lbSlot) memoMountPhoto(lbSlot, m.photo, "memo-lb-photo");
  }
  if (typeof lucide !== 'undefined') lucide.createIcons();
  document.addEventListener("keydown", _memoLightboxEsc);
}

function memoCloseLightbox() {
  var el = document.getElementById("memo-lightbox");
  if (el) el.remove();
  document.removeEventListener("keydown", _memoLightboxEsc);
}

function _memoLightboxEsc(e) {
  if (e.key === "Escape") memoCloseLightbox();
}

function memoToggleDoctor(id) {
  var memos = memoLoad();
  var m = memos.find(function(x) { return x.id === id; });
  if (!m) return;
  m.forDoctor = !m.forDoctor;
  memoSaveAll(memos);
  memoRenderList();
}

function memoSetFilter(f) {
  _memoFilter = f;
  document.querySelectorAll(".memo-filter-btn").forEach(function(b) {
    b.classList.toggle("active", b.getAttribute("data-filter") === f);
  });
  memoRenderList();
}

function memoFormatTime(iso) {
  var d = new Date(iso);
  var now = new Date();
  var diff = (now - d) / 1000;
  if (diff < 60) return "剛剛";
  if (diff < 3600) return Math.floor(diff / 60) + " 分鐘前";
  if (diff < 86400) return Math.floor(diff / 3600) + " 小時前";
  if (diff < 604800) return Math.floor(diff / 86400) + " 天前";
  return _localDay(d);
}

function memoRenderList() {
  var listEl = document.getElementById("memo-list");
  var countEl = document.getElementById("memo-count");
  var titleEl = document.getElementById("memo-list-title");
  if (!listEl) return;

  var all = memoLoad();
  var filtered = all.filter(function(m) {
    if (_memoFilter === "doctor") return !!m.forDoctor;
    if (_memoFilter === "self")   return !m.forDoctor;
    return true;
  });

  if (countEl) countEl.textContent = filtered.length;
  if (titleEl) {
    titleEl.textContent = _memoFilter === "doctor" ? "給醫師的話" :
                          _memoFilter === "self"   ? "自己的備忘" : "所有 memo";
  }

  if (!filtered.length) {
    listEl.innerHTML =
      '<div class="memo-empty">' +
        (all.length ? '這個分類下還沒有 memo，換個篩選看看。' :
                      '還沒有 memo —— 從上方「拍照片」或「寫下要說的話」開始吧。') +
      '</div>';
    return;
  }

  var html = filtered.map(function(m) {
    var bodyHtml = "";
    if (m.photo) {
      // Samsung Internet 上 <img src=dataURL> 會破圖 — 留空 div 佔位，渲染完 DOM 後再用
      // memoMountPhoto 把圖畫到 <canvas> 上放進去。
      bodyHtml += '<div class="memo-photo-slot" data-memo-photo="' + escapeHtml(m.id) + '"></div>';
    }
    if (m.text) {
      bodyHtml += '<div class="memo-text">' + escapeHtml(m.text).replace(/\n/g, "<br>") + '</div>';
    }
    var pill = m.forDoctor
      ? '<span class="memo-pill memo-pill-doctor"><i data-lucide="stethoscope" style="width:12px;height:12px"></i> 給醫師</span>'
      : '<span class="memo-pill memo-pill-self"><i data-lucide="user" style="width:12px;height:12px"></i> 自己</span>';
    return '' +
      '<article class="memo-item">' +
        '<div class="memo-item-meta">' +
          pill +
          '<span class="memo-time">' + escapeHtml(memoFormatTime(m.createdAt)) + '</span>' +
          '<button class="memo-toggle" onclick="memoToggleDoctor(\'' + m.id + '\')" title="切換給醫師／自己">' +
            '<i data-lucide="repeat" style="width:14px;height:14px"></i>' +
          '</button>' +
          '<button class="memo-edit" onclick="memoEdit(\'' + m.id + '\')" title="編輯">' +
            '<i data-lucide="pencil" style="width:14px;height:14px"></i>' +
          '</button>' +
          '<button class="memo-del" onclick="memoDelete(\'' + m.id + '\')" title="刪除">' +
            '<i data-lucide="trash-2" style="width:14px;height:14px"></i>' +
          '</button>' +
        '</div>' +
        '<div class="memo-item-body" onclick="memoOpenLightbox(\'' + m.id + '\')" role="button" tabindex="0" aria-label="點擊放大">' + bodyHtml + '</div>' +
      '</article>';
  }).join("");

  listEl.innerHTML = html;
  // DOM 渲染完後把每則 memo 的照片畫到對應 slot 上
  filtered.forEach(function(m) {
    if (!m.photo) return;
    var slot = listEl.querySelector('[data-memo-photo="' + (window.CSS && CSS.escape ? CSS.escape(m.id) : m.id) + '"]');
    if (slot) memoMountPhoto(slot, m.photo, "memo-photo");
  });

  // mobile mirror — v11 list-row style
  var mListEl = document.getElementById('mobile-memo-list');
  var mCountEl = document.getElementById('mobile-memo-count');
  if (mCountEl) mCountEl.textContent = filtered.length;
  if (mListEl) {
    if (!filtered.length) {
      mListEl.innerHTML = '<div class="list-row" style="grid-template-columns:1fr;color:var(--text-muted);font-size:11px;padding:14px;text-align:center">' +
        (all.length ? '這個分類下還沒有 memo' : '還沒有 memo — 從上方按鈕開始記') + '</div>';
    } else {
      mListEl.innerHTML = filtered.map(function(m) {
        var pillCls = m.forDoctor ? 'pill pill-rose' : 'pill pill-mute';
        var pillTxt = m.forDoctor ? '給醫師' : '自己';
        var pillIcon = m.forDoctor ? 'stethoscope' : 'user';
        var photoHtml = m.photo ? '<div class="mobile-memo-photo-slot" data-mobile-memo-photo="' + escapeHtml(m.id) + '" style="margin-top:4px;border-radius:8px;overflow:hidden;max-width:100%"></div>' : '';
        var textHtml = m.text ? '<div style="font-size:12px;color:var(--navy);line-height:1.5;margin-top:4px">' + escapeHtml(m.text).replace(/\n/g, '<br>') + '</div>' : '';
        return ''
          + '<div class="list-row" style="grid-template-columns:1fr;padding:11px 13px;align-items:flex-start;cursor:pointer" onclick="memoOpenLightbox(\'' + m.id + '\')">'
          +   '<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">'
          +     '<span class="' + pillCls + '"><i data-lucide="' + pillIcon + '"></i>' + pillTxt + '</span>'
          +     '<span class="time" style="font-size:10.5px;color:var(--text-muted);font-family:var(--font-mono,monospace)">' + escapeHtml(memoFormatTime(m.createdAt)) + '</span>'
          +     '<span style="flex:1"></span>'
          +     '<button onclick="event.stopPropagation();memoToggleDoctor(\'' + m.id + '\')" title="切換給醫師/自己" style="border:none;background:none;cursor:pointer;color:var(--text-muted);padding:2px"><i data-lucide="repeat" style="width:13px;height:13px"></i></button>'
          +     '<button onclick="event.stopPropagation();memoEdit(\'' + m.id + '\')" title="編輯" style="border:none;background:none;cursor:pointer;color:var(--text-muted);padding:2px"><i data-lucide="pencil" style="width:13px;height:13px"></i></button>'
          +     '<button onclick="event.stopPropagation();memoDelete(\'' + m.id + '\')" title="刪除" style="border:none;background:none;cursor:pointer;color:var(--rose-deep);padding:2px"><i data-lucide="trash-2" style="width:13px;height:13px"></i></button>'
          +   '</div>'
          +   textHtml
          +   photoHtml
          + '</div>';
      }).join('');
      // 把照片畫到 slot
      filtered.forEach(function(m) {
        if (!m.photo) return;
        var slot = mListEl.querySelector('[data-mobile-memo-photo="' + (window.CSS && CSS.escape ? CSS.escape(m.id) : m.id) + '"]');
        if (slot) memoMountPhoto(slot, m.photo, 'memo-photo');
      });
    }
  }
  // 同步 mobile filter chip 高亮
  document.querySelectorAll('[data-mobile-memo-filter]').forEach(function(b) {
    b.classList.toggle('active', b.getAttribute('data-mobile-memo-filter') === _memoFilter);
  });

  if (typeof lucide !== 'undefined') lucide.createIcons();
}

// ── 每日故事：分類推送（疾病 / 健康快訊 / 最新資訊）─────────
var STORY_CATEGORIES = [
  { key: "disease",    label: "疾病故事", icon: "stethoscope", desc: "用故事的方式，把一個疾病講給你聽" },
  { key: "quick_tip",  label: "健康快訊", icon: "zap",         desc: "今天就能用的小知識" },
  { key: "news",       label: "最新資訊", icon: "newspaper",   desc: "醫療新聞、衛教快報" }
];

function story() {
  var sectionsHtml = STORY_CATEGORIES.map(function(c) {
    return '' +
      '<div class="card story-section" id="story-section-' + c.key + '">' +
        '<div class="story-section-head">' +
          '<span class="story-section-cat story-cat-' + c.key + '">' +
            '<i data-lucide="' + c.icon + '" style="width:14px;height:14px;vertical-align:middle"></i> ' + c.label +
          '</span>' +
          '<span class="story-section-date" id="story-date-' + c.key + '">—</span>' +
        '</div>' +
        '<p class="story-section-desc">' + c.desc + '</p>' +
        '<div class="story-section-body" id="story-body-' + c.key + '">' +
          '<div style="color:var(--text-dim);font-size:.9rem;padding:12px 0">載入中…</div>' +
        '</div>' +
      '</div>';
  }).join("");

  // ─── Mobile v11 block ───
  var _catColor = { disease: { bg: 'puzzle-bg-rose-amber', pill: 'pill-rose', icon: 'stethoscope', tint: 'var(--rose-tint)', text: 'var(--rose-deep)' },
                    quick_tip: { bg: 'puzzle-bg-blue-teal', pill: 'pill-warn', icon: 'zap', tint: 'var(--amber-soft)', text: 'var(--amber-deep)' },
                    news: { bg: 'puzzle-bg-rose-amber', pill: 'pill-info', icon: 'newspaper', tint: 'var(--accent-tint)', text: 'var(--accent-deep)' } };
  var mobileSectionsHtml = STORY_CATEGORIES.map(function(c) {
    var conf = _catColor[c.key] || {};
    return ''
      + '<div class="sec-head">'
      +   '<h3 class="sec-title"><i data-lucide="' + c.icon + '"></i> ' + c.label + '</h3>'
      +   '<span id="mobile-story-date-' + c.key + '" class="sec-count">—</span>'
      +   '<span class="sec-spacer"></span>'
      + '</div>'
      + '<div id="mobile-story-body-' + c.key + '" data-story-conf="' + c.key + '" style="margin-bottom:12px">'
      +   '<div class="card" style="padding:12px;color:var(--text-muted);font-size:11px;text-align:center">載入中…</div>'
      + '</div>';
  }).join('');

  var _mobileStoryBlock = ''
    + '<div class="mobile-only">'
    +   '<div class="pv-hero" style="margin-bottom:12px">'
    +     '<svg class="puzzle-bg-layer" preserveAspectRatio="xMidYMid slice"><use href="#puzzle-bg-blue-teal"/></svg>'
    +     '<div class="pv-hero-eye">每日故事</div>'
    +     '<div style="font-size:17px;font-weight:600;color:var(--navy);margin-top:6px;line-height:1.4;position:relative;z-index:1">每天三則 — 慢慢讀懂自己的身體</div>'
    +     '<div class="pv-hero-meta" style="position:relative;z-index:1">一篇疾病故事 · 一則健康快訊 · 一份最新資訊</div>'
    +   '</div>'
    +   mobileSectionsHtml
    // 最新公告 + 過去幾天 mobile
    +   '<div class="sec-head">'
    +     '<h3 class="sec-title"><i data-lucide="rss"></i> 衛福部最新公告</h3>'
    +     '<span class="sec-spacer"></span>'
    +   '</div>'
    +   '<div id="mobile-story-newsfeed" class="list-card" style="margin-bottom:12px"></div>'
    +   '<div class="sec-head">'
    +     '<h3 class="sec-title"><i data-lucide="history"></i> 過去幾天</h3>'
    +     '<span class="sec-spacer"></span>'
    +   '</div>'
    +   '<div id="mobile-story-archive" style="display:flex;flex-direction:column;gap:8px;margin-bottom:12px"></div>'
    +   '<div class="disclaimer-footer">'
    +     '<i data-lucide="info"></i>'
    +     '<span>內容來自精選衛教文章，僅供參考。</span>'
    +   '</div>'
    + '</div>';

  return _mobileStoryBlock + `
    <div class="desktop-only">
    <div class="card story-hero">
      <h2 style="display:flex;align-items:center;gap:8px">
        <i data-lucide="book-open" style="width:22px;height:22px"></i> 每日故事
      </h2>
      <p style="margin-top:6px;color:var(--text-dim)">
        每天三則：一篇疾病故事、一則健康快訊、一份最新資訊——用故事的方式，陪你慢慢讀懂自己的身體。
      </p>
    </div>

    ${sectionsHtml}

    <div class="card" id="story-newsfeed-card">
      <h3 style="display:flex;align-items:center;gap:8px;font-size:1rem;margin:0">
        <i data-lucide="rss" style="width:16px;height:16px"></i> 衛福部最新公告
      </h3>
      <p class="story-section-desc" style="margin-top:6px">
        來自衛福部 RSS，每小時更新一次，點標題會在新分頁開啟原文。
      </p>
      <div id="story-newsfeed-list" class="story-newsfeed-list">
        <div style="color:var(--text-dim);font-size:.85rem">載入中…</div>
      </div>
    </div>

    <div class="card" id="story-celebrity-card" style="display:none">
      <h3 style="display:flex;align-items:center;gap:8px;font-size:1rem;margin:0">
        <i data-lucide="users" style="width:16px;height:16px"></i> 名人健康時刻
      </h3>
      <p class="story-section-desc" style="margin-top:6px">
        從公開報導整理：公眾人物分享的健康故事，連到相關衛教文章。
      </p>
      <div id="story-celebrity-list" class="story-celebrity-list"></div>
      <div class="story-celebrity-disclaimer">
        <i data-lucide="info" style="width:12px;height:12px;vertical-align:middle"></i>
        本區內容僅整理自公開報導，不代表醫療判斷。詳細治療仍以主治醫師為準。
      </div>
    </div>

    <div class="card" id="story-archive-card">
      <h3 style="display:flex;align-items:center;gap:8px;font-size:1rem;margin:0">
        <i data-lucide="history" style="width:16px;height:16px"></i> 過去幾天
      </h3>
      <p class="story-section-desc" style="margin-top:6px">
        最近錯過的也補得回來。點任一張卡片可以打開那天的文章。
      </p>
      <div id="story-archive-list" class="story-archive-list">
        <div style="color:var(--text-dim);font-size:.85rem">載入中…</div>
      </div>
    </div>
    </div>
  `;
}

function loadStoryPage() {
  apiFetch(API + "/education/articles/daily?days=7")
    .then(function(r) { return r.json(); })
    .then(function(data) {
      var today = (data && data.today) || {};
      STORY_CATEGORIES.forEach(function(c) {
        renderStorySection(c.key, today[c.key]);
      });
      renderStoryNewsFeed((data && data.news_feed) || []);
      renderStoryCelebrities((data && data.celebrity_stories) || []);
      renderStoryArchive((data && data.archive) || []);
      if (typeof lucide !== 'undefined') lucide.createIcons();
    })
    .catch(function() {
      STORY_CATEGORIES.forEach(function(c) {
        var body = document.getElementById("story-body-" + c.key);
        if (body) body.innerHTML = '<div style="color:var(--text-dim);font-size:.9rem;padding:12px 0">載入失敗，請稍後再試。</div>';
      });
      var nf = document.getElementById("story-newsfeed-list");
      if (nf) nf.innerHTML = '<div style="color:var(--text-dim);font-size:.85rem">無法取得最新公告。</div>';
      var arc = document.getElementById("story-archive-list");
      if (arc) arc.innerHTML = '';
    });
}

function _mobileStorySync(catKey, article) {
  var mDate = document.getElementById('mobile-story-date-' + catKey);
  var mBody = document.getElementById('mobile-story-body-' + catKey);
  if (!mBody) return;
  if (!article) {
    if (mDate) mDate.textContent = '';
    mBody.innerHTML = '<div class="card" style="padding:12px;color:var(--text-muted);font-size:11px;text-align:center">這個分類今天還沒有故事</div>';
    return;
  }
  if (mDate) mDate.textContent = article.pushed_on || '';
  var conf = { disease: { bg: 'puzzle-bg-rose-amber', icon: 'stethoscope' },
               quick_tip: { bg: 'puzzle-bg-blue-teal', icon: 'zap' },
               news: { bg: 'puzzle-bg-rose-amber', icon: 'newspaper' } }[catKey] || { bg: 'puzzle-bg-blue-teal', icon: 'book-open' };
  var tags = (article.tags || []).slice(0, 3).map(function(t) {
    return '<span class="pill pill-mute">' + escapeHtml(t) + '</span>';
  }).join('');
  var bodyShort = article.summary || (article.body ? String(article.body).slice(0, 120) + '…' : '');
  mBody.innerHTML = ''
    + '<button class="card" style="text-align:left;padding:13px;cursor:pointer;position:relative;overflow:hidden;display:flex;flex-direction:column;gap:6px;width:100%" onclick="eduOpenArticle(\'' + escapeHtml(article.slug || '') + '\')">'
    +   '<svg class="puzzle-bg-layer" preserveAspectRatio="xMidYMid slice" style="opacity:0.22"><use href="#' + conf.bg + '"/></svg>'
    +   '<div style="position:relative;z-index:1;display:flex;align-items:flex-start;gap:8px">'
    +     '<i data-lucide="' + conf.icon + '" style="width:15px;height:15px;color:var(--accent-deep);margin-top:1px;flex-shrink:0"></i>'
    +     '<div style="flex:1">'
    +       '<div style="font-size:13.5px;font-weight:600;color:var(--navy);line-height:1.35">' + escapeHtml(article.title || '') + '</div>'
    +       (bodyShort ? '<div style="font-size:11px;color:var(--text-dim);margin-top:4px;line-height:1.55">' + escapeHtml(bodyShort) + '</div>' : '')
    +       (tags ? '<div style="display:flex;gap:4px;flex-wrap:wrap;margin-top:6px">' + tags + '</div>' : '')
    +     '</div>'
    +   '</div>'
    + '</button>';
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function renderStorySection(catKey, article) {
  // mobile mirror
  _mobileStorySync(catKey, article);
  var dateEl = document.getElementById("story-date-" + catKey);
  var body = document.getElementById("story-body-" + catKey);
  if (!body) return;
  if (!article) {
    if (dateEl) dateEl.textContent = "";
    body.innerHTML = '<div style="color:var(--text-dim);font-size:.9rem;padding:12px 0">這個分類今天還沒有故事。</div>';
    return;
  }
  if (!window._eduArticles) window._eduArticles = {};
  window._eduArticles[article.slug] = article;

  if (dateEl) dateEl.textContent = article.pushed_on || "";

  var tags = (article.tags || []).map(function(t) {
    return '<span class="story-tag">' + escapeHtml(t) + '</span>';
  }).join("");
  var sources = (article.sources || []).map(function(s) {
    return '<li>' + escapeHtml(s) + '</li>';
  }).join("");
  var bodyHtml = article.body
    ? '<div class="story-body">' + markdownToHtml(article.body) + '</div>'
    : '<div style="color:var(--text-dim);font-size:.9rem">內容尚未提供。</div>';

  body.innerHTML =
    '<h3 class="story-title">' + escapeHtml(article.title) + '</h3>' +
    (article.summary ? '<p class="story-summary">' + escapeHtml(article.summary) + '</p>' : '') +
    (tags ? '<div class="story-tags">' + tags + '</div>' : '') +
    bodyHtml +
    (sources
      ? '<div class="story-sources"><div class="story-sources-head">參考來源</div><ol>' + sources + '</ol></div>'
      : '') +
    (article.reviewed_at ? '<div class="story-reviewed">最後審稿：' + escapeHtml(article.reviewed_at) + '</div>' : '');
}

function renderStoryNewsFeed(items) {
  var list = document.getElementById("story-newsfeed-list");
  if (list) {
    if (!items.length) {
      list.innerHTML = '<div style="color:var(--text-dim);font-size:.85rem">目前沒有可顯示的公告。</div>';
    } else {
      list.innerHTML = items.map(function(n) {
        var link = n.link ? escapeHtml(n.link) : "";
        var title = escapeHtml(n.title || "（無標題）");
        var summary = n.summary ? '<p class="story-news-summary">' + escapeHtml(n.summary) + '</p>' : "";
        var pub = n.published ? '<span class="story-news-date">' + escapeHtml(n.published) + '</span>' : "";
        var titleHtml = link
          ? '<a class="story-news-title" href="' + link + '" target="_blank" rel="noopener noreferrer">' + title + '</a>'
          : '<span class="story-news-title">' + title + '</span>';
        return '<article class="story-news-item">' + titleHtml + pub + summary + '</article>';
      }).join("");
    }
  }
  // mobile mirror
  var mList = document.getElementById('mobile-story-newsfeed');
  if (mList) {
    if (!items.length) {
      mList.innerHTML = '<div class="list-row" style="grid-template-columns:1fr;color:var(--text-muted);font-size:11px;padding:14px;text-align:center">目前沒有公告</div>';
    } else {
      mList.innerHTML = items.slice(0, 8).map(function(n) {
        var link = n.link ? escapeHtml(n.link) : "";
        var rowOpen = link ? '<a href="' + link + '" target="_blank" rel="noopener noreferrer" style="text-decoration:none;color:inherit">' : '';
        var rowClose = link ? '</a>' : '';
        return ''
          + rowOpen
          + '<div class="list-row" style="grid-template-columns:14px 1fr;padding:11px 13px;align-items:flex-start">'
          +   '<i data-lucide="rss" style="width:13px;height:13px;color:var(--accent-deep);margin-top:2px"></i>'
          +   '<div>'
          +     '<div class="name">' + escapeHtml(n.title || '（無標題）') + '</div>'
          +     (n.published ? '<div style="font-size:10px;color:var(--text-muted);font-family:var(--font-mono,monospace);margin-top:2px">' + escapeHtml(n.published) + '</div>' : '')
          +     (n.summary ? '<div style="font-size:11px;color:var(--text-dim);margin-top:3px;line-height:1.5">' + escapeHtml(n.summary).slice(0, 100) + (n.summary.length > 100 ? '…' : '') + '</div>' : '')
          +   '</div>'
          + '</div>'
          + rowClose;
      }).join('');
    }
  }
}

// 事件性質 → pill 樣式 class（顏色：確診=橘、治療中=藍、康復=綠、倡議推廣=紫）
var CELEB_EVENT_CLASSES = {
  "確診":     "story-celeb-event-diag",
  "治療中":   "story-celeb-event-treat",
  "康復":     "story-celeb-event-recover",
  "倡議推廣": "story-celeb-event-advocate"
};

function renderStoryCelebrities(stories) {
  var card = document.getElementById("story-celebrity-card");
  var list = document.getElementById("story-celebrity-list");
  if (!card || !list) return;
  if (!stories.length) {
    // 沒設 NEWS_FEED_URLS 或 LLM 沒抽到任何名人故事 — 整張卡藏起來
    card.style.display = "none";
    return;
  }
  card.style.display = "";

  list.innerHTML = stories.map(function(s, idx) {
    var person = escapeHtml(s.person || "");
    var diseaseName = escapeHtml(s.disease_name || s.disease_keyword || "");
    var eventType = s.event_type || "";
    var eventClass = CELEB_EVENT_CLASSES[eventType] || "story-celeb-event-advocate";
    var framing = escapeHtml(s.soft_framing || "");
    var link = s.source_link ? escapeHtml(s.source_link) : "";
    var sourceTitle = escapeHtml(s.source_title || "原始報導");

    var relatedHtml = "";
    if (s.related_articles && s.related_articles.length) {
      var articleId = "story-celeb-related-" + idx;
      // 順便 prime _eduArticles 快取，讓 storyOpenArchive 能直接命中
      if (!window._eduArticles) window._eduArticles = {};
      s.related_articles.forEach(function(a) {
        window._eduArticles[a.slug] = Object.assign(window._eduArticles[a.slug] || {}, a);
      });
      relatedHtml =
        '<div class="story-celeb-related" id="' + articleId + '">' +
          '<div class="story-celeb-related-head">' +
            '<i data-lucide="book-open" style="width:12px;height:12px;vertical-align:middle"></i> ' +
            '相關衛教' + (diseaseName ? '：' + diseaseName : '') +
          '</div>' +
          s.related_articles.map(function(a) {
            return '<button class="story-celeb-related-item" ' +
                     'onclick="storyOpenArchive(\'' + escapeHtml(a.slug) + '\',\'disease\')">' +
                     '<i data-lucide="arrow-right" style="width:12px;height:12px"></i> ' +
                     escapeHtml(a.title || a.slug) +
                   '</button>';
          }).join("") +
        '</div>';
    }

    var sourceHtml = link
      ? '<a class="story-celeb-source" href="' + link + '" target="_blank" rel="noopener noreferrer" title="' + sourceTitle + '">' +
          '<i data-lucide="external-link" style="width:12px;height:12px;vertical-align:middle"></i> 看新聞原文' +
        '</a>'
      : '';

    var eventPill = eventType
      ? '<span class="story-celeb-event ' + eventClass + '">' + escapeHtml(eventType) + '</span>'
      : '';

    return '' +
      '<article class="story-celeb-item">' +
        '<div class="story-celeb-head">' +
          '<span class="story-celeb-person">' + person + '</span>' +
          eventPill +
        '</div>' +
        (framing ? '<p class="story-celeb-framing">' + framing + '</p>' : '') +
        relatedHtml +
        sourceHtml +
      '</article>';
  }).join("");
}

function renderStoryArchive(days) {
  var list = document.getElementById("story-archive-list");
  if (!window._eduArticles) window._eduArticles = {};
  if (list) {
    if (!days.length) {
      list.innerHTML = '<div style="color:var(--text-dim);font-size:.85rem">還沒有歷史紀錄。</div>';
    } else {
      list.innerHTML = days.map(function(day) {
        var rows = STORY_CATEGORIES.map(function(c) {
          var a = day.items && day.items[c.key];
          if (!a) return '';
          window._eduArticles[a.slug] = Object.assign({}, window._eduArticles[a.slug] || {}, a);
          return '<button class="story-archive-item" onclick="storyOpenArchive(\'' + escapeHtml(a.slug) + '\',\'' + c.key + '\')">' +
                   '<span class="story-archive-cat story-cat-' + c.key + '">' + escapeHtml(c.label) + '</span>' +
                   '<span class="story-archive-title">' + escapeHtml(a.title) + '</span>' +
                   (a.summary ? '<span class="story-archive-summary">' + escapeHtml(a.summary) + '</span>' : '') +
                 '</button>';
        }).join("");
        return '<div class="story-archive-day">' +
                 '<div class="story-archive-day-head">' + escapeHtml(day.date) + '</div>' +
                 '<div class="story-archive-day-grid">' + rows + '</div>' +
               '</div>';
      }).join("");
    }
  }
  // mobile mirror — timeline 風格（垂直線 + 圓點 + 卡片）
  var mList = document.getElementById('mobile-story-archive');
  if (mList) {
    if (!days || !days.length) {
      mList.innerHTML = '<div class="card" style="padding:12px;color:var(--text-muted);font-size:11px;text-align:center">尚無歷史紀錄</div>';
    } else {
      mList.innerHTML = days.slice(0, 7).map(function(day) {
        var rows = STORY_CATEGORIES.map(function(c) {
          var a = day.items && day.items[c.key];
          if (!a) return '';
          window._eduArticles[a.slug] = Object.assign({}, window._eduArticles[a.slug] || {}, a);
          var conf = { disease: { pill: 'pill-rose', icon: 'stethoscope' },
                       quick_tip: { pill: 'pill-warn', icon: 'zap' },
                       news: { pill: 'pill-info', icon: 'newspaper' } }[c.key] || {};
          return ''
            + '<button class="card" style="text-align:left;padding:10px 12px;cursor:pointer;width:100%;margin-bottom:6px;display:flex;align-items:flex-start;gap:8px" onclick="storyOpenArchive(\'' + escapeHtml(a.slug) + '\',\'' + c.key + '\')">'
            +   '<i data-lucide="' + (conf.icon || 'book-open') + '" style="width:13px;height:13px;color:var(--accent-deep);margin-top:2px;flex-shrink:0"></i>'
            +   '<div style="flex:1">'
            +     '<div style="display:flex;align-items:center;gap:5px;margin-bottom:3px"><span class="pill ' + (conf.pill || 'pill-mute') + '">' + escapeHtml(c.label) + '</span></div>'
            +     '<div style="font-size:12px;font-weight:600;color:var(--navy);line-height:1.4">' + escapeHtml(a.title) + '</div>'
            +     (a.summary ? '<div style="font-size:10.5px;color:var(--text-dim);margin-top:2px;line-height:1.5">' + escapeHtml(a.summary).slice(0, 70) + (a.summary.length > 70 ? '…' : '') + '</div>' : '')
            +   '</div>'
            + '</button>';
        }).join('');
        // 時間軸日期 header
        return ''
          + '<div style="position:relative;padding-left:18px;margin-bottom:8px">'
          +   '<span style="position:absolute;left:0;top:5px;width:8px;height:8px;border-radius:50%;background:var(--accent);box-shadow:0 0 0 2px var(--bg-mid,#fff)"></span>'
          +   '<span style="position:absolute;left:3px;top:13px;bottom:-8px;width:2px;background:var(--border)"></span>'
          +   '<div style="font-size:11px;font-weight:600;color:var(--text-dim);font-family:var(--font-mono,monospace);margin-bottom:5px">' + escapeHtml(day.date) + '</div>'
          +   '<div>' + rows + '</div>'
          + '</div>';
      }).join('');
    }
  }
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function storyOpenArchive(slug, catKey) {
  var cached = (window._eduArticles && window._eduArticles[slug]) || null;

  // RSS fallback 卡（slug 以 news-feed- 開頭）不是真的 markdown article，
  // 後端 /education/articles/{slug} 會 404；直接用 archive 已經帶過來的 payload 渲染。
  var isExternal = (slug && slug.indexOf("news-feed-") === 0)
    || (cached && (cached.external_link || cached.body));
  if (isExternal && cached) {
    var key1 = catKey || cached.category || "news";
    renderStorySection(key1, cached);
    var section1 = document.getElementById("story-section-" + key1);
    if (section1) section1.scrollIntoView({ behavior: "smooth", block: "start" });
    if (typeof lucide !== 'undefined') lucide.createIcons();
    return;
  }

  apiFetch(API + "/education/articles/" + encodeURIComponent(slug))
    .then(function(r) {
      if (!r.ok) throw new Error("not found");
      return r.json();
    })
    .then(function(article) {
      var prev = (window._eduArticles && window._eduArticles[slug]) || {};
      article.pushed_on = prev.pushed_on || article.pushed_on;
      var key = catKey || article.category || "disease";
      renderStorySection(key, article);
      var section = document.getElementById("story-section-" + key);
      if (section) section.scrollIntoView({ behavior: "smooth", block: "start" });
      if (typeof lucide !== 'undefined') lucide.createIcons();
    })
    .catch(function() {
      var key = catKey || "disease";
      var body = document.getElementById("story-body-" + key);
      if (body) body.innerHTML = '<div style="color:var(--text-dim);font-size:.9rem;padding:12px 0">找不到這篇文章。</div>';
    });
}

function renderPvVisitHero() {
  // 若使用者沒設下次回診日，回空字串（不顯示）
  var iso = (typeof loadNextVisit === 'function') ? loadNextVisit() : '';
  if (!iso) {
    return ''
      + '<div class="pv-visit-hero pv-visit-hero-empty">'
      +   '<div class="pv-visit-hero-icon"><i data-lucide="calendar-plus"></i></div>'
      +   '<div class="pv-visit-hero-body">'
      +     '<div class="pv-visit-hero-eyebrow">下次回診</div>'
      +     '<div class="pv-visit-hero-title">尚未設定回診日</div>'
      +     '<div class="pv-visit-hero-sub">回首頁設好回診日期，這裡就會顯示倒數和本期紀錄範圍。</div>'
      +   '</div>'
      +   '<button class="pv-btn pv-btn-ghost" onclick="navigateTo(\'home\',null)">'
      +     '<i data-lucide="home"></i> 前往設定'
      +   '</button>'
      + '</div>';
  }
  var d = _daysBetween(iso);
  var pretty = iso.replace(/-/g, '/');
  var sessFull = (typeof sessionLabel === 'function') ? sessionLabel(loadNextVisitSession()) : '';
  var sessSuffix = sessFull ? ('（' + sessFull + '）') : '';
  var label, tone, eyebrow;
  if (d > 0)       { label = '倒數 ' + d + ' 天' + sessSuffix; tone = 'upcoming'; eyebrow = '下次回診'; }
  else if (d === 0){ label = '今天回診' + sessSuffix;          tone = 'today';    eyebrow = '今天就是回診日'; }
  else             { label = '已超過 ' + (-d) + ' 天';         tone = 'past';     eyebrow = '上次回診'; }
  return ''
    + '<div class="pv-visit-hero pv-visit-hero-' + tone + '">'
    +   '<div class="pv-visit-hero-icon"><i data-lucide="calendar-check-2"></i></div>'
    +   '<div class="pv-visit-hero-body">'
    +     '<div class="pv-visit-hero-eyebrow">' + eyebrow + '</div>'
    +     '<div class="pv-visit-hero-title">' + label + '</div>'
    +     '<div class="pv-visit-hero-sub">日期：' + pretty + (sessFull ? ('　' + sessFull) : '') + '　·　出門前可以先看一下這頁的提醒</div>'
    +   '</div>'
    +   '<div class="pv-visit-hero-warn"><i data-lucide="info" style="width:12px;height:12px"></i> 以醫師預約單為準</div>'
    + '</div>';
}

// ─── 診前報告：基本個人資料（讀 records 頁的 localStorage） ──────
function previsitBasicInfoEntries() {
  var info = (typeof getBasicInfo === 'function') ? getBasicInfo() : {};
  var u = (typeof getCurrentUser === 'function') ? (getCurrentUser() || {}) : {};
  var entries = [];

  if (u.nickname) entries.push(['姓名 / 暱稱', u.nickname]);

  var genderMap = { male: '男', female: '女', other: '其他' };
  if (info.gender) entries.push(['性別', genderMap[info.gender] || info.gender]);

  if (info.birthday) {
    var age = (typeof calcAge === 'function') ? calcAge(info.birthday) : '';
    entries.push(['生日', info.birthday + (age ? '（' + age + '）' : '')]);
  }

  if (info.blood) entries.push(['血型', info.blood]);

  var hwParts = [];
  if (info.height) hwParts.push(info.height + ' cm');
  if (info.weight) hwParts.push(info.weight + ' kg');
  var bmi = (typeof calcBMI === 'function') ? calcBMI(info.height, info.weight) : '';
  if (bmi) hwParts.push('BMI ' + bmi);
  if (hwParts.length) entries.push(['身高體重', hwParts.join(' · ')]);

  if (info.allergies) entries.push(['過敏', info.allergies]);
  if (info.conditions) entries.push(['慢性病', info.conditions]);
  if (info.current_disease) entries.push(['目前疾病', info.current_disease]);
  if (info.meds) entries.push(['目前用藥', info.meds]);

  if (info.doctor_name || info.hospital) {
    entries.push(['主治醫師', [info.doctor_name, info.hospital].filter(Boolean).join('｜')]);
  }
  if (info.emergency_name || info.emergency_phone) {
    entries.push(['緊急聯絡人', [info.emergency_name, info.emergency_phone].filter(Boolean).join(' ')]);
  }

  return entries;
}

function previsitBasicInfoHTML() {
  var entries = previsitBasicInfoEntries();
  if (!entries.length) {
    return ''
      + '<section class="pv-section pv-basic">'
      + '  <h3 class="pv-section-title"><i data-lucide="id-card"></i> 基本個人資料</h3>'
      + '  <p class="pv-basic-empty">尚未填寫。<a href="#" onclick="navigateTo(\'records\'); return false;">前往「我的基本資料」</a>填寫，看診更省心。</p>'
      + '</section>';
  }
  var items = entries.map(function(e) {
    return ''
      + '<div class="pv-basic-item">'
      + '  <span class="pv-basic-label">' + escapeHtml(e[0]) + '</span>'
      + '  <span class="pv-basic-value">' + escapeHtml(e[1]) + '</span>'
      + '</div>';
  }).join('');
  return ''
    + '<section class="pv-section pv-basic">'
    + '  <h3 class="pv-section-title"><i data-lucide="id-card"></i> 基本個人資料</h3>'
    + '  <div class="pv-basic-grid">' + items + '</div>'
    + '</section>';
}

function previsitBasicInfoTableHTML() {
  var entries = previsitBasicInfoEntries();
  if (!entries.length) {
    return '<p class="basic-empty">（使用者未填寫基本資料，請先到「我的基本資料」頁完整填寫後再產出報告）</p>';
  }
  var rows = entries.map(function(e) {
    return '<tr><th>' + escapeHtml(e[0]) + '</th><td>' + escapeHtml(e[1]) + '</td></tr>';
  }).join('');
  return '<table class="basic-info"><tbody>' + rows + '</tbody></table>';
}

