// 顯示/隱藏某 panel 的所有密碼欄位（顯示密碼勾選框）。
function toggleAuthPw(panel, show) {
  const ids = {
    login: ['login-password'],
    register: ['reg-password', 'reg-password2'],
    forgot: ['forgot-new-password'],
  }[panel] || [];
  const type = show ? 'text' : 'password';
  ids.forEach(id => { const el = document.getElementById(id); if (el) el.type = type; });
}

// Caps Lock 偵測：在密碼欄打字時提示，避免使用者大寫鎖定卻不自知一直登入失敗。
function detectCapsLock(event, hintId) {
  const hint = document.getElementById(hintId);
  if (!hint || !event.getModifierState) return;
  hint.hidden = !event.getModifierState('CapsLock');
}

// 前端密碼強度檢查（與 backend/routers/auth.py 的 _validate_password 規則一致）。
// 回 null 代表通過，否則回錯誤訊息字串。
function validateClientPassword(password, username) {
  if (password.length < 8) return '密碼至少 8 個字元';
  if (!/[A-Za-z]/.test(password) || !/\d/.test(password)) return '密碼需同時包含英文字母與數字';
  if (username && password.toLowerCase() === username.toLowerCase()) return '密碼不可與帳號相同';
  return null;
}

function onRegAvatarPicked(e) {
  const file = e.target.files && e.target.files[0];
  if (!file) return;
  const input = e.target;
  // iOS HEIC 有時 file.type 是空字串；只在明確不是圖片時擋
  if (file.type && file.type.indexOf('image/') !== 0) {
    if (typeof showToast === 'function') showToast('請選擇圖片檔', 'warning');
    try { input.value = ''; } catch (_) {}
    return;
  }
  prepareAvatarDataUrl(file).then(dataUrl => {
    _regAvatarDataUrl = dataUrl;
    const img = document.getElementById('reg-avatar-img');
    const ph = document.getElementById('reg-avatar-placeholder');
    const clr = document.getElementById('reg-avatar-clear');
    if (img) { img.src = dataUrl; img.hidden = false; }
    if (ph) ph.hidden = true;
    if (clr) clr.hidden = false;
    if (typeof showToast === 'function') showToast('頭像已準備好，記得按「建立帳號」儲存', 'success');
  }).catch(err => {
    console.warn('[avatar] register pick failed', err);
    try { input.value = ''; } catch (_) {}
    if (typeof showToast === 'function') showToast(err && err.message ? err.message : '頭像讀取失敗', 'error');
    showAuthError('register', err && err.message ? err.message : '頭像讀取失敗');
  });
}

function clearRegAvatar() {
  _regAvatarDataUrl = '';
  const img = document.getElementById('reg-avatar-img');
  const ph = document.getElementById('reg-avatar-placeholder');
  const clr = document.getElementById('reg-avatar-clear');
  const file = document.getElementById('reg-avatar-file');
  if (img) { img.hidden = true; img.src = ''; }
  if (ph) ph.hidden = false;
  if (clr) clr.hidden = true;
  if (file) file.value = '';
}

function shrinkImageToDataUrl(file, maxSize, quality) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(1, maxSize / Math.max(img.width, img.height));
        const w = Math.round(img.width * scale);
        const h = Math.round(img.height * scale);
        const canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL('image/jpeg', quality || 0.85));
      };
      img.onerror = reject;
      img.src = reader.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

// 共用的「相機/相簿照片 → 適合當頭像的 dataURL」管線：
// - 偵測 HEIC（iPhone 預設）並先轉成 JPEG，避免 Android Chrome / Samsung 直接掛掉
// - 透過 memoCompressImage 走 createImageBitmap → Object URL 兩段 fallback，比單純
//   FileReader→<img> 在大型 / 旋轉過的相簿照片上穩很多
// - 失敗時拋出帶人話訊息的 Error，呼叫端可以直接顯示給使用者
function prepareAvatarDataUrl(file) {
  const maxDim = 320;
  const quality = 0.85;
  let pipeline;
  if (typeof memoIsHeic === 'function' && memoIsHeic(file)) {
    if (typeof showToast === 'function') showToast('照片是 HEIC 格式，正在轉檔…', 'info');
    pipeline = memoConvertHeicToJpeg(file).catch(err => {
      console.warn('[avatar] HEIC convert failed', err);
      throw new Error('HEIC 轉檔失敗 — 請改用 JPEG（iPhone 設定 → 相機 → 格式 → 相容）');
    });
  } else {
    pipeline = Promise.resolve(file);
  }
  return pipeline.then(usable => {
    if (typeof memoCompressImage === 'function') {
      return memoCompressImage(usable, maxDim, quality).then(r => r.dataUrl);
    }
    return shrinkImageToDataUrl(usable, maxDim, quality);
  }).then(dataUrl => {
    if (typeof memoIsValidDataUrl === 'function' && !memoIsValidDataUrl(dataUrl)) {
      throw new Error('頭像讀取失敗，請換一張');
    }
    return dataUrl;
  });
}

function showAuthError(panel, msg) {
  const el = document.getElementById(`${panel}-error`);
  if (!el) return;
  el.textContent = msg;
  el.hidden = false;
}

async function submitLogin() {
  const username = document.getElementById('login-username').value.trim();
  const password = document.getElementById('login-password').value;
  if (!username || !password) return;
  const btn = document.getElementById('login-submit');
  const original = btn.innerHTML;
  btn.disabled = true;
  btn.innerHTML = '<i data-lucide="loader"></i> 登入中…';
  if (typeof lucide !== 'undefined') lucide.createIcons();
  document.getElementById('login-error').hidden = true;
  try {
    const res = await apiFetch(`${API}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, password }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || '登入失敗');
    }
    const user = await res.json();
    finishAuth(user);
  } catch (e) {
    showAuthError('login', e.message || '登入失敗，請稍後再試');
    btn.disabled = false;
    btn.innerHTML = original;
    if (typeof lucide !== 'undefined') lucide.createIcons();
  }
}

async function submitRegister() {
  const nickname = document.getElementById('reg-nickname').value.trim();
  const username = document.getElementById('reg-username').value.trim();
  const password = document.getElementById('reg-password').value;
  const password2 = document.getElementById('reg-password2').value;
  const recoveryQuestion = document.getElementById('reg-recovery-question').value.trim();
  const recoveryAnswer = document.getElementById('reg-recovery-answer').value.trim();

  if (!/^[A-Za-z0-9_.\-]{3,32}$/.test(username)) {
    showAuthError('register', '帳號格式不正確（3-32 字元，限英數字 _ . -）');
    return;
  }
  if (password !== password2) {
    showAuthError('register', '兩次輸入的密碼不一致');
    return;
  }
  const pwErr = validateClientPassword(password, username);
  if (pwErr) {
    showAuthError('register', pwErr);
    return;
  }
  // 安全問題為選填，但若填了一邊就要兩邊都填
  if ((recoveryQuestion && !recoveryAnswer) || (!recoveryQuestion && recoveryAnswer)) {
    showAuthError('register', '安全問題與答案請一起填寫，或都留空');
    return;
  }

  const btn = document.getElementById('register-submit');
  const original = btn.innerHTML;
  btn.disabled = true;
  btn.innerHTML = '<i data-lucide="loader"></i> 建立中…';
  if (typeof lucide !== 'undefined') lucide.createIcons();
  document.getElementById('register-error').hidden = true;

  const payload = {
    username, password, nickname,
    role: 'patient',
    avatar_url: _regAvatarDataUrl || null,
  };
  if (recoveryQuestion && recoveryAnswer) {
    payload.recovery_question = recoveryQuestion;
    payload.recovery_answer = recoveryAnswer;
  }

  try {
    const res = await apiFetch(`${API}/auth/register`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || '註冊失敗');
    }
    const user = await res.json();
    finishAuth(user);
  } catch (e) {
    showAuthError('register', e.message || '註冊失敗，請稍後再試');
    btn.disabled = false;
    btn.innerHTML = original;
    if (typeof lucide !== 'undefined') lucide.createIcons();
  }
}

// 忘記密碼第一步：用帳號查回安全問題；查到才展開第二步。
async function lookupRecoveryQuestion() {
  const username = document.getElementById('forgot-username').value.trim();
  if (!username) return;
  const btn = document.getElementById('forgot-lookup');
  const original = btn.innerHTML;
  btn.disabled = true;
  btn.innerHTML = '<i data-lucide="loader"></i> 查詢中…';
  if (typeof lucide !== 'undefined') lucide.createIcons();
  document.getElementById('forgot-error').hidden = true;
  try {
    const res = await apiFetch(`${API}/auth/recovery/question`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || '查無此帳號的安全問題');
    }
    const data = await res.json();
    document.getElementById('forgot-question').textContent = data.question || '';
    document.getElementById('forgot-step2').hidden = false;
  } catch (e) {
    showAuthError('forgot', e.message || '查詢失敗，請稍後再試');
  } finally {
    btn.disabled = false;
    btn.innerHTML = original;
    if (typeof lucide !== 'undefined') lucide.createIcons();
  }
}

// 忘記密碼第二步：答對安全問題即可設定新密碼，成功後導回登入。
async function submitRecoveryReset() {
  const username = document.getElementById('forgot-username').value.trim();
  const answer = document.getElementById('forgot-answer').value.trim();
  const newPassword = document.getElementById('forgot-new-password').value;
  if (!answer) { showAuthError('forgot', '請輸入安全問題的答案'); return; }
  const pwErr = validateClientPassword(newPassword, username);
  if (pwErr) { showAuthError('forgot', pwErr); return; }

  const btn = document.getElementById('forgot-submit');
  const original = btn.innerHTML;
  btn.disabled = true;
  btn.innerHTML = '<i data-lucide="loader"></i> 重設中…';
  if (typeof lucide !== 'undefined') lucide.createIcons();
  document.getElementById('forgot-error').hidden = true;
  try {
    const res = await apiFetch(`${API}/auth/recovery/reset`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, answer, new_password: newPassword }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || '重設失敗');
    }
    if (typeof showToast === 'function') showToast('密碼已重設，請用新密碼登入', 'success');
    switchAuthTab('login');
    document.getElementById('login-username').value = username;
  } catch (e) {
    showAuthError('forgot', e.message || '重設失敗，請稍後再試');
  } finally {
    btn.disabled = false;
    btn.innerHTML = original;
    if (typeof lucide !== 'undefined') lucide.createIcons();
  }
}

function finishAuth(user) {
  if (user.username) {
    try { localStorage.setItem('mdpiece_last_username', user.username); } catch {}
  }
  setCurrentUser(user);
  const overlay = document.getElementById('register-overlay');
  overlay.classList.remove('show');
  setTimeout(() => {
    overlay.style.display = 'none';
    document.getElementById('app-wrapper').classList.add('show');
    showPage('home');
    if (typeof lucide !== 'undefined') lucide.createIcons();
    // Profile onboarding 先跳（強制問慢性病），完成後再進原本的 tutorial onboarding
    if (typeof maybeShowProfileOnboarding === 'function') {
      maybeShowProfileOnboarding(function() {
        if (typeof maybeShowOnboarding === 'function') maybeShowOnboarding();
      });
    } else if (typeof maybeShowOnboarding === 'function') {
      maybeShowOnboarding();
    }
  }, 250);
}

// ─── Profile onboarding（Issue #131 follow-up）──────────
// 註冊／首次登入後若 backend profile.conditions 空就跳，強制收集慢性病。
// 「先跳過」會記在 localStorage（per-uid），下次登入不會再跳，但 records 頁仍可填。
const PROFILE_ONB_COMMON = [
  '高血壓', '糖尿病', '高血脂', '心臟病',
  '中風後', '氣喘', '慢性腎臟病', '甲狀腺',
  '失智症', '癌症', '肝病', '關節炎',
];
const PROFILE_ONB_SKIP_KEY = 'mdpiece_profile_onb_skip';

function maybeShowProfileOnboarding(onDone) {
  var uid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  var skipKey = PROFILE_ONB_SKIP_KEY + ':' + uid;
  if (uid && localStorage.getItem(skipKey) === '1') { if (onDone) onDone(); return; }
  // 拉一次後端 profile：有 conditions 就視為已填過，不跳
  fetchBasicInfoFromServer().then(function(remote) {
    var hasCond = remote && (remote.conditions || '').trim();
    if (hasCond) { if (onDone) onDone(); return; }
    _renderProfileOnboarding(onDone);
  }).catch(function() { _renderProfileOnboarding(onDone); });
}

function _renderProfileOnboarding(onDone) {
  var overlay = document.getElementById('profile-onb-overlay');
  if (!overlay) { if (onDone) onDone(); return; }
  var chipsBox = document.getElementById('profile-onb-chips');
  chipsBox.innerHTML = PROFILE_ONB_COMMON.map(function(name) {
    return '<button type="button" class="profile-onb-chip" data-cond="' + escapeHtml(name) + '">' + escapeHtml(name) + '</button>';
  }).join('');
  chipsBox.querySelectorAll('.profile-onb-chip').forEach(function(btn) {
    btn.addEventListener('click', function() { btn.classList.toggle('active'); });
  });
  // 預填 textarea：若 localStorage 已有舊資料，帶進來讓使用者直接編
  var existing = getBasicInfo();
  if (existing && existing.conditions) {
    document.getElementById('profile-onb-extra').value = existing.conditions;
  }
  overlay.hidden = false;
  requestAnimationFrame(function() { overlay.classList.add('show'); });
  // 把 onDone 暫存到 overlay，submit/skip 時取出
  overlay._onDone = onDone;
}

function profileOnboardingSubmit() {
  var overlay = document.getElementById('profile-onb-overlay');
  var chipsActive = Array.from(document.querySelectorAll('#profile-onb-chips .profile-onb-chip.active'))
    .map(function(b) { return b.dataset.cond; });
  var extra = (document.getElementById('profile-onb-extra').value || '').trim();
  var combined = chipsActive.join('、');
  if (extra) combined = combined ? (combined + '、' + extra) : extra;
  if (!combined) { showToast && showToast('請至少選一項或填寫', 'warning'); return; }
  // Merge 進現有 basicInfo（保留其他欄位），同步後端
  var info = getBasicInfo() || {};
  info.conditions = combined;
  setBasicInfo(info);
  syncBasicInfoToServer(info).then(function(ok) {
    if (!ok) showToast && showToast('已存本機，後端同步失敗（之後會自動重試）', 'warning');
    _closeProfileOnboarding(overlay);
  });
}

function profileOnboardingSkip() {
  var overlay = document.getElementById('profile-onb-overlay');
  var uid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (uid) localStorage.setItem(PROFILE_ONB_SKIP_KEY + ':' + uid, '1');
  _closeProfileOnboarding(overlay);
}

function _closeProfileOnboarding(overlay) {
  if (!overlay) return;
  overlay.classList.remove('show');
  setTimeout(function() {
    overlay.hidden = true;
    var cb = overlay._onDone;
    overlay._onDone = null;
    if (cb) cb();
  }, 200);
}

// 切換帳號 — 不二次確認，直接回到登入頁
function switchAccount() {
  try { localStorage.removeItem('mdpiece_user'); } catch {}
  try { localStorage.removeItem('mdpiece_demo_pid'); } catch {}
  window.location.reload();
}

