    +     '<button class="care-mode-chip' + (isOut ? ' active' : '') + '" role="tab" aria-selected="' + (isOut ? 'true' : 'false') + '" onclick="setCareMode(\'outpatient\')">'
    +       '<i data-lucide="stethoscope" style="width:16px;height:16px"></i> 門診模式'
    +     '</button>'
