function submitOtherSymptomLog() {
  const name = (document.getElementById('lf-custom-name').value || '').trim();
  if (!name) {
    showToast && showToast(_T('sym.toast.needName'), 'warning');
    document.getElementById('lf-custom-name').focus();
    return;
  }
  const cat = addCustomSymptomCat(name);
  if (!cat) return;
  const intensity = parseInt(document.getElementById('lf-intensity').value);
  const frequency = parseInt(document.getElementById('lf-freq').textContent);
  const notes = document.getElementById('lf-notes').value.trim();
  saveSymptomEntry({
    id: 'sym-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
    categoryId: cat.id, intensity, frequency, notes,
    recordedAt: new Date().toISOString()
  });
  document.body.classList.remove('is-sym-logging');
  showToast && showToast(_T('sym.toast.added'), 'success');
  if (typeof refreshNavBadges === 'function') refreshNavBadges();
  showPage('symptoms');
}

function removeCustomSymptomCatAndRefresh(id) {
  if (!confirm(_T('sym.confirm.delCustom'))) return;
  removeCustomSymptomCat(id);
  showPage('symptoms');
}
function updateIntensityBar(v) {
  document.getElementById('lf-bar').innerHTML = renderIntensityBar(v);
  document.getElementById('lf-bar-value').textContent = v;
}
function adjustFreq(delta) {
  const el = document.getElementById('lf-freq');
  el.textContent = Math.max(1, parseInt(el.textContent || '1') + delta);
}
function submitSymptomLog(catId) {
  const intensity = parseInt(document.getElementById('lf-intensity').value);
  const frequency = parseInt(document.getElementById('lf-freq').textContent);
  const notes = document.getElementById('lf-notes').value.trim();
  saveSymptomEntry({
    id: 'sym-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
    categoryId: catId, intensity, frequency, notes,
    recordedAt: new Date().toISOString()
  });
  document.body.classList.remove('is-sym-logging');
  if (typeof refreshNavBadges === 'function') refreshNavBadges();
  showPage('symptoms');
}
function deleteSymptomEntryAndRefresh(id) {
  if (!confirm(_T('sym.confirm.delEntry'))) return;
  deleteSymptomEntry(id);
  if (typeof refreshNavBadges === 'function') refreshNavBadges();
  showPage('symptoms');
}
function renderIntensityBar(v) {
  v = parseInt(v) || 0;
  const blocks = ['▁','▂','▂','▃','▃','▄','▄','▅','▆','█'];
  let out = '';
  for (let i = 0; i < 10; i++) {
    out += i < v
      ? `<span class="ib-on">${blocks[i]}</span>`
      : `<span class="ib-off">${blocks[i]}</span>`;
  }
  return out;
}
function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}
// 患者端期間累計（純文字摘要，不含趨勢圖 — 趨勢圖屬於醫師端）
function renderPeriodSummary(stats) {
  const sorted = Object.entries(stats.byCategory).sort((a, b) => b[1].count - a[1].count);
  if (sorted.length === 0) {
    return `<p class="sym-empty">${_T('sym.summary.empty')}</p>`;
  }
  return `
    <p class="sym-instruct">${_T('sym.summary.instruct')}</p>
    <ul class="sym-summary-list">
      ${sorted.map(([id, s]) => {
        const c = findSymptomCat(id);
        const avg = (s.intensitySum / s.count).toFixed(1);
        const color = c?.color || 'mint';
        return `
          <li class="sym-summary-row">
            <span class="ssr-name scc-${color}">${c ? _symField(c, 'zh') : id}</span>
            <span class="ssr-count">${_Tf('sym.summary.times', { n: s.count })}</span>
            <span class="ssr-avg">${_Tf('sym.summary.avg', { v: avg })}</span>
          </li>
        `;
      }).join('')}
    </ul>
  `;
}
function _visitSessionRadioGroup(name, current) {
  // 三選一 segmented control：不指定 / 上午診 / 下午診
  const cur = _normalizeSession(current);
  const opts = [
    { v: '',   label: _T('visit.session.pickNone') },
    { v: 'am', label: _T('visit.session.pickAm') },
    { v: 'pm', label: _T('visit.session.pickPm') },
  ];
  return `<div class="visit-modal-session" role="radiogroup" aria-label="${_T('sym.visit.label.session')}">`
    + opts.map(o => {
        const checked = (o.v === cur) ? 'checked' : '';
        const id = name + '-' + (o.v || 'none');
        return `<label class="visit-modal-session-opt">`
          + `<input type="radio" name="${name}" id="${id}" value="${o.v}" ${checked} />`
          + `<span>${o.label}</span>`
          + `</label>`;
      }).join('')
    + `</div>`;
}

function openVisitDatePrompt(opts) {
  opts = opts || {};
  // focus: 'next' 代表只想設下次回診（從首頁 chip 開啟時用），focus: 'last' 反之
  const focus = opts.focus || 'both';
  const v = getVisitDates();
  // 同步讀取「per-user 下次回診」與其診時段，優先採用
  const perUserNext = (typeof loadNextVisit === 'function') ? loadNextVisit() : '';
  const perUserSession = (typeof loadNextVisitSession === 'function') ? loadNextVisitSession() : '';
  const initialNext = perUserNext || v.nextVisit || '';
  const initialNextSession = perUserSession || v.nextVisitSession || '';
  const initialLast = v.lastVisit || '';
  const initialLastSession = v.lastVisitSession || '';

  // 移除舊的（如果有）
  const old = document.getElementById('visit-date-modal');
  if (old) old.remove();

  const overlay = document.createElement('div');
  overlay.id = 'visit-date-modal';
  overlay.className = 'visit-modal-overlay';
  // 把當前 app 主題複製到 overlay，讓 modal 顯示對應的深/淺色
  const appTheme = document.getElementById('app-wrapper')?.dataset.theme || 'light';
  overlay.dataset.theme = appTheme;
  // 注意：日期值用 setAttribute 設定（避免 XSS），不要插值進 innerHTML
  const showLast = (focus !== 'next');
  const showNext = (focus !== 'last');
  overlay.innerHTML = `
    <div class="visit-modal" role="dialog" aria-labelledby="visit-modal-title">
      <header class="visit-modal-head">
        <h3 id="visit-modal-title"><i data-lucide="calendar-cog"></i> ${_T('sym.visit.title')}</h3>
        <button class="visit-modal-close" type="button" aria-label="${_T('sym.visit.close')}">×</button>
      </header>
      <div class="visit-modal-body">
        ${showLast ? `
        <label class="visit-modal-field">
          <span>${_T('sym.visit.label.last')}</span>
          <input type="date" id="vm-last" />
          <button type="button" class="visit-modal-clear" data-clear="vm-last">${_T('sym.visit.btn.clear')}</button>
        </label>
        <div class="visit-modal-subfield">
          <span class="visit-modal-sublabel">${_T('sym.visit.label.session')}</span>
          ${_visitSessionRadioGroup('vm-last-session', initialLastSession)}
        </div>` : ''}
        ${showNext ? `
        <label class="visit-modal-field">
          <span>${_T('sym.visit.label.next')}</span>
          <input type="date" id="vm-next" />
          <button type="button" class="visit-modal-clear" data-clear="vm-next">${_T('sym.visit.btn.clear')}</button>
        </label>
        <div class="visit-modal-subfield">
          <span class="visit-modal-sublabel">${_T('sym.visit.label.session')}</span>
          ${_visitSessionRadioGroup('vm-next-session', initialNextSession)}
        </div>` : ''}
        <p class="visit-modal-hint">${_T('sym.visit.hint')}</p>
      </div>
      <footer class="visit-modal-foot">
        <button type="button" class="visit-modal-cancel">${_T('sym.visit.btn.cancel')}</button>
        <button type="button" class="visit-modal-save"><i data-lucide="check"></i> ${_T('sym.visit.btn.save')}</button>
      </footer>
    </div>
  `;
  document.body.appendChild(overlay);
  // 用 .value 賦值，瀏覽器會驗證日期字串、不會被當 HTML 處理
  if (showLast) overlay.querySelector('#vm-last').value = initialLast;
  if (showNext) overlay.querySelector('#vm-next').value = initialNext;
  if (typeof lucide !== 'undefined') lucide.createIcons();

  const close = () => overlay.remove();
  overlay.querySelector('.visit-modal-close').onclick = close;
  overlay.querySelector('.visit-modal-cancel').onclick = close;
  overlay.addEventListener('click', (e) => { if (e.target === overlay) close(); });
  overlay.querySelectorAll('.visit-modal-clear').forEach(btn => {
    btn.onclick = () => {
      document.getElementById(btn.dataset.clear).value = '';
      // 清掉日期時，同步把該欄位的診時段重置為「不指定」
      const sessName = btn.dataset.clear + '-session';
      const noneRadio = overlay.querySelector('input[name="' + sessName + '"][value=""]');
      if (noneRadio) noneRadio.checked = true;
    };
  });
  function readSession(name) {
    const r = overlay.querySelector('input[name="' + name + '"]:checked');
    return r ? _normalizeSession(r.value) : '';
  }
  overlay.querySelector('.visit-modal-save').onclick = () => {
    const prev = getVisitDates();
    const lastVisit = showLast ? (document.getElementById('vm-last').value || null) : (prev.lastVisit || null);
    const nextVisit = showNext ? (document.getElementById('vm-next').value || null) : (prev.nextVisit || null);
    const lastVisitSession = showLast ? readSession('vm-last-session') : (prev.lastVisitSession || '');
    const nextVisitSession = showNext ? readSession('vm-next-session') : (prev.nextVisitSession || '');
    // 沒設日期就把對應的 session 清掉，避免「日期空但有時段」的怪資料
    saveVisitDates({
      lastVisit,
      nextVisit,
      lastVisitSession: lastVisit ? lastVisitSession : '',
      nextVisitSession: nextVisit ? nextVisitSession : '',
    });
    // 同步 per-user 下次回診（首頁 chip 用）
    if (showNext) {
      saveNextVisit(nextVisit || '');
      saveNextVisitSession(nextVisit ? nextVisitSession : '');
    }
    close();
    if (typeof refreshNextVisitChip === 'function') refreshNextVisitChip();
    // 留在原頁，重新渲染當前頁以反映新日期
    const currentPage = document.getElementById('app')?.getAttribute('data-page') || 'symptoms';
    const slugToPage = { 'your-pieces': 'pieces', 'symptoms': 'symptoms', 'previsit': 'previsit', 'home': 'home' };
    if (typeof showPage === 'function') showPage(slugToPage[currentPage] || currentPage);
  };
}

// ═══════════════════════════════════════════════════════════
// 生理紀錄（VITALS）— 9 預設 + 自訂、BP 雙欄、BMI 自動算、歷史
// ═══════════════════════════════════════════════════════════

const VITAL_METRICS = [
  { id:'weight',  zh:'體重', icon:'weight',      unit:'kg',    range:[10,300], step:0.1, color:'mint' },
  { id:'height',  zh:'身高', icon:'ruler',       unit:'cm',    range:[50,250], step:0.5, color:'aqua' },
  { id:'bmi',     zh:'BMI',  icon:'gauge',       unit:'',      calc:true,                color:'pink' },
  { id:'bp',      zh:'血壓', icon:'heart-pulse', unit:'mmHg',  dual:true,                color:'pink' },
  { id:'glucose', zh:'血糖', icon:'droplet',     unit:'mg/dL', range:[40,500], step:1,   color:'blue' },
  { id:'heart',   zh:'心率', icon:'activity',    unit:'bpm',   range:[30,220], step:1,   color:'pink' },
  { id:'temp',    zh:'體溫', icon:'thermometer', unit:'°C',    range:[33,42],  step:0.1, color:'pink' },
  { id:'spo2',    zh:'血氧', icon:'wind',        unit:'%',     range:[70,100], step:1,   color:'aqua' },
  { id:'waist',   zh:'腰圍', icon:'circle',      unit:'cm',    range:[40,200], step:0.5, color:'mint' },
];

const DEFAULT_TRACKED = ['weight','bp','heart','glucose'];

const VITAL_CONTEXT_OPTIONS = [
  '飯前','飯後','起床後','睡前','運動前','運動後','服藥前','服藥後','其他'
];
const VITAL_METHOD_OPTIONS = [
  '居家自測','醫院測量','藥局測量','家人代測','裝置同步','其他'
];

function getTrackedMetricIds() {
  try {
    const raw = localStorage.getItem('mdpiece_vitals_tracked');
    if (raw === null) return DEFAULT_TRACKED.slice();
    return JSON.parse(raw);
  } catch { return DEFAULT_TRACKED.slice(); }
}
function setTrackedMetricIds(ids) {
  localStorage.setItem('mdpiece_vitals_tracked', JSON.stringify(ids));
}
function getCustomMetrics() {
  try { return JSON.parse(localStorage.getItem('mdpiece_vitals_custom') || '[]'); }
  catch { return []; }
}
function saveCustomMetric(m) {
  const arr = getCustomMetrics();
  arr.push(m);
  localStorage.setItem('mdpiece_vitals_custom', JSON.stringify(arr));
}
function deleteCustomMetric(id) {
  localStorage.setItem('mdpiece_vitals_custom',
    JSON.stringify(getCustomMetrics().filter(m => m.id !== id)));
  // also remove from tracked
  setTrackedMetricIds(getTrackedMetricIds().filter(x => x !== id));
}
function getAllMetrics() {
  return VITAL_METRICS.concat(getCustomMetrics().map(m => ({ ...m, custom: true, color: m.color || 'blue' })));
}
function findMetric(id) {
  return getAllMetrics().find(m => m.id === id);
}

function getVitalEntries() {
  try { return JSON.parse(localStorage.getItem('mdpiece_vitals_entries') || '[]'); }
  catch { return []; }
}
function saveVitalEntry(e) {
  const arr = getVitalEntries();
  arr.push(e);
  localStorage.setItem('mdpiece_vitals_entries', JSON.stringify(arr));
}
function deleteVitalEntry(id) {
  localStorage.setItem('mdpiece_vitals_entries',
    JSON.stringify(getVitalEntries().filter(e => e.id !== id)));
}
function getLatestEntry(metricId) {
  const arr = getVitalEntries().filter(e => e.metricId === metricId);
  if (arr.length === 0) return null;
  arr.sort((a, b) => new Date(b.recordedAt) - new Date(a.recordedAt));
  return arr[0];
}
/** 用實際紀錄畫迷你折線圖。
 *  - 取該指標最近 N 天的紀錄，依時間升冪排序
 *  - 雙欄（血壓）用 systolic = value
 *  - <2 筆：只畫一個點（或空字串）
 *  - 全部相同值：平直線
 *  回傳 SVG 字串；無資料回傳 ''。
 */
function buildVitalSparklineSvg(metricId, color, days) {
  var since = Date.now() - (days || 7) * 86400000;
  var entries = getVitalEntries()
    .filter(function(e) { return e.metricId === metricId && new Date(e.recordedAt).getTime() >= since; })
    .map(function(e) {
      return { t: new Date(e.recordedAt).getTime(), v: parseFloat(e.value) };
    })
    .filter(function(e) { return !isNaN(e.v); })
    .sort(function(a, b) { return a.t - b.t; });
  if (entries.length === 0) return '';

  var W = 100, H = 24, padY = 4;
  var minT = entries[0].t;
  var maxT = entries[entries.length - 1].t;
  var spanT = maxT - minT || 1;
  var vals = entries.map(function(e) { return e.v; });
  var minV = Math.min.apply(null, vals);
  var maxV = Math.max.apply(null, vals);
  var spanV = (maxV - minV) || 1;
  function xOf(t) { return entries.length === 1 ? W / 2 : (t - minT) / spanT * W; }
  function yOf(v) { return H - padY - (v - minV) / spanV * (H - padY * 2); }

  if (entries.length === 1) {
    return '<svg viewBox="0 0 ' + W + ' ' + H + '" preserveAspectRatio="none" style="width:100%;height:24px;margin-top:6px">'
      + '<circle cx="' + (W / 2) + '" cy="' + (H / 2) + '" r="2.8" fill="' + color + '"/>'
      + '</svg>';
  }
  var linePts = entries.map(function(e) { return xOf(e.t).toFixed(1) + ',' + yOf(e.v).toFixed(1); }).join(' ');
  var areaPts = '0,' + H + ' ' + linePts + ' ' + W + ',' + H;
  var lastX = xOf(entries[entries.length - 1].t).toFixed(1);
  var lastY = yOf(entries[entries.length - 1].v).toFixed(1);
  return '<svg viewBox="0 0 ' + W + ' ' + H + '" preserveAspectRatio="none" style="width:100%;height:24px;margin-top:6px">'
    + '<polygon fill="' + color + '" fill-opacity="0.16" points="' + areaPts + '"/>'
    + '<polyline fill="none" stroke="' + color + '" stroke-width="2.2" stroke-linejoin="round" stroke-linecap="round" points="' + linePts + '"/>'
    + '<circle cx="' + lastX + '" cy="' + lastY + '" r="2.4" fill="' + color + '"/>'
    + '</svg>';
}

/** 取某指標最近 N 天紀錄並回傳排序後的 {t, v, raw} 陣列。 */
function _vitalEntriesForChart(metricId, days) {
  var since = Date.now() - (days || 30) * 86400000;
  return getVitalEntries()
    .filter(function(e) { return e.metricId === metricId && new Date(e.recordedAt).getTime() >= since; })
    .map(function(e) { return { t: new Date(e.recordedAt).getTime(), v: parseFloat(e.value), raw: e }; })
    .filter(function(e) { return !isNaN(e.v); })
    .sort(function(a, b) { return a.t - b.t; });
}

/** 開啟單一指標的詳細折線圖 sheet（手機點 vital-card 後展開）。 */
function openVitalChartSheet(metricId) {
  var m = findMetric(metricId);
  if (!m) return;
  var entries = _vitalEntriesForChart(metricId, 30);
  var color = '#4A90C2';

  // 畫大圖（含 Y 軸標籤）
  var W = 320, H = 160, padL = 32, padR = 12, padT = 12, padB = 22;
  var plotW = W - padL - padR, plotH = H - padT - padB;
  var svgBody = '';
  if (entries.length === 0) {
    svgBody = '<text x="' + (W/2) + '" y="' + (H/2) + '" text-anchor="middle" fill="#999" font-size="12">尚無紀錄</text>';
  } else {
    var minT = entries[0].t, maxT = entries[entries.length - 1].t, spanT = (maxT - minT) || 1;
    var vals = entries.map(function(e) { return e.v; });
    var minV = Math.min.apply(null, vals);
    var maxV = Math.max.apply(null, vals);
    if (minV === maxV) { minV -= 1; maxV += 1; }
    var spanV = maxV - minV;
    var xOf = function(t) { return entries.length === 1 ? (padL + plotW / 2) : (padL + (t - minT) / spanT * plotW); };
    var yOf = function(v) { return padT + plotH - (v - minV) / spanV * plotH; };

    // Y 軸 grid + 標籤（4 條線）
    var grid = '';
    for (var i = 0; i <= 3; i++) {
      var yv = minV + (maxV - minV) * (i / 3);
      var yPx = yOf(yv);
      grid += '<line x1="' + padL + '" y1="' + yPx + '" x2="' + (W - padR) + '" y2="' + yPx + '" stroke="#e5e7eb" stroke-width="1"/>';
      grid += '<text x="' + (padL - 4) + '" y="' + (yPx + 3) + '" text-anchor="end" fill="#6b7280" font-size="9">' + (Number.isInteger(yv) ? yv : yv.toFixed(1)) + '</text>';
    }
    // X 軸日期標籤（首末）
    var d1 = new Date(minT), d2 = new Date(maxT);
    var fmt = function(d) { return (d.getMonth()+1) + '/' + d.getDate(); };
    var xLabels = '<text x="' + padL + '" y="' + (H - 6) + '" text-anchor="start" fill="#6b7280" font-size="9">' + fmt(d1) + '</text>'
      + '<text x="' + (W - padR) + '" y="' + (H - 6) + '" text-anchor="end" fill="#6b7280" font-size="9">' + fmt(d2) + '</text>';

    if (entries.length === 1) {
      svgBody = grid + xLabels
        + '<circle cx="' + xOf(entries[0].t) + '" cy="' + yOf(entries[0].v) + '" r="5" fill="' + color + '"/>'
        + '<text x="' + xOf(entries[0].t) + '" y="' + (yOf(entries[0].v) - 8) + '" text-anchor="middle" fill="#374151" font-size="10" font-weight="600">' + entries[0].v + '</text>';
    } else {
      var linePts = entries.map(function(e) { return xOf(e.t).toFixed(1) + ',' + yOf(e.v).toFixed(1); }).join(' ');
      var areaPts = (padL) + ',' + (padT + plotH) + ' ' + linePts + ' ' + (W - padR) + ',' + (padT + plotH);
      var dots = entries.map(function(e) {
        return '<circle cx="' + xOf(e.t).toFixed(1) + '" cy="' + yOf(e.v).toFixed(1) + '" r="3" fill="' + color + '"/>';
      }).join('');
      svgBody = grid + xLabels
        + '<polygon fill="' + color + '" fill-opacity="0.16" points="' + areaPts + '"/>'
        + '<polyline fill="none" stroke="' + color + '" stroke-width="2.2" stroke-linejoin="round" stroke-linecap="round" points="' + linePts + '"/>'
        + dots;
    }
  }

  // 資料點清單
  var rowsHtml = entries.length === 0
    ? '<div style="padding:14px;text-align:center;color:#9ca3af;font-size:12px">尚無紀錄</div>'
    : entries.slice().reverse().map(function(e) {
        var d = new Date(e.t);
        var dateStr = (d.getMonth()+1) + '/' + d.getDate() + ' ' + String(d.getHours()).padStart(2,'0') + ':' + String(d.getMinutes()).padStart(2,'0');
        var bits = [];
        if (e.raw.context) bits.push('情境：' + escapeHtml(e.raw.context));
        if (e.raw.method)  bits.push('方式：' + escapeHtml(e.raw.method));
        if (e.raw.notes)   bits.push(escapeHtml(e.raw.notes));
        var meta = bits.length ? '<div style="font-size:11px;color:#6b7280;margin-top:2px">' + bits.join(' · ') + '</div>' : '';
        var valStr = (e.raw.value2 != null) ? (e.raw.value + '/' + e.raw.value2) : String(e.raw.value);
        return '<div style="padding:10px 12px;border-bottom:1px solid #f1f5f9;display:flex;justify-content:space-between;align-items:flex-start;gap:10px">'
          + '<div style="min-width:0">'
          +   '<div style="font-size:12px;color:#6b7280;font-family:var(--font-mono,monospace)">' + dateStr + '</div>'
          +   meta
          + '</div>'
          + '<div style="font-size:14px;font-weight:600;color:#111;white-space:nowrap"><strong>' + valStr + '</strong> <span style="font-size:11px;color:#6b7280;font-weight:400">' + escapeHtml(m.unit || '') + '</span></div>'
          + '</div>';
      }).join('');

  var overlay = document.createElement('div');
  overlay.id = 'vt-chart-sheet';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.45);z-index:9999;display:flex;align-items:flex-end;justify-content:center';
  overlay.innerHTML = ''
    + '<div role="dialog" aria-label="' + escapeHtml(m.zh) + '折線圖" style="background:#fff;border-radius:14px 14px 0 0;width:100%;max-width:560px;max-height:90vh;display:flex;flex-direction:column">'
    +   '<div style="display:flex;align-items:center;justify-content:space-between;padding:14px 16px;border-bottom:1px solid #f1f5f9">'
    +     '<div style="font-size:15px;font-weight:600;color:#111">' + escapeHtml(m.zh) + ' 折線圖 <span style="font-weight:400;color:#6b7280;font-size:12px">(最近 30 天 · ' + entries.length + ' 筆)</span></div>'
    +     '<button type="button" onclick="closeVitalChartSheet()" aria-label="關閉" style="background:transparent;border:none;font-size:20px;cursor:pointer;color:#6b7280;padding:4px 8px">×</button>'
    +   '</div>'
    +   '<div style="padding:16px;background:#fafafa">'
    +     '<svg viewBox="0 0 ' + W + ' ' + H + '" style="width:100%;height:auto;display:block;background:#fff;border-radius:8px;border:1px solid #f1f5f9">' + svgBody + '</svg>'
    +   '</div>'
    +   '<div style="overflow:auto;flex:1">' + rowsHtml + '</div>'
    + '</div>';
  overlay.addEventListener('click', function(e) { if (e.target === overlay) closeVitalChartSheet(); });
  document.body.appendChild(overlay);
}

function closeVitalChartSheet() {
  var el = document.getElementById('vt-chart-sheet');
  if (el) el.remove();
}

function calculateBMI() {
  const w = getLatestEntry('weight'), h = getLatestEntry('height');
  if (!w || !h) return null;
  const wKg = parseFloat(w.value);
  const hM = parseFloat(h.value) / 100;
  if (!wKg || !hM) return null;
  return (wKg / (hM * hM)).toFixed(1);
}

function vitals() {
  // 首次進入時非同步抓使用中的量測提醒計畫（refresh 自動觸發再次渲染）。
  // 用 flag 避免迴圈：loadMeasurementPlans(true) → showPage('vitals') → 再進 vitals()。
  if (!window.__vtPlansLoaded) {
    window.__vtPlansLoaded = true;
    setTimeout(() => loadMeasurementPlans(true), 0);
  }
  const tracked = getTrackedMetricIds();
  const allMetrics = getAllMetrics();
  const trackedMetrics = tracked.map(id => allMetrics.find(m => m.id === id)).filter(Boolean);
  const totalEntries = getVitalEntries().length;
  const allEntries = getVitalEntries();
  const latestAcross = allEntries.sort((a,b) => new Date(b.recordedAt) - new Date(a.recordedAt))[0];
  const lastUpdate = latestAcross ? new Date(latestAcross.recordedAt) : null;
  const lastUpdateStr = lastUpdate ? `${(lastUpdate.getMonth()+1)}/${lastUpdate.getDate()} ${lastUpdate.toTimeString().slice(0,5)}` : '—';
  // 今日進度：追蹤項目中今日已記錄的 distinct metric 數
  const todayKey = _localDay();
  const todayMetricIds = new Set(allEntries.filter(e => _localDay(e.recordedAt) === todayKey).map(e => e.metricId));
  const todayCovered = tracked.filter(id => todayMetricIds.has(id)).length;
  const totalToday = tracked.length || 0;
  const pctToday = totalToday ? Math.min(100, Math.round((todayCovered / totalToday) * 100)) : 0;
  const todayStatus = totalToday === 0
    ? '先到下方勾選你要追蹤的指標'
    : (todayCovered === totalToday ? '今日追蹤全部完成 ✨' : `${todayCovered} / ${totalToday} 項已記錄 · 還剩 ${totalToday - todayCovered}`);

  // ─── 手機 v11 demo 版面 — 本週數值 + 最近紀錄 ────────────── //
  // 顯示「全部」追蹤指標卡，每張可點 → openVitalChartSheet 看單一指標折線。
  var _vitalTintCycle = ['t-rose', 't-blue', 't-mint', 't-amber'];
  var _vitalColorCycle = ['#C97A7A', '#4A90C2', '#5BA88C', '#D89B5C'];
  var _mobileVitalsCards = trackedMetrics.map(function(m, idx) {
    var latest = getLatestEntry(m.id);
    var tint = _vitalTintCycle[idx % _vitalTintCycle.length];
    var color = _vitalColorCycle[idx % _vitalColorCycle.length];
    var val = latest ? (latest.value != null ? (latest.value2 != null ? (latest.value + '/' + latest.value2) : latest.value) : '—') : '—';
    var unit = m.unit || '';
    var lastTime = latest ? ((new Date(latest.recordedAt)).getMonth()+1) + '/' + (new Date(latest.recordedAt)).getDate() : '';
    return ''
      + '<button type="button" class="vital-card ' + tint + '" onclick="openVitalChartSheet(\'' + m.id + '\')" style="text-align:left;border:1px solid var(--border-glass,rgba(0,0,0,0.06));background:inherit;cursor:pointer;padding:12px;font:inherit;color:inherit;width:100%">'
      +   '<div class="puzzle-motif"><svg><use href="#puzzle-piece"/></svg></div>'
      +   '<div class="vital-card-head"><i data-lucide="activity"></i><span class="lbl">' + escapeHtml(m.zh || m.id) + '</span><i data-lucide="chevron-right" style="margin-left:auto;width:14px;height:14px;opacity:0.4"></i></div>'
      +   '<div class="vital-card-val">' + escapeHtml(String(val)) + '<span class="vital-card-unit">' + escapeHtml(unit) + '</span></div>'
      +   '<div class="vital-card-meta">' + (lastTime ? '最後紀錄 ' + lastTime + ' · 點查看折線圖' : '尚無紀錄 · 點查看折線圖') + '</div>'
      +   (latest ? buildVitalSparklineSvg(m.id, color, 7) : '')
      + '</button>';
  }).join('');
  if (!_mobileVitalsCards) {
    _mobileVitalsCards = '<div class="vital-card" style="grid-column:1/-1;padding:16px;text-align:center;color:var(--text-muted);font-size:11px">尚未選擇追蹤項目 — 到下方勾選</div>';
  }

  // 最近紀錄（前 4 筆）
  var _mobileRecentRows = allEntries.slice(0, 4).map(function(e) {
    var m = findMetric(e.metricId);
    var val = e.value != null ? e.value : (e.systolic ? (e.systolic + '/' + e.diastolic) : '—');
    var d = new Date(e.recordedAt);
    var hhmm = String(d.getHours()).padStart(2,'0') + ':' + String(d.getMinutes()).padStart(2,'0');
    return ''
      + '<div class="list-row">'
      +   '<span></span>'
      +   '<span class="time">' + hhmm + '</span>'
      +   '<div class="name">' + escapeHtml((m && m.label) || e.metricId) + ' <span style="color:var(--text-dim);font-weight:400;font-family:var(--font-mono);font-size:11px;margin-left:6px">' + escapeHtml(String(val)) + ((m && m.unit) ? (' ' + m.unit) : '') + '</span></div>'
      +   '<span><span class="pill pill-mute mono">' + ((d.getMonth()+1) + '/' + d.getDate()) + '</span></span>'
      + '</div>';
  }).join('');
  if (!_mobileRecentRows) {
    _mobileRecentRows = '<div class="list-row" style="grid-template-columns:1fr;color:var(--text-muted);font-size:11px;padding:14px 12px;text-align:center">尚無紀錄</div>';
  }

  // ── 手機版「記一筆」模組：指標/情境/方式都用方塊 chip 點選，數值由患者自填 ─
  // 初次進來預設選第一個非 BMI 的追蹤指標
  if (!window.__vtMobileSel || !window.__vtMobileSel.metricId) {
    var _defaultMetric = trackedMetrics.filter(function(mm) { return mm.id !== 'bmi'; })[0]
      || allMetrics.filter(function(mm) { return mm.id !== 'bmi'; })[0];
    window.__vtMobileSel = { metricId: _defaultMetric ? _defaultMetric.id : '', context: '', method: '' };
  }
  var _mobileLogForm = ''
    + '<div class="vt-mobile-form" style="background:var(--surface,#fff);border:1px solid var(--border-glass,rgba(0,0,0,0.08));border-radius:14px;padding:14px;margin-bottom:14px;display:flex;flex-direction:column;gap:12px">'
    +   '<div style="font-size:12px;color:var(--text-muted);font-weight:600">指標</div>'
    +   '<div id="vt-m-metric-chips" class="vt-chip-grid" style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px"></div>'
    +   '<div id="vt-m-single-wrap">'
    +     '<div style="font-size:12px;color:var(--text-muted);font-weight:600;margin-bottom:6px">數值 <span id="vt-m-unit-lbl" style="color:var(--text-dim);font-weight:400"></span></div>'
    +     '<input type="number" id="vt-m-val1" inputmode="decimal" step="any" placeholder="自行輸入數值" style="width:100%;padding:12px;border:1px solid var(--border-glass);border-radius:10px;font-size:16px" />'
    +   '</div>'
    +   '<div id="vt-m-dual-wrap" style="display:none">'
    +     '<div style="font-size:12px;color:var(--text-muted);font-weight:600;margin-bottom:6px">收縮壓 / 舒張壓 (mmHg)</div>'
    +     '<div style="display:flex;gap:8px;align-items:center">'
    +       '<input type="number" id="vt-m-val1d" inputmode="numeric" placeholder="例 120" min="40" max="260" style="flex:1;padding:12px;border:1px solid var(--border-glass);border-radius:10px;font-size:16px" />'
    +       '<span style="color:var(--text-muted);font-size:18px">/</span>'
    +       '<input type="number" id="vt-m-val2d" inputmode="numeric" placeholder="例 80" min="30" max="160" style="flex:1;padding:12px;border:1px solid var(--border-glass);border-radius:10px;font-size:16px" />'
    +     '</div>'
    +   '</div>'
    +   '<div style="font-size:12px;color:var(--text-muted);font-weight:600">紀錄情境（選填）</div>'
    +   '<div id="vt-m-context-chips" class="vt-chip-row" style="display:flex;flex-wrap:wrap;gap:6px"></div>'
    +   '<div style="font-size:12px;color:var(--text-muted);font-weight:600">記錄方式（選填）</div>'
    +   '<div id="vt-m-method-chips" class="vt-chip-row" style="display:flex;flex-wrap:wrap;gap:6px"></div>'
    +   '<div style="font-size:12px;color:var(--text-muted);font-weight:600">備註（選填）</div>'
    +   '<textarea id="vt-m-notes" rows="2" placeholder="例如：左手量、休息 5 分鐘後..." style="width:100%;padding:10px;border:1px solid var(--border-glass);border-radius:10px;font-size:14px;font-family:inherit;resize:vertical"></textarea>'
    +   '<button type="button" onclick="submitMobileVitalEntry()" style="padding:14px;background:#4A90C2;color:#fff;border:none;border-radius:10px;font-size:15px;font-weight:600;cursor:pointer">新增紀錄</button>'
    + '</div>';

  var _mobileVitalsBlock = ''
    + '<div class="mobile-only">'
    +   '<div class="sec-head">'
    +     '<h3 class="sec-title"><i data-lucide="plus-circle"></i> 記一筆</h3>'
    +     '<span class="sec-spacer"></span>'
    +   '</div>'
    +   _mobileLogForm
    +   '<div class="sec-head">'
    +     '<h3 class="sec-title"><i data-lucide="activity"></i> 本週數值</h3>'
    +     '<span class="sec-spacer"></span>'
    +     '<span class="sec-count">7 天</span>'
    +   '</div>'
    +   '<div class="vital-snap">' + _mobileVitalsCards + '</div>'

    +   '<div class="sec-head">'
    +     '<h3 class="sec-title"><i data-lucide="list"></i> 最近紀錄</h3>'
    +     '<span class="sec-spacer"></span>'
    +     '<span class="sec-count">' + totalEntries + ' 筆</span>'
    +   '</div>'
    +   '<div class="list-card">' + _mobileRecentRows + '</div>'

    // 圖表說明（demo 的 kpi-mini-explain — 在圖底下加 1 行說明）
    +   '<div class="med-tip-card" style="margin-top:12px">'
    +     '<i data-lucide="trending-up"></i>'
    +     '<span><strong>怎麼看圖</strong>：線往上代表數值升高。請與醫師討論個人目標值。</span>'
    +   '</div>'

    // 免責 footer
    +   '<div class="disclaimer-footer">'
    +     '<i data-lucide="info"></i>'
    +     '<span><strong>本 App 僅供記錄與參考</strong>，不取代醫師診斷與處方。緊急狀況請<span class="emergency">立即就醫或撥 119</span>。</span>'
    +   '</div>'
    + '</div>';

  return `
    ${_mobileVitalsBlock}
    <div class="sym-page desktop-only">

      <div class="page-app-hero page-app-hero-blue">
        <div class="page-app-hero-head">
          <span class="page-app-hero-eyebrow">TODAY · 今日生理紀錄</span>
          <span class="page-app-hero-warn"><i data-lucide="info" style="width:11px;height:11px"></i> 異常數值請就醫確認</span>
        </div>
        <div class="page-app-hero-title">${todayStatus}</div>
        <div class="page-app-hero-bar"><div class="page-app-hero-bar-fill" style="width:${pctToday}%"></div></div>
      </div>

      <div id="vt-doctor-request-banner" style="margin:8px 0"></div>
      <div style="margin:8px 0;display:flex;justify-content:flex-end">
        <button class="secondary" onclick="loadDoctorMeasurementRequests(true)" style="padding:6px 12px;font-size:0.85rem">
          <i data-lucide="stethoscope" style="width:14px;height:14px;vertical-align:middle"></i>
          看醫師是否要我量
        </button>
      </div>

      <section class="term-section">
        <header class="ts-head">
          <span class="ts-prompt">本期概況</span>
          <span class="ts-tag">生理紀錄總覽</span>
        </header>
        <div class="ts-body">
          <div class="ts-stat-grid">
            <div class="ts-stat">
              <span class="ts-stat-label">追蹤中</span>
              <span class="ts-stat-num">${trackedMetrics.length}</span>
              <span class="ts-stat-unit">項指標</span>
            </div>
            <div class="ts-stat">
              <span class="ts-stat-label">總紀錄</span>
              <span class="ts-stat-num">${totalEntries}</span>
              <span class="ts-stat-unit">筆</span>
            </div>
            <div class="ts-stat">
              <span class="ts-stat-label">自訂指標</span>
              <span class="ts-stat-num">${getCustomMetrics().length}</span>
              <span class="ts-stat-unit">項</span>
            </div>
            <div class="ts-stat">
              <span class="ts-stat-label">上次更新</span>
              <span class="ts-stat-num sm">${lastUpdateStr}</span>
              <span class="ts-stat-unit">${lastUpdate ? '已記錄' : '尚無紀錄'}</span>
            </div>
          </div>
        </div>
      </section>

      <section class="term-section">
        <header class="ts-head">
          <span class="ts-prompt">選要追蹤的項目</span>
          <span class="ts-tag">${tracked.length} selected</span>
        </header>
        <div class="ts-body">
          <p class="sym-instruct">勾選你要追蹤的指標（可隨時調整）：</p>
          <div class="vt-toggle-grid">
            ${allMetrics.map(m => {
              const on = tracked.includes(m.id);
              return `
                <button class="vt-toggle ${on ? 'on' : ''}" onclick="toggleVitalTracked('${m.id}')" type="button">
                  <span class="vt-toggle-icon scc-${m.color}"><i data-lucide="${m.icon}"></i></span>
                  <span class="vt-toggle-name">${m.zh}${m.unit ? ` <small>${m.unit}</small>` : ''}</span>
                  <span class="vt-toggle-check">${on ? '✓' : ''}</span>
                  ${m.custom ? `<button type="button" class="vt-cm-del" onclick="deleteCustomMetricAndRefresh(event,'${m.id}')" title="刪除自訂指標" aria-label="刪除自訂指標「${escapeHtml(m.zh || m.id)}」">×</button>` : ''}
                </button>
              `;
            }).join('')}
          </div>
          <div class="vt-add-custom">
            <span class="vt-add-prompt">$ add-metric</span>
            <input id="vt-custom-name" placeholder="名稱（例：尿酸、步數、視力）" maxlength="20" />
            <select id="vt-custom-unit" class="vt-unit-select">
              <option value="">— 無單位 —</option>
              <optgroup label="醫療數值">
                <option value="mg/dL">mg/dL（血糖、膽固醇）</option>
                <option value="mmol/L">mmol/L（血糖）</option>
                <option value="mmHg">mmHg（血壓）</option>
                <option value="bpm">bpm（每分鐘心跳）</option>
                <option value="IU">IU（國際單位）</option>
              </optgroup>
              <optgroup label="百分比">
                <option value="%">%（百分比、血氧）</option>
              </optgroup>
              <optgroup label="重量">
                <option value="kg">kg（公斤）</option>
                <option value="g">g（公克）</option>
                <option value="lb">lb（磅）</option>
              </optgroup>
              <optgroup label="長度">
                <option value="cm">cm（公分）</option>
                <option value="mm">mm（毫米）</option>
                <option value="m">m（公尺）</option>
              </optgroup>
              <optgroup label="體積／容量">
                <option value="ml">ml（毫升）</option>
                <option value="cc">cc（立方公分）</option>
                <option value="L">L（公升）</option>
                <option value="杯">杯</option>
                <option value="瓶">瓶</option>
              </optgroup>
              <optgroup label="溫度">
                <option value="°C">°C（攝氏）</option>
                <option value="°F">°F（華氏）</option>
              </optgroup>
              <optgroup label="次數／數量">
                <option value="次">次</option>
                <option value="步">步</option>
                <option value="顆">顆</option>
                <option value="片">片</option>
                <option value="包">包</option>
              </optgroup>
              <optgroup label="時間">
                <option value="分鐘">分鐘</option>
                <option value="小時">小時</option>
                <option value="天">天</option>
              </optgroup>
              <optgroup label="能量">
                <option value="kcal">kcal（大卡）</option>
              </optgroup>
              <optgroup label="評級">
                <option value="級">級</option>
                <option value="分">分（評分）</option>
                <option value="星">星</option>
              </optgroup>
            </select>
            <button class="primary-btn vt-small-btn" onclick="addCustomMetricUI()" type="button">
              <i data-lucide="plus"></i><span>新增</span>
            </button>
          </div>
        </div>
      </section>

      <section class="term-section" id="vt-logform" style="display:none">
        <header class="ts-head">
          <span class="ts-prompt">加一筆紀錄</span>
          <span class="ts-tag" id="vt-logform-tag">—</span>
        </header>
        <div class="ts-body" id="vt-logform-body"></div>
      </section>

      <section class="term-section">
        <header class="ts-head">
          <span class="ts-prompt">最近一次紀錄</span>
          <span class="ts-tag">各項最新值</span>
        </header>
        <div class="ts-body">
          ${trackedMetrics.length === 0 ? `
            <p class="sym-empty">// 還沒有追蹤任何指標 — 上面勾選一個開始。</p>
          ` : `
            <div class="vt-snapshot-grid">
              ${trackedMetrics.map(m => renderVitalSnapshotCard(m)).join('')}
            </div>
          `}
        </div>
      </section>

      <section class="term-section">
        <header class="ts-head">
          <span class="ts-prompt">近 30 筆紀錄</span>
          <span class="ts-tag">歷史</span>
        </header>
        <div class="ts-body">
          ${renderVitalHistory()}
        </div>
      </section>

    </div>
  `;
}

// ─── 醫師「要件測」面板（vitals 頁頂部 banner） ───────────────
//
// 病患按「看醫師是否要我量」→ 抓 pending 的 measurement_requests，
// 渲染卡片 + 「我量好了」回填鈕。

const MEASURE_TYPE_LABELS = {
  bp: '血壓', glucose: '血糖', heart_rate: '心率',
  weight: '體重', temperature: '體溫',
};

function loadDoctorMeasurementRequests(announce) {
  const banner = document.getElementById('vt-doctor-request-banner');
  if (!banner) return;
  const pid = getStablePatientId();
  apiFetch(`${API}/reminders/measurement-requests?patient_id=${encodeURIComponent(pid)}&status=pending&limit=10`)
    .then(r => r.ok ? r.json() : { items: [] })
    .then(data => renderDoctorMeasurementRequests(data.items || [], !!announce))
    .catch(() => {
      if (announce) banner.innerHTML = '<div style="padding:10px;border:1px dashed var(--border-glass);border-radius:8px;color:var(--text-muted)">無法連線醫師端，請稍後再試。</div>';
    });
}

function renderDoctorMeasurementRequests(items, announce) {
  const banner = document.getElementById('vt-doctor-request-banner');
  if (!banner) return;
  if (!items.length) {
    banner.innerHTML = announce
      ? '<div style="padding:10px;border:1px dashed var(--border-glass);border-radius:8px;color:var(--text-muted);font-size:0.85rem">目前醫師沒有量測請求 ✅</div>'
      : '';
    return;
  }
  const cards = items.map(req => {
    const label = MEASURE_TYPE_LABELS[req.measure_type] || req.measure_type;
    const note = req.note ? `<div style="font-size:0.85rem;color:var(--text-dim);margin-top:4px">${escapeHtml(req.note)}</div>` : '';
    const when = req.requested_at ? new Date(req.requested_at).toLocaleString() : '';
    return `
      <div style="padding:12px;border:1px solid #ffb3a7;background:rgba(255,179,167,0.12);border-radius:10px;margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start">
          <div>
            <strong>📞 醫師請您量${label}</strong>
            <div style="font-size:0.75rem;color:var(--text-muted);margin-top:2px">${when}</div>
            ${note}
          </div>
        </div>
        <div style="margin-top:10px;display:flex;gap:6px;flex-wrap:wrap;align-items:center">
          <input id="mr-val-${req.id}" placeholder="${label === '血壓' ? '例：145/92' : '數值'}" style="flex:1;min-width:120px;padding:6px;border-radius:6px;border:1px solid var(--border-glass)" />
          <button class="primary" onclick="completeMeasurementRequest('${req.id}')" style="padding:6px 14px">我量好了 ✅</button>
          <button class="secondary" onclick="cancelMeasurementRequest('${req.id}')" style="padding:6px 10px;font-size:0.8rem">忽略</button>
        </div>
      </div>
    `;
  }).join('');
  banner.innerHTML = cards;
}

function completeMeasurementRequest(reqId) {
  const input = document.getElementById(`mr-val-${reqId}`);
  const val = (input && input.value || '').trim();
  apiFetch(`${API}/reminders/measurement-requests/${encodeURIComponent(reqId)}/complete`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ result_value: val || null }),
  }).then(r => r.ok ? r.json() : Promise.reject())
    .then(() => loadDoctorMeasurementRequests())
    .catch(() => alert('回報失敗，請稍後再試。'));
}

function cancelMeasurementRequest(reqId) {
  if (!confirm('忽略這次請求？醫師會在報告看到。')) return;
  apiFetch(`${API}/reminders/measurement-requests/${encodeURIComponent(reqId)}`, { method: 'DELETE' })
    .then(() => loadDoctorMeasurementRequests());
}

// ─── 量測提醒計畫（病患自報「醫師要求 X 頻率量測」） ──────────
//
// 流程：
//   step 1 → 醫師有沒有請您測量 X？  [是] [否（只追蹤不設提醒）]
//   step 2 → 選頻率（一天一次 / 兩次 / 三次 / 每週 / 自訂） + 時間
//   送出 → POST /reminders/measurement-plan，後端展開成多筆 reminders + 一筆 measurement_request

window.__vtPlans = window.__vtPlans || [];

const VT_PLAN_PRESETS = [
  { id: 'once_daily',   label: '一天一次',          slots: 1, defaults: ['08:00'] },
  { id: 'twice_daily',  label: '一天兩次（早晚）',  slots: 2, defaults: ['08:00','20:00'] },
  { id: 'thrice_daily', label: '一天三次（早中晚）',slots: 3, defaults: ['08:00','13:00','20:00'] },
  { id: 'weekly',       label: '每週一次',          slots: 1, defaults: ['08:00'], weekly: true },
  { id: 'custom',       label: '自訂時間',          slots: 0, defaults: [] },
];

function getPlanForMetric(metricId) {
  return (window.__vtPlans || []).find(p => p.measure_type === metricId);
}

function loadMeasurementPlans(refresh) {
  const pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return Promise.resolve([]);
  return apiFetch(`${API}/reminders/measurement-plan?patient_id=${encodeURIComponent(pid)}`)
    .then(r => r.ok ? r.json() : { plans: [] })
    .then(data => {
      window.__vtPlans = data.plans || [];
      if (refresh) showPage('vitals');
      return window.__vtPlans;
    })
    .catch(() => { window.__vtPlans = []; return []; });
}

function openMeasurementPlanDialog(metricId, opts) {
  const m = findMetric(metricId);
  if (!m) return;
  opts = opts || {};
  const existing = getPlanForMetric(metricId);
  const skipStep1 = !!opts.skipStep1 || !!existing;

  // 移除舊的 dialog
  const old = document.getElementById('vt-plan-dialog');
  if (old) old.remove();

  const overlay = document.createElement('div');
  overlay.id = 'vt-plan-dialog';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.45);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';
  overlay.innerHTML = `
    <div role="dialog" aria-modal="true" style="background:var(--bg, #fff);color:var(--text, #111);border-radius:14px;max-width:420px;width:100%;padding:18px;box-shadow:0 12px 40px rgba(0,0,0,0.25);max-height:90vh;overflow:auto">
      <div id="vt-plan-step1" style="display:${skipStep1 ? 'none' : 'block'}">
        <div style="font-size:0.85rem;color:var(--text-muted);margin-bottom:6px">設定量測提醒</div>
        <h3 style="margin:0 0 12px;font-size:1.1rem">醫師有請您定期測量 <strong>${escapeHtml(m.zh)}</strong> 嗎？</h3>
        <p style="font-size:0.85rem;color:var(--text-dim);margin:0 0 16px;line-height:1.5">如果醫師有交代，我們可以幫您設定固定提醒並通知醫師端。</p>
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          <button class="primary" onclick="vtPlanDialogYes()" style="flex:1;min-width:120px;padding:10px">是，請幫我設定 ✅</button>
          <button class="secondary" onclick="vtPlanDialogNo('${metricId}')" style="flex:1;min-width:120px;padding:10px">否，只追蹤就好</button>
        </div>
        <button onclick="vtPlanDialogClose()" style="margin-top:10px;width:100%;padding:6px;background:transparent;border:none;color:var(--text-muted);font-size:0.85rem;cursor:pointer">取消</button>
      </div>

      <div id="vt-plan-step2" style="display:${skipStep1 ? 'block' : 'none'}">
        <div style="font-size:0.85rem;color:var(--text-muted);margin-bottom:6px">${existing ? '修改' : '設定'} ${escapeHtml(m.zh)} 提醒</div>
        <h3 style="margin:0 0 12px;font-size:1.05rem">多久量一次？</h3>
        <div id="vt-plan-presets" style="display:flex;flex-direction:column;gap:8px;margin-bottom:12px">
          ${VT_PLAN_PRESETS.map((p,i) => `
            <label style="display:flex;align-items:center;gap:8px;padding:10px;border:1px solid var(--border-glass);border-radius:8px;cursor:pointer">
              <input type="radio" name="vt-plan-preset" value="${p.id}" ${i === 0 ? 'checked' : ''} onchange="vtPlanPresetChanged('${p.id}')" />
              <span>${p.label}</span>
            </label>
          `).join('')}
        </div>
        <div id="vt-plan-times" style="margin-bottom:10px"></div>
        <div id="vt-plan-weekly" style="display:none;margin-bottom:10px">
          <div style="font-size:0.85rem;margin-bottom:6px">選擇星期：</div>
          <div style="display:flex;gap:4px;flex-wrap:wrap">
            ${['一','二','三','四','五','六','日'].map((d,i) => `
              <label style="display:flex;align-items:center;gap:3px;padding:6px 10px;border:1px solid var(--border-glass);border-radius:6px;cursor:pointer;font-size:0.85rem">
                <input type="checkbox" class="vt-plan-dow" value="${i}" ${i === 0 ? 'checked' : ''} /> ${d}
              </label>
            `).join('')}
          </div>
        </div>
        <div style="display:flex;gap:8px;margin-top:14px">
          <button class="secondary" onclick="vtPlanDialogClose()" style="flex:1;padding:10px">取消</button>
          <button class="primary" onclick="vtPlanDialogSave('${metricId}', ${existing ? 'true' : 'false'})" style="flex:2;padding:10px">確定 ${existing ? '更新' : '建立'}提醒 🔔</button>
        </div>
        ${existing ? `
          <button onclick="vtPlanDialogCancelExisting('${existing.plan_id}')" style="margin-top:10px;width:100%;padding:6px;background:transparent;border:none;color:#c53030;font-size:0.85rem;cursor:pointer">移除現有提醒</button>
        ` : ''}
      </div>
    </div>
  `;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', (e) => { if (e.target === overlay) vtPlanDialogClose(); });

  // 初始化 step2 時間欄
  if (skipStep1) {
    const initial = existing
      ? (VT_PLAN_PRESETS.find(p => p.slots === existing.times.length && (existing.frequency === 'weekly') === !!p.weekly)?.id || 'custom')
      : 'once_daily';
    const radio = overlay.querySelector(`input[name="vt-plan-preset"][value="${initial}"]`);
    if (radio) radio.checked = true;
    vtPlanPresetChanged(initial, existing ? existing.times : null);
    if (existing && existing.days_of_week) {
      overlay.querySelectorAll('.vt-plan-dow').forEach(cb => {
        cb.checked = existing.days_of_week.includes(parseInt(cb.value, 10));
      });
    }
  }
}

function vtPlanDialogClose() {
  const el = document.getElementById('vt-plan-dialog');
  if (el) el.remove();
}

function vtPlanDialogYes() {
  document.getElementById('vt-plan-step1').style.display = 'none';
  document.getElementById('vt-plan-step2').style.display = 'block';
  vtPlanPresetChanged('once_daily');
}

function vtPlanDialogNo(metricId) {
  // 只追蹤，不設提醒
  const cur = getTrackedMetricIds();
  if (!cur.includes(metricId)) setTrackedMetricIds(cur.concat(metricId));
  vtPlanDialogClose();
  showPage('vitals');
}

function vtPlanPresetChanged(presetId, prefillTimes) {
  const preset = VT_PLAN_PRESETS.find(p => p.id === presetId);
  if (!preset) return;
  const wkly = document.getElementById('vt-plan-weekly');
  if (wkly) wkly.style.display = preset.weekly ? 'block' : 'none';
  const timesEl = document.getElementById('vt-plan-times');
  if (!timesEl) return;

  let times = prefillTimes && prefillTimes.length ? prefillTimes.slice() : preset.defaults.slice();
  if (presetId === 'custom' && times.length === 0) times = ['08:00'];

  const renderTimes = () => {
    timesEl.innerHTML = `
      <div style="font-size:0.85rem;margin-bottom:6px">提醒時間：</div>
      <div id="vt-plan-time-list" style="display:flex;flex-direction:column;gap:6px">
        ${times.map((t, idx) => `
          <div style="display:flex;gap:6px;align-items:center">
            <input type="time" class="vt-plan-time" value="${t}" data-idx="${idx}" style="flex:1;padding:6px;border:1px solid var(--border-glass);border-radius:6px" />
            ${presetId === 'custom' && times.length > 1 ? `<button type="button" onclick="vtPlanRemoveTime(${idx})" style="padding:4px 8px;background:transparent;border:1px solid var(--border-glass);border-radius:6px;cursor:pointer">×</button>` : ''}
          </div>
        `).join('')}
      </div>
      ${presetId === 'custom' && times.length < 6 ? `
        <button type="button" onclick="vtPlanAddTime()" style="margin-top:6px;padding:6px 10px;background:transparent;border:1px dashed var(--border-glass);border-radius:6px;cursor:pointer;font-size:0.85rem">+ 加一個時間</button>
      ` : ''}
    `;
  };
  // 暫存目前 preset，供 add/remove 用
  window.__vtPlanCurrent = { presetId, times };
  renderTimes();
}

function vtPlanAddTime() {
  const cur = window.__vtPlanCurrent;
  if (!cur || cur.presetId !== 'custom') return;
  // 抓現有 input 值
  document.querySelectorAll('.vt-plan-time').forEach((el, i) => {
    cur.times[i] = el.value || cur.times[i];
  });
  cur.times.push('12:00');
  vtPlanPresetChanged('custom', cur.times);
}

function vtPlanRemoveTime(idx) {
  const cur = window.__vtPlanCurrent;
  if (!cur || cur.presetId !== 'custom') return;
  document.querySelectorAll('.vt-plan-time').forEach((el, i) => {
    cur.times[i] = el.value || cur.times[i];
  });
  cur.times.splice(idx, 1);
  if (cur.times.length === 0) cur.times = ['08:00'];
  vtPlanPresetChanged('custom', cur.times);
}

function vtPlanDialogSave(metricId, isUpdate) {
  const m = findMetric(metricId);
  if (!m) return;
  const pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) { alert('找不到病患 ID，請重新登入'); return; }

  const presetRadio = document.querySelector('input[name="vt-plan-preset"]:checked');
  const presetId = presetRadio ? presetRadio.value : 'once_daily';
  const preset = VT_PLAN_PRESETS.find(p => p.id === presetId);

  const times = Array.from(document.querySelectorAll('.vt-plan-time'))
    .map(el => el.value).filter(Boolean);
  if (!times.length) { alert('請至少設定一個時間'); return; }

  let days_of_week = null;
  if (preset.weekly) {
    days_of_week = Array.from(document.querySelectorAll('.vt-plan-dow:checked')).map(cb => parseInt(cb.value, 10));
    if (!days_of_week.length) { alert('請至少選一個星期'); return; }
  }

  // 把每個時間換算成「下一次該觸發的 UTC ISO 字串」
  const scheduled_dates = times.map(t => nextOccurrenceUtcIso(t, days_of_week));

  const measure_type = m.id;
  const measure_label = m.zh;

  const body = {
    patient_id: pid,
    measure_type,
    measure_label,
    frequency_preset: presetId,
    times,
    scheduled_dates,
    days_of_week,
    doctor_requested: true,
    note: null,
  };

  // 若是更新：先停用舊計畫
  const existing = getPlanForMetric(metricId);
  const promise = (isUpdate && existing)
    ? apiFetch(`${API}/reminders/measurement-plan/${encodeURIComponent(existing.plan_id)}?patient_id=${encodeURIComponent(pid)}`, { method: 'DELETE' }).catch(() => null)
    : Promise.resolve();

  promise.then(() => apiFetch(`${API}/reminders/measurement-plan`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  })).then(r => r.ok ? r.json() : Promise.reject(r))
    .then(() => {
      // 確保 metric 在追蹤清單
      const cur = getTrackedMetricIds();
      if (!cur.includes(metricId)) setTrackedMetricIds(cur.concat(metricId));
      vtPlanDialogClose();
      loadMeasurementPlans(true);
      if (typeof showToast === 'function') showToast(`已設定 ${m.zh} 提醒 🔔`, 'success');
    })
    .catch(() => alert('建立提醒失敗，請稍後再試。'));
}

function vtPlanDialogCancelExisting(planId) {
  if (!confirm('確定要移除這個提醒嗎？')) return;
  const pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return;
  apiFetch(`${API}/reminders/measurement-plan/${encodeURIComponent(planId)}?patient_id=${encodeURIComponent(pid)}`, { method: 'DELETE' })
    .then(() => {
      vtPlanDialogClose();
      loadMeasurementPlans(true);
      if (typeof showToast === 'function') showToast('已移除提醒', 'success');
    });
}

/** 給定 HH:MM（使用者本地時區），算出最近一次未來觸發時間的 UTC ISO 字串。
 *  weekly 模式還需考慮 days_of_week。 */
function nextOccurrenceUtcIso(hhmm, days_of_week) {
  const [h, m] = hhmm.split(':').map(n => parseInt(n, 10));
  const now = new Date();
  const target = new Date(now);
  target.setHours(h, m, 0, 0);
  if (target <= now) target.setDate(target.getDate() + 1);
  if (days_of_week && days_of_week.length) {
    // JS: getDay() 0=Sun..6=Sat；我們的 days 0=Mon..6=Sun
    const toOurs = (jsDay) => (jsDay + 6) % 7;
    for (let i = 0; i < 8; i++) {
      if (days_of_week.includes(toOurs(target.getDay()))) break;
      target.setDate(target.getDate() + 1);
    }
  }
  return target.toISOString();
}

function renderVitalSnapshotCard(m) {
  const latest = getLatestEntry(m.id);
  let valDisplay, timeStr = '尚無紀錄', isBmi = m.id === 'bmi';
  if (m.id === 'bmi') {
    const bmi = calculateBMI();
    if (bmi) {
      valDisplay = `<span class="vt-val">${bmi}</span>`;
      timeStr = '依最新身高/體重計算';
    } else {
      valDisplay = `<span class="vt-val sm">—</span>`;
      timeStr = '需要身高與體重';
    }
  } else if (latest) {
    if (m.dual) {
      valDisplay = `<span class="vt-val">${latest.value}/${latest.value2}</span><span class="vt-unit">${m.unit}</span>`;
    } else {
      valDisplay = `<span class="vt-val">${latest.value}</span><span class="vt-unit">${m.unit || ''}</span>`;
    }
    const d = new Date(latest.recordedAt);
    const today = new Date(); today.setHours(0,0,0,0);
    const dDay = new Date(d); dDay.setHours(0,0,0,0);
    const diffDays = Math.round((today - dDay) / 86400000);
    if (diffDays === 0) timeStr = `今天 ${d.toTimeString().slice(0,5)}`;
    else if (diffDays === 1) timeStr = `昨天 ${d.toTimeString().slice(0,5)}`;
    else timeStr = `${diffDays} 天前`;
  } else {
    valDisplay = `<span class="vt-val sm">—</span>`;
  }
  const plan = getPlanForMetric(m.id);
  let planBadge = '';
  if (plan) {
    const times = (plan.times || []).join(', ');
    const freqText = plan.frequency === 'weekly' ? '每週' : '每日';
    planBadge = `
      <div style="margin-top:6px;padding:4px 8px;background:rgba(99,179,237,0.15);border-radius:6px;font-size:0.72rem;color:var(--text-muted);display:flex;align-items:center;gap:4px">
        <span>🔔 ${freqText} ${times}</span>
      </div>
    `;
  }
  const planBtn = isBmi ? '' : `
    <button class="vt-rec-btn" onclick="openMeasurementPlanDialog('${m.id}', { skipStep1: ${plan ? 'true' : 'false'} })" type="button" title="${plan ? '修改提醒' : '設定提醒'}" style="padding:6px 8px;margin-right:4px">
      🔔
    </button>
  `;
  return `
    <div class="vt-snap scc-${m.color}-bd">
      <div class="vt-snap-head">
        <span class="vt-snap-icon scc-${m.color}"><i data-lucide="${m.icon}"></i></span>
        <span class="vt-snap-name">${m.zh}</span>
      </div>
      <div class="vt-snap-body">
        ${valDisplay}
      </div>
      ${planBadge}
      <div class="vt-snap-foot">
        <span class="vt-snap-time">${timeStr}</span>
        <div style="display:flex;gap:4px;align-items:center">
          ${planBtn}
          <button class="vt-rec-btn" onclick="openVitalLog('${m.id}')" type="button">
            ${isBmi ? '計算' : '記一筆'}
          </button>
        </div>
      </div>
    </div>
  `;
}

function renderVitalHistory() {
  const all = getVitalEntries().slice().sort((a, b) => new Date(b.recordedAt) - new Date(a.recordedAt));
  if (all.length === 0) {
    return '<p class="sym-empty">// 還沒有任何紀錄 — 點上面快覽卡片的「記一筆」開始。</p>';
  }
  const filterMetric = window.__vtFilter || 'all';
  const filtered = filterMetric === 'all' ? all : all.filter(e => e.metricId === filterMetric);
  const allMetrics = getAllMetrics();
  const filterOptions = '<option value="all">全部指標</option>' +
    allMetrics.map(m => `<option value="${m.id}" ${filterMetric === m.id ? 'selected' : ''}>${m.zh}</option>`).join('');
  const rows = filtered.slice(0, 30).map(e => {
    const m = allMetrics.find(x => x.id === e.metricId);
    const d = new Date(e.recordedAt);
    const dateStr = `${d.getFullYear()}/${(d.getMonth()+1).toString().padStart(2,'0')}/${d.getDate().toString().padStart(2,'0')} ${d.toTimeString().slice(0,5)}`;
    const valStr = m?.dual ? `${e.value}/${e.value2}` : `${e.value}`;
    return `
      <li class="vt-hist-row">
        <span class="vh-date">${dateStr}</span>
        <span class="vh-name scc-${m?.color || 'blue'}">${m?.zh || e.metricId}</span>
        <span class="vh-val"><strong>${valStr}</strong> <small>${m?.unit || ''}</small></span>
        ${e.context ? `<span class="vh-notes">情境：${escapeHtml(e.context)}</span>` : ''}
        ${e.method ? `<span class="vh-notes">方式：${escapeHtml(e.method)}</span>` : ''}
        ${e.notes ? `<span class="vh-notes">${escapeHtml(e.notes)}</span>` : ''}
        <button class="se-del" onclick="deleteVitalEntryAndRefresh('${e.id}')" title="刪除">×</button>
      </li>
    `;
  }).join('');
  return `
    <div class="vt-hist-filter">
      <label class="vt-hist-label">$ filter</label>
      <select class="vt-hist-select" onchange="setVitalFilter(this.value)">
        ${filterOptions}
      </select>
      <span class="vt-hist-count">${filtered.length} 筆</span>
    </div>
    <ul class="vt-hist-list">${rows}</ul>
  `;
}

function setVitalFilter(v) {
  window.__vtFilter = v;
  showPage('vitals');
}

function toggleVitalTracked(id) {
  const cur = getTrackedMetricIds();
  const turningOn = !cur.includes(id);
  if (turningOn) {
    // 開啟追蹤：跳出對話框讓使用者選擇「醫師有沒有要求 + 頻率」。
    // 對話框內的 vtPlanDialogNo 會把指標加進 tracked 並關閉；
    // vtPlanDialogSave 會建 plan 並加進 tracked。
    openMeasurementPlanDialog(id);
    return;
  }
  // 關閉追蹤：若有現存 plan，先確認是否一併取消
  const plan = getPlanForMetric(id);
  if (plan) {
    if (!confirm('要同時移除這個指標的提醒嗎？\n（按取消會保留提醒，只從追蹤清單移除）')) {
      // 不取消提醒，只移出追蹤清單
    } else {
      const pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
      if (pid) {
        apiFetch(`${API}/reminders/measurement-plan/${encodeURIComponent(plan.plan_id)}?patient_id=${encodeURIComponent(pid)}`, { method: 'DELETE' })
          .then(() => loadMeasurementPlans());
      }
    }
  }
  setTrackedMetricIds(cur.filter(x => x !== id));
  showPage('vitals');
}

function addCustomMetricUI() {
  const name = document.getElementById('vt-custom-name').value.trim();
  const unit = document.getElementById('vt-custom-unit').value.trim();
  if (!name) {
    if (typeof showToast === 'function') showToast('請先輸入指標名稱', 'warning');
    document.getElementById('vt-custom-name').focus();
    return;
  }
  const id = 'custom-' + Date.now() + '-' + Math.random().toString(36).slice(2, 6);
  const colors = ['blue','aqua','mint','pink'];
  saveCustomMetric({
    id, zh: name, icon: 'tag', unit,
    color: colors[Math.floor(Math.random() * colors.length)]
  });
  // auto-track newly added
  setTrackedMetricIds(getTrackedMetricIds().concat(id));
  showPage('vitals');
}

function deleteCustomMetricAndRefresh(ev, id) {
  ev.stopPropagation();
  if (!confirm('刪除此自訂指標？已記錄的歷史會保留。')) return;
  deleteCustomMetric(id);
  showPage('vitals');
}

function openVitalLog(metricId) {
  const m = findMetric(metricId);
  if (!m) return;
  const form = document.getElementById('vt-logform');
  document.getElementById('vt-logform-tag').textContent = m.id + '.entry';
  let body = `
    <div class="lf-explain">
      <div class="lf-icon scc-${m.color}"><i data-lucide="${m.icon}"></i></div>
      <div class="lf-info">
        <h3>${m.zh}${m.unit ? ` <small style="opacity:0.7">${m.unit}</small>` : ''}</h3>
        <p class="lf-detail">輸入目前數值，並選擇紀錄情境與記錄方式（可選填備註）。</p>
      </div>
    </div>
    <div class="lf-form">
  `;
  const contextFieldHtml = `
      <label class="lf-label">紀錄情境（選填）</label>
      <select id="vt-context" class="vt-unit-select">
        <option value="">— 未指定 —</option>
        ${VITAL_CONTEXT_OPTIONS.map(o => `<option value="${o}">${o}</option>`).join('')}
      </select>
      <label class="lf-label">記錄方式（選填）</label>
      <select id="vt-method" class="vt-unit-select">
        <option value="">— 未指定 —</option>
        ${VITAL_METHOD_OPTIONS.map(o => `<option value="${o}">${o}</option>`).join('')}
      </select>
  `;
  if (m.id === 'bmi') {
    const bmi = calculateBMI();
    body += `
      <p class="vt-bmi-note">BMI 由最新身高與體重自動計算 — 不需要手動輸入。</p>
      <div class="vt-bmi-result">
        ${bmi ? `<span class="vt-val">${bmi}</span>` : '<span class="vt-val sm">尚無資料</span>'}
        <span class="vt-bmi-meta">${bmi ? interpretBMI(parseFloat(bmi)) : '請先記錄身高與體重'}</span>
      </div>
      <div class="lf-actions">
        ${bmi ? `<button class="primary-btn" onclick="saveBmiSnapshot('${bmi}')" type="button">
          <i data-lucide="bookmark"></i><span>記下這次的 BMI</span>
        </button>` : ''}
        <button class="secondary-btn" onclick="cancelVitalLog()" type="button">取消</button>
      </div>
    `;
  } else if (m.dual) {
    body += `
      <label class="lf-label">收縮壓 / 舒張壓 (${m.unit})</label>
      <div class="vt-dual-wrap">
        <input type="number" id="vt-val1" placeholder="例 120" min="40" max="260" step="1" />
        <span class="vt-dual-sep">/</span>
        <input type="number" id="vt-val2" placeholder="例 80" min="30" max="160" step="1" />
        <span class="vt-dual-unit">${m.unit}</span>
      </div>
      ${contextFieldHtml}
      <label class="lf-label">備註（選填）</label>
      <textarea id="vt-notes" placeholder="例如：起床後測量、有運動..." rows="2"></textarea>
      <div class="lf-actions">
        <button class="primary-btn" onclick="submitVitalEntry('${m.id}')" type="button">
          <i data-lucide="check"></i><span>新增紀錄</span>
        </button>
        <button class="secondary-btn" onclick="cancelVitalLog()" type="button">取消</button>
      </div>
    `;
  } else {
    body += `
      <label class="lf-label">數值${m.unit ? ` (${m.unit})` : ''}</label>
      <input type="number" id="vt-val1" placeholder="輸入數值" ${m.range ? `min="${m.range[0]}" max="${m.range[1]}"` : ''} ${m.step ? `step="${m.step}"` : 'step="any"'} />
      ${contextFieldHtml}
      <label class="lf-label">備註（選填）</label>
      <textarea id="vt-notes" placeholder="例如：飯前、運動後..." rows="2"></textarea>
      <div class="lf-actions">
        <button class="primary-btn" onclick="submitVitalEntry('${m.id}')" type="button">
          <i data-lucide="check"></i><span>新增紀錄</span>
        </button>
        <button class="secondary-btn" onclick="cancelVitalLog()" type="button">取消</button>
      </div>
    `;
  }
  body += `</div>`;
  document.getElementById('vt-logform-body').innerHTML = body;
  form.style.display = 'block';
  if (typeof lucide !== 'undefined') lucide.createIcons();
  form.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function cancelVitalLog() {
  const f = document.getElementById('vt-logform');
  if (f) f.style.display = 'none';
}

function submitVitalEntry(metricId) {
  const m = findMetric(metricId);
  if (!m) return;
  const v1 = document.getElementById('vt-val1').value;
  if (!v1) {
    if (typeof showToast === 'function') showToast('請先輸入數值', 'warning');
    document.getElementById('vt-val1').focus();
    return;
  }
  const entry = {
    id: 'vt-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
    metricId,
    value: parseFloat(v1),
    recordedAt: new Date().toISOString()
  };
  if (m.dual) {
    const v2 = document.getElementById('vt-val2').value;
    if (!v2) {
      if (typeof showToast === 'function') showToast('請完整輸入收縮 / 舒張壓', 'warning');
      document.getElementById('vt-val2').focus();
      return;
    }
    entry.value2 = parseFloat(v2);
  }
  const ctxEl = document.getElementById('vt-context');
  const methodEl = document.getElementById('vt-method');
  const ctx = ctxEl ? ctxEl.value.trim() : '';
  const method = methodEl ? methodEl.value.trim() : '';
  if (ctx) entry.context = ctx;
  if (method) entry.method = method;
  const notes = document.getElementById('vt-notes').value.trim();
  if (notes) entry.notes = notes;
  saveVitalEntry(entry);
  if (typeof refreshNavBadges === 'function') refreshNavBadges();
  showPage('vitals');
}

// ─── 手機版「記一筆」模組：chip 點選邏輯 ──────────────────────
//
// state 存在 window.__vtMobileSel = { metricId, context, method }
// 數值由患者自行輸入；情境/方式可不選（再點一次取消）。

function _vitalChipStyle(on) {
  return 'padding:10px;border-radius:10px;border:1.5px solid '
    + (on ? '#4A90C2' : 'var(--border-glass,rgba(0,0,0,0.12))')
    + ';background:' + (on ? 'rgba(74,144,194,0.10)' : 'var(--surface,#fff)')
    + ';color:' + (on ? '#1E5A82' : 'var(--text,#374151)')
    + ';font-size:13px;font-weight:' + (on ? '600' : '500')
    + ';cursor:pointer;display:flex;align-items:center;gap:6px;justify-content:center;text-align:center;line-height:1.2';
}

function renderMobileMetricChips() {
  var el = document.getElementById('vt-m-metric-chips');
  if (!el) return;
  var cur = (window.__vtMobileSel || {}).metricId;
  var list = getAllMetrics().filter(function(mm) { return mm.id !== 'bmi'; });
  var chipsHtml = list.map(function(mm) {
    var on = cur === mm.id;
    var delBtn = mm.custom
      ? '<span onclick="event.stopPropagation();deleteMobileCustomMetric(\'' + mm.id + '\')" '
        + 'style="position:absolute;top:-6px;right:-6px;width:18px;height:18px;border-radius:50%;background:#c97a7a;color:#fff;font-size:11px;font-weight:700;display:flex;align-items:center;justify-content:center;cursor:pointer;border:1px solid #fff" title="刪除自訂指標">×</span>'
      : '';
    return '<button type="button" onclick="setVitalChipMetric(\'' + mm.id + '\')" '
      + 'style="' + _vitalChipStyle(on) + ';flex-direction:column;padding:12px 8px;min-height:64px;position:relative">'
      + delBtn
      + '<i data-lucide="' + (mm.icon || 'tag') + '" style="width:18px;height:18px"></i>'
      + '<span>' + escapeHtml(mm.zh) + (mm.unit ? ' <small style="font-weight:400;opacity:0.7">' + escapeHtml(mm.unit) + '</small>' : '') + '</span>'
      + '</button>';
  }).join('');
  chipsHtml += '<button type="button" onclick="openMobileAddCustomMetric()" '
    + 'style="' + _vitalChipStyle(false) + ';flex-direction:column;padding:12px 8px;min-height:64px;border-style:dashed">'
    + '<i data-lucide="plus" style="width:18px;height:18px"></i>'
    + '<span>自訂</span>'
    + '</button>';
  el.innerHTML = chipsHtml;
  if (typeof lucide !== 'undefined') try { lucide.createIcons(); } catch (_) {}
  syncVitalMobileValueInputs();
}

function renderMobileContextChips() {
  var el = document.getElementById('vt-m-context-chips');
  if (!el) return;
  var cur = (window.__vtMobileSel || {}).context;
  el.innerHTML = VITAL_CONTEXT_OPTIONS.map(function(o) {
    var on = cur === o;
    return '<button type="button" onclick="setVitalChipContext(\'' + o + '\')" '
      + 'style="' + _vitalChipStyle(on) + ';padding:8px 14px">' + escapeHtml(o) + '</button>';
  }).join('');
}

function renderMobileMethodChips() {
  var el = document.getElementById('vt-m-method-chips');
  if (!el) return;
  var cur = (window.__vtMobileSel || {}).method;
  el.innerHTML = VITAL_METHOD_OPTIONS.map(function(o) {
    var on = cur === o;
    return '<button type="button" onclick="setVitalChipMethod(\'' + o + '\')" '
      + 'style="' + _vitalChipStyle(on) + ';padding:8px 14px">' + escapeHtml(o) + '</button>';
  }).join('');
}

function syncVitalMobileValueInputs() {
  var sel = window.__vtMobileSel || {};
  var m = findMetric(sel.metricId);
  var isDual = m && m.dual;
  var single = document.getElementById('vt-m-single-wrap');
  var dual = document.getElementById('vt-m-dual-wrap');
  if (single) single.style.display = isDual ? 'none' : 'block';
  if (dual)   dual.style.display   = isDual ? 'block' : 'none';
  var unitLbl = document.getElementById('vt-m-unit-lbl');
  if (unitLbl) unitLbl.textContent = m && m.unit ? '(' + m.unit + ')' : '';
}

function setVitalChipMetric(id) {
  window.__vtMobileSel = window.__vtMobileSel || {};
  window.__vtMobileSel.metricId = id;
  renderMobileMetricChips();
}
function setVitalChipContext(val) {
  window.__vtMobileSel = window.__vtMobileSel || {};
  window.__vtMobileSel.context = window.__vtMobileSel.context === val ? '' : val;
  renderMobileContextChips();
}
function setVitalChipMethod(val) {
  window.__vtMobileSel = window.__vtMobileSel || {};
  window.__vtMobileSel.method = window.__vtMobileSel.method === val ? '' : val;
  renderMobileMethodChips();
}

function initMobileVitalChips() {
  renderMobileMetricChips();
  renderMobileContextChips();
  renderMobileMethodChips();
}

function openMobileAddCustomMetric() {
  var old = document.getElementById('vt-m-add-sheet');
  if (old) old.remove();
  var units = ['mg/dL','mmol/L','mmHg','bpm','%','kg','g','lb','cm','mm','ml','L','°C','°F','次','步','顆','片','分鐘','小時','kcal','級','分'];
  var unitOptions = '<option value="">— 無單位 —</option>' + units.map(function(u) {
    return '<option value="' + u + '">' + u + '</option>';
  }).join('');
  var overlay = document.createElement('div');
  overlay.id = 'vt-m-add-sheet';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.45);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';
  overlay.innerHTML = ''
    + '<div role="dialog" aria-modal="true" style="background:#fff;border-radius:14px;max-width:380px;width:100%;padding:18px">'
    +   '<h3 style="margin:0 0 4px;font-size:16px;color:#111">新增自訂指標</h3>'
    +   '<p style="margin:0 0 14px;font-size:12px;color:#6b7280">例：尿酸、步數、視力、運動時間</p>'
    +   '<label style="font-size:12px;color:#6b7280;font-weight:600;display:block;margin-bottom:4px">指標名稱</label>'
    +   '<input id="vt-m-add-name" maxlength="20" placeholder="輸入名稱" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;font-size:14px;margin-bottom:10px;box-sizing:border-box" />'
    +   '<label style="font-size:12px;color:#6b7280;font-weight:600;display:block;margin-bottom:4px">單位</label>'
    +   '<select id="vt-m-add-unit" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;font-size:14px;margin-bottom:14px;box-sizing:border-box">' + unitOptions + '</select>'
    +   '<div style="display:flex;gap:8px">'
    +     '<button type="button" onclick="closeMobileAddCustomMetric()" style="flex:1;padding:12px;background:transparent;border:1px solid #e5e7eb;border-radius:8px;font-size:14px;cursor:pointer">取消</button>'
    +     '<button type="button" onclick="submitMobileAddCustomMetric()" style="flex:2;padding:12px;background:#4A90C2;color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer">新增</button>'
    +   '</div>'
    + '</div>';
  overlay.addEventListener('click', function(e) { if (e.target === overlay) closeMobileAddCustomMetric(); });
  document.body.appendChild(overlay);
  setTimeout(function() { var n = document.getElementById('vt-m-add-name'); if (n) n.focus(); }, 80);
}

function closeMobileAddCustomMetric() {
  var el = document.getElementById('vt-m-add-sheet');
  if (el) el.remove();
}

function submitMobileAddCustomMetric() {
  var name = document.getElementById('vt-m-add-name').value.trim();
  if (!name) {
    if (typeof showToast === 'function') showToast('請輸入指標名稱', 'warning');
    document.getElementById('vt-m-add-name').focus();
    return;
  }
  var unit = document.getElementById('vt-m-add-unit').value.trim();
  var id = 'custom-' + Date.now() + '-' + Math.random().toString(36).slice(2, 6);
  var colors = ['blue','aqua','mint','pink'];
  saveCustomMetric({
    id: id, zh: name, icon: 'tag', unit: unit,
    color: colors[Math.floor(Math.random() * colors.length)]
  });
  setTrackedMetricIds(getTrackedMetricIds().concat(id));
  window.__vtMobileSel = window.__vtMobileSel || {};
  window.__vtMobileSel.metricId = id;
  closeMobileAddCustomMetric();
  if (typeof showToast === 'function') showToast('已新增「' + name + '」✅', 'success');
  showPage('vitals');
}

function deleteMobileCustomMetric(id) {
  if (!confirm('刪除此自訂指標？已記錄的歷史會保留。')) return;
  deleteCustomMetric(id);
  if (window.__vtMobileSel && window.__vtMobileSel.metricId === id) {
    window.__vtMobileSel.metricId = '';
  }
  showPage('vitals');
}

function submitMobileVitalEntry() {
  var sel = window.__vtMobileSel || {};
  var metricId = sel.metricId;
  var m = findMetric(metricId);
  if (!m) { if (typeof showToast === 'function') showToast('請先選擇指標', 'warning'); return; }
  var entry = {
    id: 'vt-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
    metricId: metricId,
    recordedAt: new Date().toISOString()
  };
  if (m.dual) {
    var v1d = document.getElementById('vt-m-val1d').value;
    var v2d = document.getElementById('vt-m-val2d').value;
    if (!v1d || !v2d) {
      if (typeof showToast === 'function') showToast('請完整輸入收縮 / 舒張壓', 'warning');
      var focusEl = document.getElementById(v1d ? 'vt-m-val2d' : 'vt-m-val1d');
      if (focusEl) focusEl.focus();
      return;
    }
    entry.value = parseFloat(v1d);
    entry.value2 = parseFloat(v2d);
  } else {
    var v1 = document.getElementById('vt-m-val1').value;
    if (!v1) {
      if (typeof showToast === 'function') showToast('請先輸入數值', 'warning');
      var sEl = document.getElementById('vt-m-val1');
      if (sEl) sEl.focus();
      return;
    }
    entry.value = parseFloat(v1);
  }
  if (sel.context) entry.context = sel.context;
  if (sel.method)  entry.method  = sel.method;
  var notes = document.getElementById('vt-m-notes').value.trim();
  if (notes) entry.notes = notes;
  saveVitalEntry(entry);
  // 送出後清掉情境/方式選擇（指標保留方便連續記）
  window.__vtMobileSel.context = '';
  window.__vtMobileSel.method = '';
  if (typeof refreshNavBadges === 'function') refreshNavBadges();
  if (typeof showToast === 'function') showToast('已新增紀錄 ✅', 'success');
  showPage('vitals');
}

function saveBmiSnapshot(bmi) {
  saveVitalEntry({
    id: 'vt-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
    metricId: 'bmi',
    value: parseFloat(bmi),
    notes: 'auto-calculated',
    recordedAt: new Date().toISOString()
  });
  showPage('vitals');
}

function deleteVitalEntryAndRefresh(id) {
  if (!confirm('刪除這筆紀錄？')) return;
  deleteVitalEntry(id);
  showPage('vitals');
}

function interpretBMI(v) {
  if (v < 18.5) return '體重過輕';
  if (v < 24)   return '健康範圍';
  if (v < 27)   return '體重過重';
  if (v < 30)   return '輕度肥胖';
  if (v < 35)   return '中度肥胖';
  return '重度肥胖';
}

// ─── 症狀分析（獨立頁） ────────────────────────────────────
//
// 把症狀清單丟給 AI，回緊急程度 / 可能病因 / 建議科別 / 處置建議。
// 來源 1：使用者直接打字（comma 分隔）
// 來源 2：「從最近紀錄帶入」按鈕 — 從 getPeriodStats() 取近期 top symptoms
// 顯示：urgency badge、conditions list、recommended dept、advice、disclaimer
// 並列出 GET /symptoms/history/{patient_id} 的歷史分析

function symptomsAnalyze() {
  // ─── Mobile v11 hero ───
  var _mobileSaHero = ''
    + '<div class="mobile-only" style="margin-bottom:12px">'
    +   '<div class="pv-hero">'
    +     '<svg class="puzzle-bg-layer" preserveAspectRatio="xMidYMid slice"><use href="#puzzle-bg-rose-amber"/></svg>'
    +     '<div class="pv-hero-eye">症狀分析</div>'
    +     '<div style="font-size:17px;font-weight:600;color:var(--navy);margin-top:6px;line-height:1.4;position:relative;z-index:1">把症狀寫下來 — AI 幫你分析緊急程度</div>'
    +     '<div class="pv-hero-meta" style="position:relative;z-index:1">列出可能病因、建議科別、處置建議；<strong>不取代醫師診斷</strong></div>'
    +   '</div>'
    + '</div>';
  var _mobileSaFooter = ''
    + '<div class="mobile-only">'
    +   '<div class="disclaimer-footer">'
    +     '<i data-lucide="info"></i>'
    +     '<span><strong>結果僅供參考</strong>，嚴重不適請<span class="emergency">立即就醫或撥 119</span>。</span>'
    +   '</div>'
    + '</div>';

  return _mobileSaHero + `
    <div class="card">
      <h2>症狀分析</h2>
      <p style="margin-top:8px;color:var(--text-dim)">把現在的症狀寫下來，MD.Piece 會幫你分析可能病因、緊急程度與建議就診科別。</p>
      <p style="margin-top:4px;font-size:0.85rem;color:var(--text-muted)">⚠️ 結果僅供參考，<strong>不取代醫師診斷</strong>。如有嚴重不適請立即就醫或撥 119。</p>
    </div>

    <div class="card">
      <h3>輸入症狀</h3>
      <div style="margin-top:8px;display:flex;flex-direction:column;gap:8px">
        <textarea id="symptom-analyze-input"
          rows="3"
          placeholder="例：頭痛, 發燒 38.5度, 喉嚨痛, 全身痠痛"
          style="width:100%;padding:10px;border-radius:var(--radius-sm);border:1px solid var(--border-glass);background:var(--bg-glass);color:var(--text);font-family:inherit;resize:vertical"></textarea>
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          <button class="primary" onclick="runSymptomAnalysis()">
            <i data-lucide="sparkles" style="width:14px;height:14px;vertical-align:middle"></i> 開始分析
          </button>
          <button class="secondary" onclick="fillSymptomsFromRecent()">
            <i data-lucide="history" style="width:14px;height:14px;vertical-align:middle"></i> 從最近紀錄帶入
          </button>
          <button class="secondary" onclick="document.getElementById('symptom-analyze-input').value=''">
            清空
          </button>
        </div>
      </div>
      <div id="symptom-analyze-result" style="margin-top:16px"></div>
    </div>

    <div class="card">
      <h3><i data-lucide="clock" style="width:18px;height:18px;vertical-align:middle"></i> 分析歷史</h3>
      <div id="symptom-analyze-history" style="margin-top:12px"><p style="color:var(--text-muted)">載入中...</p></div>
    </div>
  ` + _mobileSaFooter;
}

// 緊急度（從 /symptoms/analyze 回的 urgency）對應到 5 級 severity token
// 對齊 docs/research/ui_color_research.md §4 與 backend/routers/triage.py
function _symptomUrgency(level) {
  const map = {
    emergency: { label: "緊急",   severity: "er"       },  // → var(--sev-er)
    high:      { label: "高",     severity: "medical"  },  // → var(--sev-medical)
    medium:    { label: "中",     severity: "clinic"   },  // → var(--sev-clinic)
    low:       { label: "低",     severity: "self"     },  // → var(--sev-self)
  };
  return map[level] || map.low;
}

function fillSymptomsFromRecent() {
  try {
    const stats = getPeriodStats();
    const top = [];
    for (const cid in stats.byCategory) {
      const cat = findSymptomCat(cid);
      if (cat) top.push({ name: cat.label || cat.name || cid, count: stats.byCategory[cid].count });
    }
    top.sort((a, b) => b.count - a.count);
    const names = top.slice(0, 5).map(t => t.name);
    if (!names.length) {
      showToast("最近沒有症狀紀錄可帶入", "info");
      return;
    }
    document.getElementById("symptom-analyze-input").value = names.join(", ");
  } catch (e) {
    showToast("帶入失敗", "error");
  }
}

var _saTypingTimer = null;
async function runSymptomAnalysis() {
  const input = document.getElementById("symptom-analyze-input").value;
  if (!input.trim()) {
    showToast("請先輸入症狀", "info");
    return;
  }
  const symptoms = input.split(/[,，、]/).map(s => s.trim()).filter(Boolean);
  if (!symptoms.length) {
    showToast("請輸入有效的症狀", "info");
    return;
  }
  const el = document.getElementById("symptom-analyze-result");
  el.innerHTML =
    '<div style="text-align:center;padding:20px;color:var(--text-muted)">' +
    '<div id="sa-typing-mascot" style="display:flex;justify-content:center">' + chatMascotSvg('typing', 0) + '</div>' +
    '<p style="margin-top:8px">小禾正在分析... 約 5-15 秒</p>' +
    '</div>';
  if (_saTypingTimer) { clearInterval(_saTypingTimer); _saTypingTimer = null; }
  let _saFrame = 0;
  _saTypingTimer = setInterval(() => {
    const w = document.getElementById('sa-typing-mascot');
    if (!w) { clearInterval(_saTypingTimer); _saTypingTimer = null; return; }
    _saFrame = (_saFrame + 1) % 2;
    w.innerHTML = chatMascotSvg('typing', _saFrame);
  }, 140);

  const pid = getStablePatientId();
  try {
    const res = await apiFetch(`${API}/symptoms/analyze`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ symptoms, patient_id: pid }),
    });
    if (!res.ok) {
      const txt = await res.text();
      throw new Error("HTTP " + res.status + ": " + txt.slice(0, 200));
    }
    const data = await res.json();
    if (_saTypingTimer) { clearInterval(_saTypingTimer); _saTypingTimer = null; }
    el.innerHTML = renderSymptomAnalysis(data);
    if (window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch (_) {}
    // 重新載入歷史
    loadSymptomAnalysisHistory();
    // 再打 /triage/evaluate 拿後端的 severity_color（5 級分級醫療）並套上 data-severity
    enrichSymptomAnalysisWithTriage(symptoms, pid).catch(function() { /* 安靜失敗，不擋主流程 */ });
  } catch (e) {
    if (_saTypingTimer) { clearInterval(_saTypingTimer); _saTypingTimer = null; }
    el.innerHTML =
      '<div style="padding:14px;background:rgba(232,136,156,0.1);border-left:3px solid var(--danger);border-radius:var(--radius-sm)">' +
      '<strong>分析失敗</strong><br>' +
      '<span style="font-size:0.85rem;color:var(--text-muted)">' + escapeHtml(e.message || "未知錯誤") + '</span>' +
      '</div>';
  }
}

// 在症狀分析成功後，再呼叫 /triage/evaluate 拿後端的 severity_color（er/regional/clinic/self）
// 把分級醫療顏色補上去，並在結果區塊浮一條「建議去哪裡看」chip
async function enrichSymptomAnalysisWithTriage(symptoms, pid) {
  const TRIAGE_LABEL = {
    emergency: { sev: 'er',       text: '建議立即就醫 / 急診' },
    follow_up: { sev: 'regional', text: '近期回診追蹤' },
    stable:    { sev: 'self',     text: '可先自我照護觀察' },
  };
  try {
    const res = await apiFetch(`${API}/triage/evaluate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ patient_id: pid, symptoms: symptoms || [] }),
    });
    if (!res.ok) return;
    const data = await res.json();
    const result = data && data.result;
    const meta = TRIAGE_LABEL[result];
    if (!meta) return;
    // 安全檢查 severity_color：只接受 5 個白名單值
    const SEV = { self:1, clinic:1, regional:1, medical:1, er:1 };
    const sev = SEV[data.severity_color] ? data.severity_color : meta.sev;
    const host = document.getElementById('symptom-analyze-result');
    if (!host) return;
    // 把 result 區塊外層也掛上 data-severity（讓樣式統一）
    host.setAttribute('data-severity', sev);
    // 插入分級建議 chip
    const banner = document.createElement('div');
    banner.className = 'sa-triage-banner';
    banner.innerHTML =
      '<span class="sev-chip" data-severity="' + sev + '">分級建議</span>' +
      '<span class="sa-triage-text">' + escapeHtml(meta.text) + '</span>' +
      (data.message ? '<span class="sa-triage-msg">' + escapeHtml(data.message) + '</span>' : '');
    // 放在結果第一行
    host.insertBefore(banner, host.firstChild);
  } catch (e) {
    // 不擋主流程
  }
}

function renderSymptomAnalysis(data) {
  const u = _symptomUrgency(data.urgency);
  const conditions = (data.conditions || [])
    .map(c => {
      const name = escapeHtml(c.name || "");
      const desc = c.description ? `<div class="sa-cond-desc">${escapeHtml(c.description)}</div>` : '';
      const likelihood = c.likelihood ? `<span class="sa-cond-likelihood">可能性 ${escapeHtml(c.likelihood)}</span>` : '';
      const lookupBtn = c.name
        ? ` <button type="button" class="sa-cond-lookup"
              data-disease="${escapeHtml(c.name)}"
              onclick="navigateToDiseaseSearch(this.dataset.disease)"
              title="到疾病百科查詢更詳細的說明、用藥、風險">
              <i data-lucide="stethoscope" style="width:12px;height:12px"></i> 查更多
            </button>`
        : '';
      return `<li class="sa-cond"><div class="sa-cond-head"><strong>${name}</strong>${likelihood}${lookupBtn}</div>${desc}</li>`;
    })
    .join("");

  // 用 data-severity attribute（CSS 套 var(--sev-*)），前端不再硬寫顏色
  return `
    <div class="sa-urgency" data-severity="${u.severity}">
      <span class="sev-chip" data-severity="${u.severity}">緊急程度：${u.label}</span>
    </div>
    <div class="sa-grid">
      <section class="sa-section">
        <h4 class="sa-section-title">可能的原因</h4>
        <ul class="sa-cond-list">${conditions || '<li class="sa-empty">需要醫師進一步評估</li>'}</ul>
      </section>
      <section class="sa-section">
        <h4 class="sa-section-title">建議看哪一科</h4>
        <p class="sa-text">${escapeHtml(data.recommended_department || "家醫科")}</p>
      </section>
      <section class="sa-section">
        <h4 class="sa-section-title">建議怎麼做</h4>
        <p class="sa-text">${escapeHtml(data.advice || "")}</p>
      </section>
      <p class="sa-disclaimer">
        ${escapeHtml(data.disclaimer || "這份分析僅供參考，不是診斷。如果不舒服或不確定，請直接就醫。")}
      </p>
    </div>
  `;
}

function loadSymptomAnalysisHistory() {
  const pid = getStablePatientId();
  const el = document.getElementById("symptom-analyze-history");
  if (!el) return;
  apiFetch(`${API}/symptoms/history/${pid}`)
    .then(r => r.ok ? r.json() : { history: [] })
    .then(data => {
      const items = (data.history || []).slice(0, 5);
      if (!items.length) {
        el.innerHTML = '<p style="color:var(--text-muted);font-size:0.9rem">尚無分析紀錄。完成第一次分析後會出現在這裡。</p>';
        return;
      }
      el.innerHTML = items.map(it => {
        const sx = (it.symptoms || []).join("、");
        const u = _symptomUrgency((it.ai_response || {}).urgency);
        const dept = (it.ai_response || {}).recommended_department || "—";
        const date = it.created_at ? new Date(it.created_at).toLocaleString("zh-TW", { month: "numeric", day: "numeric", hour: "2-digit", minute: "2-digit" }) : "";
        return `
          <div style="padding:12px;background:var(--bg-glass);border-radius:var(--radius-sm);margin-bottom:8px">
            <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start;flex-wrap:wrap">
              <div style="flex:1;min-width:0">
                <div style="font-size:0.9rem;color:var(--text)">${escapeHtml(sx)}</div>
                <div style="font-size:0.78rem;color:var(--text-muted);margin-top:4px">${escapeHtml(date)}・建議 ${escapeHtml(dept)}</div>
              </div>
              <span style="font-size:0.78rem;font-weight:600;color:${u.color}">${u.label}</span>
              <button type="button"
                onclick="deleteSymptomHistoryItem('${escapeHtml(it.id || "")}')"
                aria-label="刪除這筆紀錄"
                title="刪除這筆紀錄"
                style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-muted);display:inline-flex;align-items:center">
                <i data-lucide="trash-2" style="width:16px;height:16px"></i>
              </button>
            </div>
          </div>
        `;
      }).join("");
      if (window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch (_) {}
    })
    .catch(() => {
      el.innerHTML = '<p style="color:var(--text-muted);font-size:0.9rem">無法載入歷史紀錄。</p>';
    });
}

async function deleteSymptomHistoryItem(logId) {
  if (!logId) return;
  if (!confirm("確定要刪除這筆分析紀錄？")) return;
  const pid = getStablePatientId();
  try {
    const res = await apiFetch(`${API}/symptoms/history/${pid}/${logId}`, { method: "DELETE" });
    if (!res.ok) {
      const txt = await res.text();
      throw new Error("HTTP " + res.status + ": " + txt.slice(0, 200));
    }
    loadSymptomAnalysisHistory();
  } catch (e) {
    showToast("刪除失敗：" + (e.message || "未知錯誤"), "error");
  }
}

// 舊 inline 版（保留向後相容；新獨立頁是 symptomsAnalyze 上方）
async function analyzeSymptoms() {
  const input = document.getElementById("symptom-input").value;
  if (!input.trim()) return;
  const symptoms = input.split(",").map(s => s.trim()).filter(Boolean);
  const el = document.getElementById("analysis-result");
  el.innerHTML = '<div class="loading">分析中...</div>';

  try {
    const res = await apiFetch(`${API}/symptoms/analyze`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ symptoms }),
    });
    const data = await res.json();

    const urgencyMap = {
      emergency: { label: "緊急", cls: "urgency-emergency" },
      high: { label: "高", cls: "urgency-high" },
      medium: { label: "中", cls: "urgency-medium" },
      low: { label: "低", cls: "urgency-low" },
    };
    const urg = urgencyMap[data.urgency] || urgencyMap.low;

    const conditions = (data.conditions || [])
      .map(c => `<li><strong>${c.name}</strong> — 可能性：${c.likelihood}</li>`)
      .join("");

    el.innerHTML = `
      <div class="ai-result-card">
        <div class="urgency-badge ${urg.cls}">緊急程度：${urg.label}</div>
        <h4>可能病因</h4>
        <ul>${conditions}</ul>
        <h4>建議科別</h4>
        <p>${data.recommended_department || "家醫科"}</p>
        <h4>建議</h4>
        <p>${data.advice || ""}</p>
        <div class="disclaimer">${data.disclaimer || "此分析僅供參考，不構成醫療診斷。如有不適請立即就醫。"}</div>
      </div>`;
  } catch (e) {
    el.innerHTML = '<div class="advice-box">分析失敗，請確認後端是否啟動。</div>';
  }
}

async function quickAdvice() {
  const input = document.getElementById("symptom-input").value.split(",")[0].trim();
  if (!input) return;
  const res = await apiFetch(`${API}/symptoms/advice?symptom=${encodeURIComponent(input)}`);
  const data = await res.json();
  document.getElementById("analysis-result").innerHTML =
    `<div class="advice-box"><strong>${data.symptom}</strong>：${data.advice}</div>`;
}

// ─── 我的基本資料 ──────────────────────────────────────────
// 個人檔案 — 後端同步 + localStorage 快取（Issue #131）
//
// 原本只存 localStorage（BASIC_INFO_KEY），清快取 / 換瀏覽器就遺失。
// 現在：登入後從 /profile/{user_id} 拉、儲存時 PUT 同步、本地快取做離線顯示。
// 一次性 migration：若 backend 沒有 + localStorage 有 → 推上去，之後就以 backend 為真。

const BASIC_INFO_KEY = 'mdpiece_basic_info';
const BASIC_INFO_MIGRATED_KEY = 'mdpiece_basic_info_migrated';

// 同步版（保留 sig，給渲染用）— 讀本地快取，後端是非同步預載的真值來源。
function getBasicInfo() {
  try { return JSON.parse(localStorage.getItem(BASIC_INFO_KEY)) || {}; }
  catch { return {}; }
}

// 寫快取（本地立即生效，UI 不卡）。後端同步由 saveBasicInfo 觸發。
function setBasicInfo(info) {
  localStorage.setItem(BASIC_INFO_KEY, JSON.stringify(info));
}

// 從後端拉個人檔案，成功就覆寫 localStorage 快取，並回 promise resolve(info)。
// 失敗（404 = 從沒填過、或網路問題）就 resolve(null)，UI 仍能用 getBasicInfo() 本地快取。
function fetchBasicInfoFromServer() {
  var uid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!uid) return Promise.resolve(null);
  return apiFetch(API + '/profile/' + encodeURIComponent(uid))
    .then(function(r) { return r.ok ? r.json() : null; })
    .then(function(remote) {
      if (!remote) return null;
      // 後端欄位 → 前端欄位（保留原本 form id 一致）
      var info = {
        gender: remote.gender || '',
        birthday: remote.birthday || '',
        blood: remote.blood || '',
        height: remote.height_cm != null ? String(remote.height_cm) : '',
        weight: remote.weight_kg != null ? String(remote.weight_kg) : '',
        allergies: remote.allergies || '',
        conditions: remote.conditions || '',
        current_disease: remote.current_disease || '',
        meds: remote.meds || '',
        doctor_name: remote.doctor_name || '',
        hospital: remote.hospital || '',
        emergency_name: remote.emergency_name || '',
        emergency_phone: remote.emergency_phone || '',
      };
      setBasicInfo(info);
      return info;
    })
    .catch(function() { return null; });
}

// 把本地 info 推到後端。回 promise resolve(true|false)。
function syncBasicInfoToServer(info) {
  var uid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!uid) return Promise.resolve(false);
  var payload = {
    gender: info.gender || null,
    birthday: info.birthday || null,
    blood: info.blood || null,
    height_cm: info.height ? parseFloat(info.height) : null,
    weight_kg: info.weight ? parseFloat(info.weight) : null,
    allergies: info.allergies || null,
    conditions: info.conditions || null,
    current_disease: info.current_disease || null,
    meds: info.meds || null,
    doctor_name: info.doctor_name || null,
    hospital: info.hospital || null,
    emergency_name: info.emergency_name || null,
    emergency_phone: info.emergency_phone || null,
  };
  return apiFetch(API + '/profile/' + encodeURIComponent(uid), {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })
    .then(function(r) { return r.ok; })
    .catch(function() { return false; });
}

// 一次性 migration：若 backend 沒資料但本地有舊資料 → 推上去。每個帳號只跑一次。
// 由 boot / 進入 records 頁時觸發。
function migrateBasicInfoIfNeeded() {
  var uid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!uid) return Promise.resolve();
  var migKey = BASIC_INFO_MIGRATED_KEY + ':' + uid;
  if (localStorage.getItem(migKey) === '1') return Promise.resolve();
  // 先拉一次 backend；有就標記已 migrated 就走人
  return fetchBasicInfoFromServer().then(function(remote) {
    if (remote && Object.values(remote).some(Boolean)) {
      localStorage.setItem(migKey, '1');
      return;
    }
    // backend 空、檢查本地有沒有舊資料
    var local = getBasicInfo();
    if (!local || !Object.values(local).some(Boolean)) {
      localStorage.setItem(migKey, '1');
      return;
    }
    // backfill 上去
    return syncBasicInfoToServer(local).then(function(ok) {
      if (ok) localStorage.setItem(migKey, '1');
    });
  });
}

function calcAge(birthday) {
  if (!birthday) return '';
  const b = new Date(birthday);
  if (isNaN(b)) return '';
  const now = new Date();
  let age = now.getFullYear() - b.getFullYear();
  const m = now.getMonth() - b.getMonth();
  if (m < 0 || (m === 0 && now.getDate() < b.getDate())) age--;
  return age >= 0 ? age + ' ' + _T('rec.unit.years') : '';
}

function calcBMI(h, w) {
  const hn = parseFloat(h), wn = parseFloat(w);
  if (!hn || !wn) return '';
  const bmi = wn / Math.pow(hn / 100, 2);
  return bmi.toFixed(1);
}

